function drawElementPentagon(){
  const canvas = document.getElementById("elementPentagon");
  if(!canvas) return;
  const ctx = canvas.getContext("2d");
  const W = canvas.width, H = canvas.height;
  const cx = W/2, cy = H/2;
  const r  = 72; // 頂点の半径

  ctx.clearRect(0,0,W,H);

  // 順番：火→木→地→雷→水（時計回り、上から）
  const elements = ["fire","wood","earth","thunder","water"];
  const colors   = elements.map(e=>ELEMENT_INFO[e].color);
  const labels   = elements.map(e=>ELEMENT_INFO[e].label);

  // 頂点座標（上から時計回り）
  const pts = elements.map((_,i)=>{
    const angle = -Math.PI/2 + (i/5)*Math.PI*2;
    return { x: cx + r*Math.cos(angle), y: cy + r*Math.sin(angle) };
  });

  // 五角形の枠線
  ctx.save();
  ctx.strokeStyle = "rgba(255,255,255,0.1)";
  ctx.lineWidth   = 1;
  ctx.beginPath();
  pts.forEach((p,i)=>{ i===0?ctx.moveTo(p.x,p.y):ctx.lineTo(p.x,p.y); });
  ctx.closePath();
  ctx.stroke();
  ctx.restore();

  // 矢印（火→木、木→地、地→雷、雷→水、水→火）
  elements.forEach((el,i)=>{
    const from = pts[i];
    const to   = pts[(i+1)%5];
    drawArrow(ctx, from.x, from.y, to.x, to.y, colors[i]);
  });

  // 頂点アイコン
  elements.forEach((el,i)=>{
    const p = pts[i];
    const col = colors[i];

    // 円背景
    ctx.save();
    ctx.fillStyle   = col+"33";
    ctx.strokeStyle = col;
    ctx.lineWidth   = 2;
    ctx.shadowColor = col;
    ctx.shadowBlur  = 8;
    ctx.beginPath();
    ctx.arc(p.x, p.y, 18, 0, Math.PI*2);
    ctx.fill();
    ctx.stroke();
    ctx.restore();

    // ラベル（絵文字+テキスト）
    ctx.save();
    ctx.font          = "13px sans-serif";
    ctx.textAlign     = "center";
    ctx.textBaseline  = "middle";
    ctx.fillText(labels[i].split(" ")[0], p.x, p.y-1);
    ctx.font      = `bold 9px sans-serif`;
    ctx.fillStyle = col;
    ctx.fillText(labels[i].split(" ")[1]||"", p.x, p.y+10);
    ctx.restore();
  });
}

function drawArrow(ctx, x1, y1, x2, y2, color){
  // 始点・終点を円の縁に調整
  const rad  = 20;
  const dx   = x2-x1, dy = y2-y1;
  const dist = Math.sqrt(dx*dx+dy*dy);
  const ux   = dx/dist, uy = dy/dist;

  const sx = x1 + ux*rad;
  const sy = y1 + uy*rad;
  const ex = x2 - ux*rad;
  const ey = y2 - uy*rad;

  ctx.save();
  ctx.strokeStyle = color;
  ctx.lineWidth   = 2.5;
  ctx.shadowColor = color;
  ctx.shadowBlur  = 6;
  ctx.beginPath();
  ctx.moveTo(sx, sy);
  ctx.lineTo(ex, ey);
  ctx.stroke();

  // 矢印の先
  const arrowLen = 9;
  const angle    = Math.atan2(ey-sy, ex-sx);
  ctx.fillStyle  = color;
  ctx.beginPath();
  ctx.moveTo(ex, ey);
  ctx.lineTo(ex - arrowLen*Math.cos(angle-0.4), ey - arrowLen*Math.sin(angle-0.4));
  ctx.lineTo(ex - arrowLen*Math.cos(angle+0.4), ey - arrowLen*Math.sin(angle+0.4));
  ctx.closePath();
  ctx.fill();
  ctx.restore();
}

const STAGE2_CLEAR_KEY = "shootingStage2Cleared";
function isStage2Cleared(){ return localStorage.getItem(STAGE2_CLEAR_KEY)==="cleared"; }
