// =============================================
function beginStage3(){
  // 既存のタイマーを必ずクリア
if(shootingTimerInterval){
  clearInterval(shootingTimerInterval);
  shootingTimerInterval = null;
}
if(shootingAnimFrame){
  cancelAnimationFrame(shootingAnimFrame);
  shootingAnimFrame = null;
}
  const area=document.getElementById("spaceArea");
  area.innerHTML=`
    <div style="position:relative;width:100%;max-width:420px;margin:0 auto">
      <canvas id="shootCanvas" style="display:block;width:100%;border-radius:16px;background:#000020;touch-action:none"></canvas>
      <div id="shootQuizResult"
  style="position:absolute;bottom:30px;left:50%;transform:translateX(-50%);
    font-family:'Fredoka One',cursive;font-size:1rem;
    background:rgba(0,0,0,0.7);border-radius:12px;padding:6px 16px;
    pointer-events:none;display:none;text-align:center;
    white-space:pre-line;z-index:100;min-width:200px">
</div>
      <button onclick="toggleShootingPause()"
  style="position:absolute;top:8px;right:8px;
    background:rgba(0,0,0,0.5);border:1px solid rgba(255,255,255,0.3);
    color:#fff;font-size:12px;padding:5px 10px;border-radius:8px;
    z-index:2100;cursor:pointer">
  ⏸ ポーズ
</button>
      <div id="shootHUD" style="position:absolute;top:8px;left:8px;right:8px;display:flex;justify-content:space-between;pointer-events:none">
        <div id="shootHP" style="font-family:'Fredoka One',cursive;font-size:14px;color:#6BCB77;text-shadow:0 0 8px rgba(107,203,119,0.8)">❤️ 0</div>
        <div id="shootTimer" style="font-family:'Fredoka One',cursive;font-size:14px;color:#FFD93D;text-shadow:0 0 8px rgba(255,217,61,0.8)">⏱ 60</div>
        <div id="shootCard" style="font-family:'Fredoka One',cursive;font-size:11px;color:#4D96FF">🚀 1枚目</div>
      </div>
      <div id="shootBossHUD" style="position:absolute;top:36px;left:8px;right:8px;display:none;pointer-events:none">
        <div style="font-family:'Fredoka One',cursive;font-size:11px;color:#FFD700;text-align:center;margin-bottom:2px">⚡ 金星</div>
        <div style="background:rgba(0,0,0,0.4);border-radius:8px;height:10px;overflow:hidden">
          <div id="shootBossHPBar" style="height:100%;background:linear-gradient(90deg,#FFD700,#FF9500);border-radius:8px;transition:width 0.3s;width:100%"></div>
        </div>
      </div>
      <div id="shootMessage" style="position:absolute;top:45%;left:50%;transform:translate(-50%,-50%);font-family:'Fredoka One',cursive;font-size:1.2rem;color:#fff;text-align:center;pointer-events:none;text-shadow:0 0 20px rgba(255,255,255,0.8);display:none;background:rgba(0,0,0,0.6);border-radius:12px;padding:8px 16px;white-space:pre-line"></div>
    </div>`;

  shootCanvas=document.getElementById("shootCanvas");
  const maxW=Math.min(420,window.innerWidth-32);
  shootCanvas.width=maxW;
  shootCanvas.height=Math.floor(maxW*1.5);
  shootCtx=shootCanvas.getContext("2d");

  // 状態リセット
  shootingCurrentCard=0; shootingPhase="survival"; shootingTime=60;
  shipBullets=[]; meteors=[]; hitEffects=[]; tunas=[];
  bulletTimer=0; meteorTimer=0; bossTimer=0;
  boss.bullets=[]; boss.hp=s3BossMaxHP;
  shootingBossActive=false; lastFrameTime=0;

  s3QuizActive=false; s3QuizShown15=false; s3QuizShown30=false; s3QuizShown45=false;
  s3BossPhase=false; s3BossQuizTimer=0; s3QuizZones=[];
  if(s3QuizCountdown){ clearInterval(s3QuizCountdown); s3QuizCountdown=null; }

  const c=shootingDeck[0];
  shootingPlayerMaxHP=c.hp; shootingPlayerHP=c.hp; shootingPlayerATK=c.atk;
  s3PlayerElement=c.element;

  ship.x=shootCanvas.width/2-ship.w/2;
  ship.y=shootCanvas.height-ship.h-20;

  shootCanvas.addEventListener("touchstart",onShootTouchStart,{passive:false});
  shootCanvas.addEventListener("touchmove", onShootTouchMove, {passive:false});
  shootCanvas.addEventListener("touchend",  onShootTouchEnd,  {passive:false});
  shootCanvas.addEventListener("mousedown", onShootMouseDown);
  shootCanvas.addEventListener("mousemove", onShootMouseMove);
  shootCanvas.addEventListener("mouseup",   onShootMouseUp);

  let tunaTimer=0;
  shootingTimerInterval=setInterval(()=>{
    if(shootingPhase!=="survival")return;
    shootingTime--;
    updateShootHUD();
    if(shootingTime===45&&!s3QuizShown15){ s3QuizShown15=true; triggerS3Quiz(); }
    if(shootingTime===30&&!s3QuizShown30){ s3QuizShown30=true; triggerS3Quiz(); }
    if(shootingTime===15&&!s3QuizShown45){ s3QuizShown45=true; triggerS3Quiz(); }
    if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS3BossPhase(); }
  },1000);
   
  shootingPaused = false; 
  // 小型機チェック
  const subUnlocked = localStorage.getItem("subShipUnlocked")==="true";
  if(subUnlocked){
    ship.subShips = [{offset:-35},{offset:35}];
  } else {
    ship.subShips = [];
  }         // ← 追加
  currentShootingStage = "stage3";
  shootingGameActive=true;
  lockShootingUI();
  updateShootHUD();
  requestAnimationFrame(stage3Loop);
}

// =============================================
//  STAGE 3 BOSS
// =============================================
function startS3BossPhase(){
  shootingPhase="boss"; s3BossPhase=true; shootingBossActive=true;
  boss.x=shootCanvas.width/2-boss.w/2; boss.y=60;
  boss.hp=s3BossMaxHP; boss.vx=2; boss.bullets=[]; meteors=[]; tunas=[]; bossTimer=0; s3BossQuizTimer=0;
  const bossHUD=document.getElementById("shootBossHUD");
  if(bossHUD) bossHUD.style.display="block";
  showShootMessage("⚡ 金星 出現！",2000);
  updateBossHUD();
}

// =============================================
//  STAGE 3 LOOP
// =============================================
function stage3Loop(timestamp){
  if(!shootingGameActive)return;
  const dt=Math.min((timestamp-(lastFrameTime||timestamp))/16.67,3);
  lastFrameTime=timestamp;
  update_stage3(dt);
  draw_stage3();
  shootingAnimFrame=requestAnimationFrame(stage3Loop);
}

let tunaShotTimer=0;

function update_stage3(dt){
  const W=shootCanvas.width, H=shootCanvas.height;
  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // エフェクト更新
  hitEffects.forEach(e=>{
    e.life+=dt; e.alpha=Math.max(0,1-e.life/e.maxLife);
    if(e.type==="debris"){ e.x+=(e.vx||0)*dt; e.y+=(e.vy||0)*dt; e.r=Math.max(0,e.r-0.15*dt); }
    else { e.r+=(e.maxR-e.r)*0.18*dt; }
  });
  hitEffects=hitEffects.filter(e=>e.life<e.maxLife);
  // 回避・無敵タイマー更新
  if(dodgeActive){
    dodgeActiveTimer-=dt;
    if(dodgeActiveTimer<=0){
      dodgeActive=false;
      dodgeCooldown=600; // 10秒（600フレーム）
    }
  }
  if(dodgeCooldown>0){
    dodgeCooldown-=dt;
    if(dodgeCooldown<0) dodgeCooldown=0;
    updateDodgeButton();
  }
  if(dodgeActive) updateDodgeButton();

  // 弾発射　←この行の直後（全ステージ共通）
  bulletTimer+=dt;
  if(bulletTimer>=60){
    bulletTimer=0;
    // メイン弾
    shipBullets.push({x:ship.x+ship.w/2-4,y:ship.y-10,w:8,h:14,active:true});
    // 小型機の弾
    if(ship.subShips && ship.subShips.length>0){
      ship.subShips.forEach(ss=>{
        const angle=15*Math.PI/180;
        const dir=ss.offset<0?-1:1;
        shipBullets.push({
          x:ship.x+ship.w/2+ss.offset-4,
          y:ship.y-10,
          w:6, h:10,
          vx:Math.sin(angle)*4*dir,
          vy:-Math.cos(angle)*8,
          active:true,
          isSub:true,
        });
      });
    }
  }
  shipBullets.forEach(b=>{
    b.x+=(b.vx||0)*dt;
    b.y+=(b.vy||-8)*dt;
  });
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

  if(shootingPhase==="survival"){
    // 隕石生成
    meteorTimer+=dt;
    if(meteorTimer>=50+Math.random()*25){
      meteorTimer=0;
      const mw=36+Math.random()*20, mh=36+Math.random()*20;
      meteors.push({x:Math.random()*(W-mw),y:-mh,w:mw,h:mh,vy:2+Math.random()*2,hp:2,id:Date.now()+Math.random()});
    }
    meteors.forEach(m=>{ m.y+=m.vy*dt; });

    // マグロ生成（3秒に1匹）
    tunaShotTimer+=dt;
    if(tunaShotTimer>=180+Math.random()*60){
      tunaShotTimer=0;
      const side=Math.random()<0.5?"left":"right";
      tunas.push({
        x: side==="left"?-60:W+10,
        y: H*0.2+Math.random()*H*0.5,
        w:60, h:28,
        vx: side==="left"?3.5:-3.5,
        hp:3,
        id:Date.now()+Math.random(),
        side
      });
    }
    tunas.forEach(t=>{ t.x+=t.vx*dt; });

    // 自弾 vs 隕石
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let mi=meteors.length-1;mi>=0;mi--){
        const m=meteors[mi]; if(m.hp<=0)continue;
        if(rectsOverlap(b,m)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#FFD93D");
          b.active=false; m.hp--;
          if(m.hp<=0){
            spawnMeteorBreakEffect(m.x+m.w/2,m.y+m.h/2);
            const heal=Math.floor(shootingPlayerMaxHP*0.02);
            shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
            spawnHealEffect(ship.x+ship.w/2,ship.y);
            updateShootHUD(); meteors.splice(mi,1);
          }
          break;
        }
      }
    }

    // 自弾 vs マグロ
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let ti=tunas.length-1;ti>=0;ti--){
        const t=tunas[ti]; if(t.hp<=0)continue;
        if(rectsOverlap(b,t)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#00BFFF");
          b.active=false; t.hp--;
          if(t.hp<=0){
            spawnMeteorBreakEffect(t.x+t.w/2,t.y+t.h/2);
            const heal=Math.floor(shootingPlayerMaxHP*0.01);
            shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
            updateShootHUD(); tunas.splice(ti,1);
          }
          break;
        }
      }
    }

    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
    meteors=meteors.filter(m=>m.hp>0&&m.y<H+50);
    tunas=tunas.filter(t=>t.hp>0&&t.x>-80&&t.x<W+80);

    // 隕石 vs プレイヤー
    for(let mi=meteors.length-1;mi>=0;mi--){
      const m=meteors[mi];
      if(rectsOverlap(ship,m)){
        meteors.splice(mi,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        shootingPlayerHP-=300; updateShootHUD();
        if(shootingPlayerHP<=0) handlePlayerDeath();
      }
    }

    // マグロ vs プレイヤー
    for(let ti=tunas.length-1;ti>=0;ti--){
      const t=tunas[ti];
      if(rectsOverlap(ship,t)){
        tunas.splice(ti,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#00BFFF");
        shootingPlayerHP-=400; updateShootHUD();
        if(shootingPlayerHP<=0) handlePlayerDeath();
      }
    }

  } else if(shootingPhase==="boss"){
    boss.x+=boss.vx*dt;
    if(boss.x<=0||boss.x+boss.w>=W) boss.vx*=-1;
    const minY=boss.y+boss.h+10;
    if(ship.y<minY) ship.y=minY;

    // ボスクイズ（15秒に1回）
    s3BossQuizTimer+=dt;
    if(s3BossQuizTimer>=900){ s3BossQuizTimer=0; if(!s3QuizActive) triggerS3Quiz(); }

    // ボス攻撃（2〜4秒に1回、ランダムで通常/大弾/3方向）
    bossTimer+=dt;
    const fireInterval=120+Math.random()*120;
    if(bossTimer>=fireInterval){
      bossTimer=0;
      const roll=Math.random();
      const bx=boss.x+boss.w/2, by=boss.y+boss.h;
      if(roll<0.4){
        // 通常弾
        boss.bullets.push({x:bx-7,y:by,w:14,h:14,vx:0,vy:4,active:true,big:false});
      } else if(roll<0.7){
        // でかい弾
        boss.bullets.push({x:bx-18,y:by,w:36,h:36,vx:0,vy:3,active:true,big:true});
      } else {
        // 3方向弾
        [-1,0,1].forEach(dir=>{
          boss.bullets.push({x:bx-7,y:by,w:14,h:14,vx:dir*2.5,vy:3.5,active:true,big:false});
        });
      }
    }

    boss.bullets.forEach(b=>{ b.x+=b.vx*dt; b.y+=b.vy*dt; });

    // ボス弾 vs プレイヤー
    for(let i=boss.bullets.length-1;i>=0;i--){
      const b=boss.bullets[i]; if(!b.active)continue;
      if(rectsOverlap(b,ship)){
        boss.bullets.splice(i,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FFD700");
        const mult=getElementMultiplier(s3BossElement,s3PlayerElement);
        const dmg=Math.floor(s3BossATK*(b.big?2:1)*mult);
        shootingPlayerHP-=dmg; updateShootHUD();
        if(shootingPlayerHP<=0) handlePlayerDeath();
      }
    }
    boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+50&&b.x>-50&&b.x<W+50);

    // 自弾 vs ボス
    const bossRect={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      if(rectsOverlap(b,bossRect)){
        spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
        b.active=false;
        const mult=getElementMultiplier(s3PlayerElement,s3BossElement);
        boss.hp-=Math.floor(shootingPlayerATK*mult);
        updateBossHUD();
        if(boss.hp<=0){ clearStage3(); return; }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
  }
}

// =============================================
//  STAGE 3 QUIZ
// =============================================
function triggerS3Quiz(){
  if(s3QuizActive)return;
  s3QuizActive=true;
  const card=target1900Cards[Math.floor(Math.random()*target1900Cards.length)];
  const q=card.quizzes[Math.floor(Math.random()*card.quizzes.length)];
  s3QuizAnswer=q.correct;
  s3QuizWord=card.word;
  const wrongs=q.choices.sort(()=>Math.random()-0.5).slice(0,3);
  const allChoices=[...wrongs,q.correct].sort(()=>Math.random()-0.5);

  const W=shootCanvas.width, H=shootCanvas.height;
  const zoneTop=H*0.55, zoneH=(H-zoneTop-20)/2, zoneW=W/2-8;
  s3QuizZones=[
    {label:allChoices[0],x:4,     y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[1],x:W/2+4, y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[2],x:4,     y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
    {label:allChoices[3],x:W/2+4, y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
  ];
  s3QuizTimer=5;
  if(s3QuizCountdown) clearInterval(s3QuizCountdown);
  s3QuizCountdown=setInterval(()=>{
    s3QuizTimer--;
    if(s3QuizTimer<=0){ clearInterval(s3QuizCountdown); s3QuizCountdown=null; judgeS3Quiz(); }
  },1000);
}

function judgeS3Quiz(){
  s3QuizActive=false;
  const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
  let chosen=null;
  for(const z of s3QuizZones){ if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){ chosen=z.label; break; } }
  s3QuizZones=[];
  if(chosen===s3QuizAnswer){  // ← 各ステージの変数名に合わせる
    diamonds+=3; saveGame();
    showQuizResult(true,"");
  } else {
    shootingPlayerHP-=600; updateShootHUD();
    showQuizResult(false, s3QuizAnswer); // ← 各ステージの変数名に合わせる
    const wrongCard=target1900Cards.find(c=>c.word===s3QuizWord);
    if(wrongCard) recordWrongWord("target1900", wrongCard.word, wrongCard.meaning);
    if(shootingPlayerHP<=0) handlePlayerDeath();
  }
}

// =============================================
//  DRAW STAGE 3
// =============================================
function draw_stage3(){
  const ctx=shootCtx, W=shootCanvas.width, H=shootCanvas.height;
  ctx.fillStyle="#000020"; ctx.fillRect(0,0,W,H);

  // 星（少し多め）
  ctx.fillStyle="rgba(255,255,255,0.5)";
  for(let i=0;i<80;i++) ctx.fillRect((i*97+30)%W,(i*137+50)%H,1.5,1.5);

  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // クイズゾーン
  if(s3QuizActive&&s3QuizZones.length>0){
    ctx.save();
    ctx.fillStyle="rgba(0,0,0,0.8)";
    ctx.beginPath(); ctx.roundRect(W*0.03,H*0.47,W*0.94,46,8); ctx.fill();
    ctx.fillStyle="#FFD93D"; ctx.font=`bold ${Math.floor(W*0.034)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText(`「${s3QuizWord}」の意味は？`,W/2,H*0.47+16);
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.font=`${Math.floor(W*0.028)}px sans-serif`;
    ctx.fillText(`⏱ ${s3QuizTimer}秒 いるゾーンが回答！`,W/2,H*0.47+34);
    ctx.restore();

    const zoneColors=["rgba(255,107,107,0.3)","rgba(77,150,255,0.3)","rgba(107,203,119,0.3)","rgba(255,217,61,0.3)"];
    const zoneBorders=["#FF6B6B","#4D96FF","#6BCB77","#FFD93D"];
    s3QuizZones.forEach((z,i)=>{
      ctx.save();
      ctx.fillStyle=zoneColors[i%4]; ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=2;
      ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.fill(); ctx.stroke();
      ctx.fillStyle="#fff"; ctx.textAlign="center"; ctx.textBaseline="middle";
      const fs=Math.floor(W*0.026); ctx.font=`bold ${fs}px sans-serif`;
      const lines=wrapText(ctx,z.label,z.w-14,fs);
      const lh=fs+3, sy=z.y+z.h/2-(lines.length-1)*lh/2;
      lines.forEach((l,li)=>ctx.fillText(l,z.x+z.w/2,sy+li*lh));
      const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
      if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){
        ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=4;
        ctx.shadowColor=zoneBorders[i%4]; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.stroke();
      }
      ctx.restore();
    });
  }

  // 隕石
  meteors.forEach(m=>{
    ctx.save();
    ctx.fillStyle="#8B6914"; ctx.shadowColor="rgba(139,105,20,0.5)"; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    ctx.fillStyle="#6B4F10"; ctx.shadowBlur=0;
    ctx.beginPath(); ctx.ellipse(m.x+m.w*0.35,m.y+m.h*0.35,m.w*0.15,m.h*0.12,0.5,0,Math.PI*2); ctx.fill();
    if(m.hp===1){ ctx.strokeStyle="rgba(255,107,107,0.8)"; ctx.lineWidth=1.5; ctx.beginPath(); ctx.moveTo(m.x+m.w*0.4,m.y+m.h*0.2); ctx.lineTo(m.x+m.w*0.55,m.y+m.h*0.5); ctx.lineTo(m.x+m.w*0.45,m.y+m.h*0.8); ctx.stroke(); }
    ctx.restore();
  });

  // マグロ
  tunas.forEach(t=>{
    ctx.save();
    const facingRight = t.vx > 0;
    ctx.save();
    ctx.translate(t.x+t.w/2, t.y+t.h/2);
    if(!facingRight) ctx.scale(-1,1);

    // 体
    ctx.fillStyle="#1a6fa8"; ctx.shadowColor="rgba(0,180,255,0.5)"; ctx.shadowBlur=8;
    ctx.beginPath();
    ctx.ellipse(0,0,t.w/2,t.h/2,0,0,Math.PI*2); ctx.fill();

    // お腹（白）
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.shadowBlur=0;
    ctx.beginPath(); ctx.ellipse(2,4,t.w/3,t.h/3.5,0,0,Math.PI*2); ctx.fill();

    // 目
    ctx.fillStyle="#fff";
    ctx.beginPath(); ctx.arc(t.w/2-8,-2,4,0,Math.PI*2); ctx.fill();
    ctx.fillStyle="#000";
    ctx.beginPath(); ctx.arc(t.w/2-7,-2,2,0,Math.PI*2); ctx.fill();

    // 尾びれ
    ctx.fillStyle="#1a5a8a";
    ctx.beginPath();
    ctx.moveTo(-t.w/2,0);
    ctx.lineTo(-t.w/2-14,-t.h/2);
    ctx.lineTo(-t.w/2-14,t.h/2);
    ctx.closePath(); ctx.fill();

    // 背びれ
    ctx.fillStyle="#1a5a8a";
    ctx.beginPath();
    ctx.moveTo(0,-t.h/2);
    ctx.lineTo(-8,-t.h/2-10);
    ctx.lineTo(-16,-t.h/2);
    ctx.closePath(); ctx.fill();

    // HPゲージ（3→赤くなる）
    const hpColor=t.hp===3?"#6BCB77":t.hp===2?"#FFD93D":"#FF6B6B";
    ctx.fillStyle="rgba(0,0,0,0.4)";
    ctx.beginPath(); ctx.roundRect(-t.w/2,-t.h/2-12,t.w,6,3); ctx.fill();
    ctx.fillStyle=hpColor;
    ctx.beginPath(); ctx.roundRect(-t.w/2,-t.h/2-12,t.w*(t.hp/3),6,3); ctx.fill();

    ctx.restore();
    ctx.restore();
  });

  // 自弾
  shipBullets.forEach(b=>{
    if(!b.active)return;
    ctx.save();
    const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+b.h);
    g.addColorStop(0,"#fff"); g.addColorStop(1,"#FFD700");
    ctx.fillStyle=g; ctx.shadowColor="#FFD700"; ctx.shadowBlur=10;
    ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h,4); ctx.fill();
    ctx.restore();
  });

  // ボスフェーズ
  if(shootingPhase==="boss"){
    boss.bullets.forEach(b=>{
      ctx.save();
      ctx.fillStyle=b.big?"#FF9500":"#FFD700";
      ctx.shadowColor=b.big?"#FF9500":"#FFD700"; ctx.shadowBlur=b.big?20:12;
      ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
      if(b.big){
        ctx.strokeStyle="rgba(255,255,255,0.4)"; ctx.lineWidth=3;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.stroke();
      }
      ctx.restore();
    });

    // 金星
    const bossHPRatio=Math.max(0,boss.hp/s3BossMaxHP);
    ctx.save();
    ctx.shadowColor=`rgba(255,215,0,0.8)`; ctx.shadowBlur=25+(1-bossHPRatio)*30;
    const pg=ctx.createRadialGradient(boss.x+boss.w*0.35,boss.y+boss.h*0.3,boss.w*0.05,boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2);
    pg.addColorStop(0,"#FFF0A0"); pg.addColorStop(0.4,"#FFD700"); pg.addColorStop(0.8,"#FF9500"); pg.addColorStop(1,"#CC6600");
    ctx.fillStyle=pg;
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.fill();
    // 渦巻き模様
    ctx.strokeStyle="rgba(255,200,0,0.4)"; ctx.lineWidth=2; ctx.shadowBlur=0;
    for(let ri=0;ri<3;ri++){
      ctx.beginPath();
      ctx.ellipse(boss.x+boss.w/2,boss.y+boss.h/2,boss.w*(0.2+ri*0.12),boss.h*(0.1+ri*0.06),ri*0.8,0,Math.PI*2);
      ctx.stroke();
    }
    // HP低下でひび
    if(bossHPRatio<0.5){
      ctx.strokeStyle=`rgba(255,100,0,${0.5+(1-bossHPRatio)*0.5})`; ctx.lineWidth=2;
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.3,boss.y+boss.h*0.1); ctx.lineTo(boss.x+boss.w*0.5,boss.y+boss.h*0.5); ctx.lineTo(boss.x+boss.w*0.7,boss.y+boss.h*0.9); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.6,boss.y+boss.h*0.15); ctx.lineTo(boss.x+boss.w*0.4,boss.y+boss.h*0.55); ctx.stroke();
    }
    ctx.restore();
  }

  // エフェクト
  hitEffects.forEach(e=>{
    if(e.alpha<=0)return;
    ctx.save(); ctx.globalAlpha=e.alpha;
    if(e.type==="debris"){ ctx.fillStyle=e.color; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill(); }
    else if(e.type==="heal"){ ctx.strokeStyle=e.color; ctx.lineWidth=3; ctx.shadowColor=e.color; ctx.shadowBlur=12; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.font=`bold ${Math.max(8,Math.floor(e.r*0.8))}px sans-serif`; ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.fillText("+",e.x,e.y-Math.max(0,e.r)*1.2); }
    else { ctx.strokeStyle=e.color; ctx.lineWidth=2.5; ctx.shadowColor=e.color; ctx.shadowBlur=14; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.globalAlpha=e.alpha*0.3; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r*0.5),0,Math.PI*2); ctx.fill(); }
    ctx.restore();
  });

  // 宇宙船
  drawSpaceShip(ctx,ship.x,ship.y,ship.w,ship.h);
  if(dodgeActive){
    ctx.save();
    const pulse=Math.sin(Date.now()*0.02)*0.3+0.7;
    ctx.strokeStyle=`rgba(255,255,255,${pulse})`;
    ctx.lineWidth=3;
    ctx.shadowColor="#fff";
    ctx.shadowBlur=20;
    ctx.beginPath();
    ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();
  }
  // 小型機描画
  if(ship.subShips && ship.subShips.length>0){
    ship.subShips.forEach(ss=>{
      const sx=ship.x+ship.w/2+ss.offset-12;
      const sy=ship.y+8;
      drawRVSubShip(ctx,sx,sy,"#4D96FF");
    });
  }

  // HPバー
  const hpRatio=Math.max(0,shootingPlayerHP/shootingPlayerMaxHP);
  const barW=W*0.5,barX=(W-barW)/2,barY=H-14;
  ctx.save();
  ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(barX,barY,barW,8,4); ctx.fill();
  const hpColor=hpRatio>0.5?"#6BCB77":hpRatio>0.25?"#FFD93D":"#FF6B6B";
  ctx.fillStyle=hpColor; ctx.shadowColor=hpColor; ctx.shadowBlur=6;
  ctx.beginPath(); ctx.roundRect(barX,barY,barW*hpRatio,8,4); ctx.fill();
  ctx.restore();

  // 属性バッジ
  drawElementBadge(ctx,W,s3PlayerElement);
}

// =============================================
//  STAGE 3 CLEAR / GAMEOVER
// =============================================
function clearStage3(){
  unlockShootingUI(); // ← 追加
  shootingPhase="clear"; shootingGameActive=false;
  clearInterval(shootingTimerInterval);
  if(s3QuizCountdown) clearInterval(s3QuizCountdown);
  cancelAnimationFrame(shootingAnimFrame);
  removeShootListeners();
  const firstClear=!isStage3Cleared();
  if(firstClear){ markStage3Cleared(); diamonds+=15; saveGame(); }
  draw_stage3();
  setTimeout(()=>{
    document.getElementById("spaceArea").innerHTML=`
      <div style="text-align:center;padding:30px 16px">
        <div style="font-size:4rem;margin-bottom:10px">🏆</div>
        <div style="font-family:'Fredoka One',cursive;font-size:2rem;background:linear-gradient(90deg,#FFD700,#FF9500);-webkit-background-clip:text;-webkit-text-fill-color:transparent;margin-bottom:8px">STAGE 3 CLEAR!</div>
        ${firstClear?`<div style="font-family:'Fredoka One',cursive;font-size:1.3rem;color:#FFD93D;margin-bottom:6px">💎×15 獲得！</div>`:`<div style="font-size:13px;color:rgba(255,255,255,0.4);margin-bottom:6px">※2回目以降クリア報酬なし</div>`}
        <div style="font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:20px">⚡ 金星を撃破した！<br><span style="font-size:12px;color:rgba(255,255,255,0.4)">※クイズ正解で💎×3（回数無制限）</span></div>
        <button onclick="showStage3DeckSelect()" style="background:linear-gradient(135deg,#FFD700,#FF9500);font-size:1rem;padding:14px 28px;margin:6px">🔄 もう一度</button>
        <br>
        <button onclick="showNormalStageMenu()" style="background:rgba(255,255,255,0.08);box-shadow:none;font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">← ステージ選択へ</button>
      </div>`;
    spawnStars();
  },500);
}

// =============================================
//  STAGE 4
// =============================================
let s4PlayerElement  = "fire";
let s4BossElement    = "water"; // 火星は水属性に弱い（木が強い）
let s4BossMaxHP      = 13000;
let s4BossATK        = 400;
let s4QuizActive     = false;
let s4QuizAnswer     = "";
let s4QuizZones      = [];
let s4QuizTimer      = 0;
let s4QuizWord       = "";
let s4QuizCountdown  = null;
let s4QuizShown15    = false;
let s4QuizShown30    = false;
let s4QuizShown45    = false;
let s4BossQuizTimer  = 0;
let s4BossPhase      = false;
let s4Walls          = []; // 障害物（岩壁）
let s4WallTimer      = 0;

function showStage4DeckSelect(){
  const pool = owned.filter(c=>c.type==="target1900");
  const grouped = {};
  pool.forEach(c=>{ if(!grouped[c.word]) grouped[c.word]=c; });
  const cards = Object.values(grouped);

  const area = document.getElementById("spaceArea");
  area.innerHTML = `
    <div style="text-align:center;padding:12px">
      <div style="font-family:'Fredoka One',cursive;font-size:1.1rem;color:#FF4444;margin-bottom:8px">🔴 ステージ４ デッキ選択</div>
      <div style="background:rgba(255,68,68,0.1);border:1px solid rgba(255,68,68,0.3);border-radius:12px;padding:10px;margin:0 auto 12px;max-width:320px;font-size:12px;color:rgba(255,255,255,0.7);text-align:left;line-height:1.8">
        🌋 <b>ステージ4 特殊ギミック</b><br>
        岩壁が横断してくる！弾を遮断・触れるとダメージ！<br>
        <br>🔥 ボス属性：<b style="color:#FF4444">火属性</b>（水属性が有利！）<br>
        クイズ正解で💎×3獲得！
      </div>
      <div style="font-size:13px;color:#FF4444;margin-bottom:8px">選択: <span id="s4SelectedCount">0</span> / 2</div>
      <div id="s4CardPicker" style="display:flex;flex-wrap:wrap;justify-content:center;gap:8px;margin-bottom:16px"></div>
      <div id="s4SelectedDisplay" style="display:flex;justify-content:center;gap:12px;margin-bottom:16px;min-height:60px"></div>
      <div style="position:fixed;bottom:70px;right:16px;z-index:1000">
  <button id="s4StartBtn" disabled
    style="background:linear-gradient(135deg,#FFD93D,#FF6B6B);
      font-size:1rem;padding:14px 20px;border-radius:20px;
      opacity:0.4;cursor:not-allowed;
      box-shadow:0 4px 20px rgba(0,0,0,0.4)">
    🚀 スタート！
  </button>
</div>
      <br>
      <button onclick="showNormalStageMenu()"
        style="background:rgba(255,255,255,0.08);box-shadow:none;font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">← 戻る</button>
    </div>`;

  if(cards.length===0){
    document.getElementById("s4CardPicker").innerHTML=`<div style="color:rgba(255,255,255,0.4);font-size:13px;padding:20px">ターゲット1900カードがありません！</div>`;
    return;
  }

  let selected=[];

  function renderPicker(){
    document.getElementById("s4SelectedCount").textContent=selected.length;
    document.getElementById("s4CardPicker").innerHTML=cards.map(c=>{
      const idx=selected.findIndex(s=>s.word===c.word);
      const isSel=idx!==-1;
    
      return `<div onclick="s4ToggleCard('${c.word}')"
        style="cursor:pointer;width:95px;padding:10px 6px;border-radius:14px;
          background:${isSel?"rgba(255,217,61,0.2)":"rgba(255,255,255,0.06)"};
          border:2px solid ${isSel?c.elementColor:"rgba(255,255,255,0.15)"};
          text-align:center;transition:all 0.15s;position:relative">
        ${isSel?`<div style="position:absolute;top:-6px;right:-6px;background:#FFD93D;border-radius:50%;width:18px;height:18px;font-size:10px;display:flex;align-items:center;justify-content:center;color:#1a1a2e;font-weight:700">${idx+1}</div>`:""}
        <div style="font-size:1rem">${c.elementLabel.split(" ")[0]}</div>
        <div style="font-family:'Fredoka One',cursive;font-size:0.8rem;color:#fff">${c.word}</div>
        <div style="font-size:10px;color:rgba(255,255,255,0.5)">${c.meaning}</div>
        <div style="font-size:10px;color:${c.elementColor}">⚔️${c.atk} ❤️${c.hp}</div>
      </div>`;
    }).join("");

    document.getElementById("s4SelectedDisplay").innerHTML=[0,1].map(i=>{
      const c=selected[i];
      return c
        ?`<div style="background:rgba(255,255,255,0.08);border:1px solid ${c.elementColor};border-radius:12px;padding:8px 14px;text-align:center;min-width:80px">
            <div style="font-size:10px;color:rgba(255,255,255,0.4)">${i===0?"1枚目（メイン）":"2枚目（予備）"}</div>
            <div style="font-family:'Fredoka One',cursive;font-size:0.85rem;color:#fff">${c.word}</div>
            <div style="font-size:10px;color:${c.elementColor}">⚔️${c.atk} ❤️${c.hp}</div>
          </div>`
        :`<div style="background:rgba(255,255,255,0.03);border:1px dashed rgba(255,255,255,0.15);border-radius:12px;padding:8px 14px;text-align:center;min-width:80px;color:rgba(255,255,255,0.25);font-size:12px">${i===0?"1枚目":"2枚目"}<br>未選択</div>`;
    }).join("");

    const btn=document.getElementById("s4StartBtn");
    btn.disabled=selected.length!==2;
    btn.style.opacity=selected.length===2?"1":"0.4";
    btn.style.cursor=selected.length===2?"pointer":"not-allowed";
  }

  window.s4ToggleCard=function(word){
    const c=cards.find(x=>x.word===word);
    const idx=selected.findIndex(s=>s.word===word);
    if(idx!==-1){ selected.splice(idx,1); } else { if(selected.length>=2)return; selected.push(c); }
    renderPicker();
  };

  document.getElementById("s4StartBtn").onclick=()=>{
    if(selected.length<2)return;
    shootingDeck=selected;
    beginStage4();
  };
  renderPicker();
}

// =============================================
//  BEGIN STAGE 4
// =============================================
function beginStage4(){
  // 既存のタイマーを必ずクリア
if(shootingTimerInterval){
  clearInterval(shootingTimerInterval);
  shootingTimerInterval = null;
}
if(shootingAnimFrame){
  cancelAnimationFrame(shootingAnimFrame);
  shootingAnimFrame = null;
}
  const area=document.getElementById("spaceArea");
  area.innerHTML=`
    <div style="position:relative;width:100%;max-width:420px;margin:0 auto">
      <canvas id="shootCanvas" style="display:block;width:100%;border-radius:16px;background:#1a0005;touch-action:none"></canvas>
      <div id="shootQuizResult"
  style="position:absolute;bottom:30px;left:50%;transform:translateX(-50%);
    font-family:'Fredoka One',cursive;font-size:1rem;
    background:rgba(0,0,0,0.7);border-radius:12px;padding:6px 16px;
    pointer-events:none;display:none;text-align:center;
    white-space:pre-line;z-index:100;min-width:200px">
</div>
      <button onclick="toggleShootingPause()"
  style="position:absolute;top:8px;right:8px;
    background:rgba(0,0,0,0.5);border:1px solid rgba(255,255,255,0.3);
    color:#fff;font-size:12px;padding:5px 10px;border-radius:8px;
    z-index:2100;cursor:pointer">
  ⏸ ポーズ
</button>
      <div id="shootHUD" style="position:absolute;top:8px;left:8px;right:8px;display:flex;justify-content:space-between;pointer-events:none">
        <div id="shootHP" style="font-family:'Fredoka One',cursive;font-size:14px;color:#6BCB77;text-shadow:0 0 8px rgba(107,203,119,0.8)">❤️ 0</div>
        <div id="shootTimer" style="font-family:'Fredoka One',cursive;font-size:14px;color:#FFD93D;text-shadow:0 0 8px rgba(255,217,61,0.8)">⏱ 60</div>
        <div id="shootCard" style="font-family:'Fredoka One',cursive;font-size:11px;color:#FF4444">🚀 1枚目</div>
      </div>
      <div id="shootBossHUD" style="position:absolute;top:36px;left:8px;right:8px;display:none;pointer-events:none">
        <div style="font-family:'Fredoka One',cursive;font-size:11px;color:#FF4444;text-align:center;margin-bottom:2px">🔴 火星</div>
        <div style="background:rgba(0,0,0,0.4);border-radius:8px;height:10px;overflow:hidden">
          <div id="shootBossHPBar" style="height:100%;background:linear-gradient(90deg,#FF4444,#FF9500);border-radius:8px;transition:width 0.3s;width:100%"></div>
        </div>
      </div>
      <div id="shootMessage" style="position:absolute;top:45%;left:50%;transform:translate(-50%,-50%);font-family:'Fredoka One',cursive;font-size:1.2rem;color:#fff;text-align:center;pointer-events:none;text-shadow:0 0 20px rgba(255,255,255,0.8);display:none;background:rgba(0,0,0,0.6);border-radius:12px;padding:8px 16px;white-space:pre-line"></div>
    </div>`;

  shootCanvas=document.getElementById("shootCanvas");
  const maxW=Math.min(420,window.innerWidth-32);
  shootCanvas.width=maxW;
  shootCanvas.height=Math.floor(maxW*1.5);
  shootCtx=shootCanvas.getContext("2d");

  // 状態リセット
  shootingCurrentCard=0; shootingPhase="survival"; shootingTime=60;
  shipBullets=[]; meteors=[]; hitEffects=[]; s4Walls=[];
  bulletTimer=0; meteorTimer=0; bossTimer=0; s4WallTimer=0;
  boss.bullets=[]; boss.hp=s4BossMaxHP;
  shootingBossActive=false; lastFrameTime=0;

  s4QuizActive=false; s4QuizShown15=false; s4QuizShown30=false; s4QuizShown45=false;
  s4BossPhase=false; s4BossQuizTimer=0; s4QuizZones=[];
  if(s4QuizCountdown){ clearInterval(s4QuizCountdown); s4QuizCountdown=null; }

  const c=shootingDeck[0];
  shootingPlayerMaxHP=c.hp; shootingPlayerHP=c.hp; shootingPlayerATK=c.atk;
  s4PlayerElement=c.element;

  ship.x=shootCanvas.width/2-ship.w/2;
  ship.y=shootCanvas.height-ship.h-20;

  shootCanvas.addEventListener("touchstart",onShootTouchStart,{passive:false});
  shootCanvas.addEventListener("touchmove", onShootTouchMove, {passive:false});
  shootCanvas.addEventListener("touchend",  onShootTouchEnd,  {passive:false});
  shootCanvas.addEventListener("mousedown", onShootMouseDown);
  shootCanvas.addEventListener("mousemove", onShootMouseMove);
  shootCanvas.addEventListener("mouseup",   onShootMouseUp);

  shootingTimerInterval=setInterval(()=>{
    if(shootingPhase!=="survival")return;
    shootingTime--;
    updateShootHUD();
    if(shootingTime===45&&!s4QuizShown15){ s4QuizShown15=true; triggerS4Quiz(); }
    if(shootingTime===30&&!s4QuizShown30){ s4QuizShown30=true; triggerS4Quiz(); }
    if(shootingTime===15&&!s4QuizShown45){ s4QuizShown45=true; triggerS4Quiz(); }
    if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS4BossPhase(); }
  },1000);

  shootingGameActive=true;
  shootingPaused=false;          // ← 追加
  currentShootingStage="stage4"; // ← すでにあるはず、なければ追加
  // 小型機チェック
  const subUnlocked=localStorage.getItem("subShipUnlocked")==="true";
  if(subUnlocked){ ship.subShips=[{offset:-35},{offset:35}]; }
  else { ship.subShips=[]; }
  shootingGameActive=true;
  lockShootingUI();
  dodgeUnlocked = localStorage.getItem("dodgeUnlocked")==="true";
  dodgeCooldown = 0;
  dodgeActive   = false;
  dodgeActiveTimer = 0;
  renderDodgeButton();
  updateShootHUD();
  requestAnimationFrame(stage4Loop);
}

// =============================================
//  STAGE 4 BOSS
// =============================================
function startS4BossPhase(){
  shootingPhase="boss"; s4BossPhase=true; shootingBossActive=true;
  boss.x=shootCanvas.width/2-boss.w/2; boss.y=60;
  boss.hp=s4BossMaxHP; boss.vx=2.2; boss.bullets=[]; meteors=[]; s4Walls=[]; bossTimer=0; s4BossQuizTimer=0;
  const bossHUD=document.getElementById("shootBossHUD");
  if(bossHUD) bossHUD.style.display="block";
  showShootMessage("🔴 火星 出現！\n岩壁に気をつけろ！",2500);
  updateBossHUD();
}

// =============================================
//  STAGE 4 LOOP
// =============================================
function stage4Loop(timestamp){
  if(!shootingGameActive)return;
  const dt=Math.min((timestamp-(lastFrameTime||timestamp))/16.67,3);
  lastFrameTime=timestamp;
  update_stage4(dt);
  draw_stage4();
  shootingAnimFrame=requestAnimationFrame(stage4Loop);
}

// =============================================
//  UPDATE STAGE 4
// =============================================
function update_stage4(dt){
  const W=shootCanvas.width, H=shootCanvas.height;
  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // エフェクト更新
  hitEffects.forEach(e=>{
    e.life+=dt; e.alpha=Math.max(0,1-e.life/e.maxLife);
    if(e.type==="debris"){ e.x+=(e.vx||0)*dt; e.y+=(e.vy||0)*dt; e.r=Math.max(0,e.r-0.15*dt); }
    else { e.r+=(e.maxR-e.r)*0.18*dt; }
  });
  hitEffects=hitEffects.filter(e=>e.life<e.maxLife);
  // 回避・無敵タイマー更新
  if(dodgeActive){
    dodgeActiveTimer-=dt;
    if(dodgeActiveTimer<=0){
      dodgeActive=false;
      dodgeCooldown=600; // 10秒（600フレーム）
    }
  }
  if(dodgeCooldown>0){
    dodgeCooldown-=dt;
    if(dodgeCooldown<0) dodgeCooldown=0;
    updateDodgeButton();
  }
  if(dodgeActive) updateDodgeButton();

  /// 弾発射　←この行の直後（全ステージ共通）
  bulletTimer+=dt;
  if(bulletTimer>=60){
    bulletTimer=0;
    // メイン弾
    shipBullets.push({x:ship.x+ship.w/2-4,y:ship.y-10,w:8,h:14,active:true});
    // 小型機の弾
    if(ship.subShips && ship.subShips.length>0){
      ship.subShips.forEach(ss=>{
        const angle=15*Math.PI/180;
        const dir=ss.offset<0?-1:1;
        shipBullets.push({
          x:ship.x+ship.w/2+ss.offset-4,
          y:ship.y-10,
          w:6, h:10,
          vx:Math.sin(angle)*4*dir,
          vy:-Math.cos(angle)*8,
          active:true,
          isSub:true,
        });
      });
    }
  }
  shipBullets.forEach(b=>{
    b.x+=(b.vx||0)*dt;
    b.y+=(b.vy||-8)*dt;
  });
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

  // ===== 岩壁更新（サバイバル・ボス両方） =====
  // 岩壁生成：サバイバル中は8秒、ボス中は5秒ごと
  s4WallTimer+=dt;
  const wallInterval = shootingPhase==="boss" ? 300 : 480;
  if(s4WallTimer>=wallInterval){
    s4WallTimer=0;
    spawnS4Wall(W, H);
  }

  // 岩壁移動（下から上へ、または左右から横断）
  s4Walls.forEach(w=>{
    if(w.dir==="down"){
      w.y+=w.vy*dt;
    } else if(w.dir==="left"){
      w.x+=w.vx*dt;
    } else {
      w.x+=w.vx*dt;
    }
  });
  s4Walls=s4Walls.filter(w=>w.y<H+60&&w.y>-60&&w.x>-W&&w.x<W*2);

  // 自弾 vs 岩壁（弾が岩壁に当たると消える）
  for(let bi=shipBullets.length-1;bi>=0;bi--){
    const b=shipBullets[bi]; if(!b.active)continue;
    for(const w of s4Walls){
      if(rectsOverlap(b,w)){
        spawnHitEffect(b.x+b.w/2,b.y,"#C8A96E");
        b.active=false;
        break;
      }
    }
  }
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

  // 岩壁 vs プレイヤー（触れたらダメージ＋押し出し、即死なし）
for(let wi=s4Walls.length-1;wi>=0;wi--){
  const w=s4Walls[wi];
  if(rectsOverlap(ship,w)){
    spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF4444");
    
    // 押し出し処理
    if(w.dir==="down"){ ship.y=w.y-ship.h-2; }
    else if(w.dir==="left"){ ship.x=w.x+w.w+2; }
    else { ship.x=w.x-ship.w-2; }
    ship.x=Math.max(0,Math.min(W-ship.w,ship.x));
    ship.y=Math.max(0,Math.min(H-ship.h,ship.y));
    // ダメージなし（押し出すだけ）
  }
}

  if(shootingPhase==="survival"){
    // 隕石生成（ST3より多め）
    meteorTimer+=dt;
    if(meteorTimer>=40+Math.random()*20){
      meteorTimer=0;
      const mw=32+Math.random()*20, mh=32+Math.random()*20;
      meteors.push({x:Math.random()*(W-mw),y:-mh,w:mw,h:mh,vy:2.5+Math.random()*2.5,hp:2,id:Date.now()+Math.random()});
    }
    meteors.forEach(m=>{ m.y+=m.vy*dt; });

    // 自弾 vs 隕石
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let mi=meteors.length-1;mi>=0;mi--){
        const m=meteors[mi]; if(m.hp<=0)continue;
        if(rectsOverlap(b,m)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#FFD93D");
          b.active=false; m.hp--;
          if(m.hp<=0){
            spawnMeteorBreakEffect(m.x+m.w/2,m.y+m.h/2);
            const heal=Math.floor(shootingPlayerMaxHP*0.015);
            shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
            spawnHealEffect(ship.x+ship.w/2,ship.y);
            updateShootHUD(); meteors.splice(mi,1);
          }
          break;
        }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
    meteors=meteors.filter(m=>m.hp>0&&m.y<H+50);

    // 隕石 vs プレイヤー
    for(let mi=meteors.length-1;mi>=0;mi--){
      const m=meteors[mi];
      if(rectsOverlap(ship,m)){
        meteors.splice(mi,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        shootingPlayerHP-=350; updateShootHUD();
        if(shootingPlayerHP<=0){ handlePlayerDeath(); return; }
      }
    }

  } else if(shootingPhase==="boss"){
    boss.x+=boss.vx*dt;
    if(boss.x<=0||boss.x+boss.w>=W) boss.vx*=-1;
    const minY=boss.y+boss.h+10;
    if(ship.y<minY) ship.y=minY;

    // ボスクイズ（20秒に1回）
    s4BossQuizTimer+=dt;
    if(s4BossQuizTimer>=1200){ s4BossQuizTimer=0; if(!s4QuizActive) triggerS4Quiz(); }

    // ボス攻撃（岩壁弾 + 通常弾の混合）
    bossTimer+=dt;
    if(bossTimer>=100+Math.random()*80){
      bossTimer=0;
      const roll=Math.random();
      const bx=boss.x+boss.w/2, by=boss.y+boss.h;
      if(roll<0.5){
        // 通常弾2発
        boss.bullets.push({x:bx-20,y:by,w:14,h:14,vx:-1,vy:4,active:true,big:false});
        boss.bullets.push({x:bx+6, y:by,w:14,h:14,vx:1, vy:4,active:true,big:false});
      } else if(roll<0.75){
        // でかい炎弾
        boss.bullets.push({x:bx-20,y:by,w:40,h:40,vx:0,vy:3,active:true,big:true});
      } else {
        // 扇形5発
        [-2,-1,0,1,2].forEach(i=>{
          boss.bullets.push({x:bx-7,y:by,w:12,h:12,vx:i*1.8,vy:3.5,active:true,big:false});
        });
      }
    }

    boss.bullets.forEach(b=>{ b.x+=b.vx*dt; b.y+=b.vy*dt; });

    // ボス弾 vs 岩壁（弾は岩壁を通過する）
    // ボス弾 vs プレイヤー
    for(let i=boss.bullets.length-1;i>=0;i--){
      const b=boss.bullets[i]; if(!b.active)continue;
      if(rectsOverlap(b,ship)){
        boss.bullets.splice(i,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF4444");
        const mult=getElementMultiplier("fire",s4PlayerElement);
        const dmg=Math.floor(s4BossATK*(b.big?2.5:1)*mult);
        shootingPlayerHP-=dmg; updateShootHUD();
        if(shootingPlayerHP<=0){ handlePlayerDeath(); return; }
      }
    }
    boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+50&&b.x>-50&&b.x<W+50);

    // 自弾 vs ボス
    const bossRect={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      if(rectsOverlap(b,bossRect)){
        spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
        b.active=false;
        const mult=getElementMultiplier(s4PlayerElement,"fire");
        boss.hp-=Math.floor(shootingPlayerATK*mult);
        updateBossHUD();
        if(boss.hp<=0){ clearStage4(); return; }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
  }
}

// =============================================
//  岩壁生成
// =============================================
function spawnS4Wall(W, H){
  const roll=Math.random();
  if(roll<0.4){
    // 横断壁（左から右）：画面を部分的に遮断
    const wallH=18+Math.random()*14;
    const gapSize=90+Math.random()*60; // 通り抜けられる隙間
    const gapY=H*0.3+Math.random()*H*0.4;
    // 隙間の上の壁
    if(gapY>40){
      s4Walls.push({x:-W,y:gapY-wallH-gapSize,w:W,h:wallH,vx:2.5+Math.random()*1,vy:0,dir:"left",id:Date.now()+"a"});
    }
    // 隙間の下の壁
    if(gapY+wallH+gapSize<H-40){
      s4Walls.push({x:-W,y:gapY+gapSize,w:W,h:wallH,vx:2.5+Math.random()*1,vy:0,dir:"left",id:Date.now()+"b"});
    }
  } else if(roll<0.7){
    // 横断壁（右から左）
    const wallH=18+Math.random()*14;
    const gapSize=90+Math.random()*60;
    const gapY=H*0.3+Math.random()*H*0.4;
    if(gapY>40){
      s4Walls.push({x:W,y:gapY-wallH-gapSize,w:W,h:wallH,vx:-(2.5+Math.random()*1),vy:0,dir:"right",id:Date.now()+"c"});
    }
    if(gapY+wallH+gapSize<H-40){
      s4Walls.push({x:W,y:gapY+gapSize,w:W,h:wallH,vx:-(2.5+Math.random()*1),vy:0,dir:"right",id:Date.now()+"d"});
    }
  } else {
    // 縦断壁（上から下）：横に隙間あり
    const wallW=18+Math.random()*14;
    const gapSize=80+Math.random()*50;
    const gapX=W*0.2+Math.random()*W*0.6;
    if(gapX>30){
      s4Walls.push({x:0,y:-60,w:gapX-gapSize/2,h:16,vx:0,vy:2+Math.random()*1.5,dir:"down",id:Date.now()+"e"});
    }
    if(gapX+gapSize/2<W-30){
      s4Walls.push({x:gapX+gapSize/2,y:-60,w:W-(gapX+gapSize/2),h:16,vx:0,vy:2+Math.random()*1.5,dir:"down",id:Date.now()+"f"});
    }
  }
}

// =============================================
//  STAGE 4 QUIZ
// =============================================
function triggerS4Quiz(){
  if(s4QuizActive)return;
  s4QuizActive=true;
  const card=target1900Cards[Math.floor(Math.random()*target1900Cards.length)];
  const q=card.quizzes[Math.floor(Math.random()*card.quizzes.length)];
  s4QuizAnswer=q.correct;
  s4QuizWord=card.word;
  const wrongs=q.choices.sort(()=>Math.random()-0.5).slice(0,3);
  const allChoices=[...wrongs,q.correct].sort(()=>Math.random()-0.5);

  const W=shootCanvas.width, H=shootCanvas.height;
  const zoneTop=H*0.55, zoneH=(H-zoneTop-20)/2, zoneW=W/2-8;
  s4QuizZones=[
    {label:allChoices[0],x:4,     y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[1],x:W/2+4, y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[2],x:4,     y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
    {label:allChoices[3],x:W/2+4, y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
  ];
  s4QuizTimer=5;
  if(s4QuizCountdown) clearInterval(s4QuizCountdown);
  s4QuizCountdown=setInterval(()=>{
    s4QuizTimer--;
    if(s4QuizTimer<=0){ clearInterval(s4QuizCountdown); s4QuizCountdown=null; judgeS4Quiz(); }
  },1000);
}

function judgeS4Quiz(){
  s4QuizActive=false;
  const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
  let chosen=null;
  for(const z of s4QuizZones){ if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){ chosen=z.label; break; } }
  s4QuizZones=[];
  if(chosen===s4QuizAnswer){  // ← 各ステージの変数名に合わせる
    diamonds+=3; saveGame();
    showQuizResult(true,"");
  } else {
    shootingPlayerHP-=600; updateShootHUD();
    showQuizResult(false, s4QuizAnswer); // ← 各ステージの変数名に合わせる
    const wrongCard=target1900Cards.find(c=>c.word===s4QuizWord);
    if(wrongCard) recordWrongWord("target1900", wrongCard.word, wrongCard.meaning);
    if(shootingPlayerHP<=0) handlePlayerDeath();
  }
}

// =============================================
//  DRAW STAGE 4
// =============================================
function draw_stage4(){
  const ctx=shootCtx, W=shootCanvas.width, H=shootCanvas.height;
  // 赤みがかった宇宙背景
  ctx.fillStyle="#120005"; ctx.fillRect(0,0,W,H);

  // 星（赤みがかった）
  for(let i=0;i<70;i++){
    const bri=0.3+((i*73)%100)/100*0.4;
    ctx.fillStyle=`rgba(255,${150+((i*37)%80)},${100+((i*53)%80)},${bri})`;
    ctx.fillRect((i*137+50)%W,(i*97+30)%H,1.5,1.5);
  }
  // 遠くの赤い霧
  const nebula=ctx.createRadialGradient(W*0.5,H*0.3,0,W*0.5,H*0.3,W*0.6);
  nebula.addColorStop(0,"rgba(180,20,0,0.08)");
  nebula.addColorStop(1,"rgba(0,0,0,0)");
  ctx.fillStyle=nebula; ctx.fillRect(0,0,W,H);

  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // ===== 岩壁描画 =====
  s4Walls.forEach(w=>{
    ctx.save();
    // 岩壁グラデーション
    const wg=ctx.createLinearGradient(w.x,w.y,w.x,w.y+w.h);
    wg.addColorStop(0,"#8B3A1A");
    wg.addColorStop(0.5,"#C8603A");
    wg.addColorStop(1,"#6B2A10");
    ctx.fillStyle=wg;
    ctx.shadowColor="rgba(200,80,50,0.6)"; ctx.shadowBlur=8;
    ctx.fillRect(w.x,w.y,w.w,w.h);
    // 岩の模様
    ctx.fillStyle="rgba(0,0,0,0.2)";
    for(let i=0;i<Math.floor(w.w/30);i++){
      ctx.fillRect(w.x+i*30+10,w.y+3,8,w.h-6);
    }
    // ハイライト
    ctx.fillStyle="rgba(255,150,100,0.3)";
    ctx.fillRect(w.x,w.y,w.w,3);
    ctx.restore();
  });

  // ===== クイズゾーン =====
  if(s4QuizActive&&s4QuizZones.length>0){
    ctx.save();
    ctx.fillStyle="rgba(0,0,0,0.82)";
    ctx.beginPath(); ctx.roundRect(W*0.03,H*0.47,W*0.94,46,8); ctx.fill();
    ctx.fillStyle="#FF9500"; ctx.font=`bold ${Math.floor(W*0.034)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText(`「${s4QuizWord}」の意味は？`,W/2,H*0.47+16);
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.font=`${Math.floor(W*0.028)}px sans-serif`;
    ctx.fillText(`⏱ ${s4QuizTimer}秒 いるゾーンが回答！`,W/2,H*0.47+34);
    ctx.restore();

    const zoneColors=["rgba(255,68,68,0.3)","rgba(255,149,0,0.3)","rgba(107,203,119,0.3)","rgba(255,217,61,0.3)"];
    const zoneBorders=["#FF4444","#FF9500","#6BCB77","#FFD93D"];
    s4QuizZones.forEach((z,i)=>{
      ctx.save();
      ctx.fillStyle=zoneColors[i%4]; ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=2;
      ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.fill(); ctx.stroke();
      ctx.fillStyle="#fff"; ctx.textAlign="center"; ctx.textBaseline="middle";
      const fs=Math.floor(W*0.026); ctx.font=`bold ${fs}px sans-serif`;
      const lines=wrapText(ctx,z.label,z.w-14,fs);
      const lh=fs+3, sy=z.y+z.h/2-(lines.length-1)*lh/2;
      lines.forEach((l,li)=>ctx.fillText(l,z.x+z.w/2,sy+li*lh));
      const cx2=ship.x+ship.w/2, cy2=ship.y+ship.h/2;
      if(cx2>=z.x&&cx2<=z.x+z.w&&cy2>=z.y&&cy2<=z.y+z.h){
        ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=4;
        ctx.shadowColor=zoneBorders[i%4]; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.stroke();
      }
      ctx.restore();
    });
  }

  // 隕石
  meteors.forEach(m=>{
    ctx.save();
    ctx.fillStyle="#8B3010"; ctx.shadowColor="rgba(200,80,50,0.5)"; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    ctx.fillStyle="#6B2010"; ctx.shadowBlur=0;
    ctx.beginPath(); ctx.ellipse(m.x+m.w*0.35,m.y+m.h*0.35,m.w*0.15,m.h*0.12,0.5,0,Math.PI*2); ctx.fill();
    if(m.hp===1){ ctx.strokeStyle="rgba(255,107,107,0.8)"; ctx.lineWidth=1.5; ctx.beginPath(); ctx.moveTo(m.x+m.w*0.4,m.y+m.h*0.2); ctx.lineTo(m.x+m.w*0.55,m.y+m.h*0.5); ctx.lineTo(m.x+m.w*0.45,m.y+m.h*0.8); ctx.stroke(); }
    ctx.restore();
  });

  // 自弾（赤い炎色）
  shipBullets.forEach(b=>{
    if(!b.active)return;
    ctx.save();
    const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+b.h);
    g.addColorStop(0,"#fff"); g.addColorStop(1,"#FF4444");
    ctx.fillStyle=g; ctx.shadowColor="#FF4444"; ctx.shadowBlur=10;
    ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h,4); ctx.fill();
    ctx.restore();
  });

  // ボスフェーズ
  if(shootingPhase==="boss"){
    // ボス弾
    boss.bullets.forEach(b=>{
      ctx.save();
      if(b.big){
        const fg=ctx.createRadialGradient(b.x+b.w/2,b.y+b.h/2,2,b.x+b.w/2,b.y+b.h/2,b.w/2);
        fg.addColorStop(0,"#fff"); fg.addColorStop(0.4,"#FF6B00"); fg.addColorStop(1,"rgba(200,50,0,0.3)");
        ctx.fillStyle=fg; ctx.shadowColor="#FF6B00"; ctx.shadowBlur=20;
      } else {
        ctx.fillStyle="#FF4444"; ctx.shadowColor="#FF4444"; ctx.shadowBlur=12;
      }
      ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
      ctx.restore();
    });

    // 火星ボス描画
    const bossHPRatio=Math.max(0,boss.hp/s4BossMaxHP);
    ctx.save();
    ctx.shadowColor=`rgba(255,80,0,0.9)`; ctx.shadowBlur=25+(1-bossHPRatio)*35;
    // 本体グラデーション
    const pg=ctx.createRadialGradient(
      boss.x+boss.w*0.35,boss.y+boss.h*0.3,boss.w*0.05,
      boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2
    );
    pg.addColorStop(0,"#FF8060"); pg.addColorStop(0.4,"#CC3010"); pg.addColorStop(0.8,"#8B1A05"); pg.addColorStop(1,"#5A0A00");
    ctx.fillStyle=pg;
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.fill();
    // 表面模様（砂嵐みたいな縞）
    ctx.save();
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.clip();
    ctx.fillStyle="rgba(200,80,30,0.35)";
    for(let i=0;i<5;i++){
      const wy=boss.y+boss.h*0.15+i*(boss.h*0.15);
      const ww=boss.w*(0.6+Math.sin(i*1.3)*0.3);
      const wx=boss.x+(boss.w-ww)/2+Math.sin(i*2)*10;
      ctx.beginPath(); ctx.ellipse(wx+ww/2,wy,ww/2,boss.h*0.04,0,0,Math.PI*2); ctx.fill();
    }
    ctx.restore();
    // クレーター
    ctx.fillStyle="rgba(80,10,0,0.5)"; ctx.shadowBlur=0;
    [[0.35,0.35,0.1],[0.65,0.55,0.08],[0.45,0.7,0.07],[0.25,0.6,0.05]].forEach(([rx,ry,rs])=>{
      ctx.beginPath(); ctx.arc(boss.x+boss.w*rx,boss.y+boss.h*ry,boss.w*rs,0,Math.PI*2); ctx.fill();
    });
    // HP低下でひび
    if(bossHPRatio<0.5){
      ctx.strokeStyle=`rgba(255,150,50,${0.5+(1-bossHPRatio)*0.5})`; ctx.lineWidth=2.5;
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.3,boss.y+boss.h*0.1); ctx.lineTo(boss.x+boss.w*0.5,boss.y+boss.h*0.5); ctx.lineTo(boss.x+boss.w*0.75,boss.y+boss.h*0.85); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.6,boss.y+boss.h*0.15); ctx.lineTo(boss.x+boss.w*0.42,boss.y+boss.h*0.58); ctx.stroke();
    }
    ctx.restore();
  }

  // エフェクト
  hitEffects.forEach(e=>{
    if(e.alpha<=0)return;
    ctx.save(); ctx.globalAlpha=e.alpha;
    if(e.type==="debris"){ ctx.fillStyle=e.color; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill(); }
    else if(e.type==="heal"){ ctx.strokeStyle=e.color; ctx.lineWidth=3; ctx.shadowColor=e.color; ctx.shadowBlur=12; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.font=`bold ${Math.max(8,Math.floor(e.r*0.8))}px sans-serif`; ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.fillText("+",e.x,e.y-Math.max(0,e.r)*1.2); }
    else { ctx.strokeStyle=e.color; ctx.lineWidth=2.5; ctx.shadowColor=e.color; ctx.shadowBlur=14; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.globalAlpha=e.alpha*0.3; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r*0.5),0,Math.PI*2); ctx.fill(); }
    ctx.restore();
  });

  // 宇宙船
  drawSpaceShip(ctx,ship.x,ship.y,ship.w,ship.h);
  if(dodgeActive){
    ctx.save();
    const pulse=Math.sin(Date.now()*0.02)*0.3+0.7;
    ctx.strokeStyle=`rgba(255,255,255,${pulse})`;
    ctx.lineWidth=3;
    ctx.shadowColor="#fff";
    ctx.shadowBlur=20;
    ctx.beginPath();
    ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();
  }
  // 小型機描画
  if(ship.subShips && ship.subShips.length>0){
    ship.subShips.forEach(ss=>{
      const sx=ship.x+ship.w/2+ss.offset-12;
      const sy=ship.y+8;
      drawRVSubShip(ctx,sx,sy,"#4D96FF");
    });
  }

  // HPバー
  const hpRatio=Math.max(0,shootingPlayerHP/shootingPlayerMaxHP);
  const barW=W*0.5,barX=(W-barW)/2,barY=H-14;
  ctx.save();
  ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(barX,barY,barW,8,4); ctx.fill();
  const hpColor=hpRatio>0.5?"#6BCB77":hpRatio>0.25?"#FFD93D":"#FF6B6B";
  ctx.fillStyle=hpColor; ctx.shadowColor=hpColor; ctx.shadowBlur=6;
  ctx.beginPath(); ctx.roundRect(barX,barY,barW*hpRatio,8,4); ctx.fill();
  ctx.restore();

  // 属性バッジ
  drawElementBadge(ctx,W,s4PlayerElement);
}

// =============================================
//  STAGE 4 CLEAR / GAMEOVER
// =============================================
function clearStage4(){
  unlockShootingUI(); // ← 追加
  shootingPhase="clear"; shootingGameActive=false;
  clearInterval(shootingTimerInterval);
  if(s4QuizCountdown) clearInterval(s4QuizCountdown);
  cancelAnimationFrame(shootingAnimFrame);
  removeShootListeners();
  const firstClear=!isStage4Cleared();
  if(firstClear){ markStage4Cleared(); diamonds+=15; saveGame(); }
  draw_stage4();
  setTimeout(()=>{
    document.getElementById("spaceArea").innerHTML=`
      <div style="text-align:center;padding:30px 16px">
        <div style="font-size:4rem;margin-bottom:10px">🏆</div>
        <div style="font-family:'Fredoka One',cursive;font-size:2rem;
          background:linear-gradient(90deg,#FF4444,#FF9500);
          -webkit-background-clip:text;-webkit-text-fill-color:transparent;
          margin-bottom:8px">STAGE 4 CLEAR!</div>
        ${firstClear
          ?`<div style="font-family:'Fredoka One',cursive;font-size:1.3rem;color:#FFD93D;margin-bottom:6px">💎×15 獲得！</div>`
          :`<div style="font-size:13px;color:rgba(255,255,255,0.4);margin-bottom:6px">※2回目以降クリア報酬なし</div>`}
        <div style="font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:20px">
          🔴 火星を撃破した！<br>
          <span style="font-size:12px;color:rgba(255,255,255,0.4)">
            ※クイズ正解で💎×3（回数無制限）
          </span>
        </div>
        <button onclick="showStage4DeckSelect()"
          style="background:linear-gradient(135deg,#FF4444,#FF9500);
            font-size:1rem;padding:14px 28px;margin:6px">
          🔄 もう一度
        </button>
        <br>
        <button onclick="showNormalStageMenu()"
          style="background:rgba(255,255,255,0.08);box-shadow:none;
            font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">
          ← ステージ選択へ
        </button>
      </div>`;
    spawnStars();
  },500);
}

// =============================================
//  SHOOTING UI LOCK / UNLOCK
// =============================================
function lockShootingUI(){
  const h1 = document.querySelector("h1");
  if(h1) h1.style.display = "none";
  const topRes = document.getElementById("topResource");
  if(topRes) topRes.style.display = "none";
  const modeBar = document.querySelector(".modeTabBar");
  if(modeBar) modeBar.style.display = "none";
}

function unlockShootingUI(){
  const h1 = document.querySelector("h1");
  if(h1) h1.style.display = "";
  const topRes = document.getElementById("topResource");
  if(topRes) topRes.style.display = "";
  const modeBar = document.querySelector(".modeTabBar");
  if(modeBar) modeBar.style.display = "";
}

// =============================================
//  SHOOTING PAUSE
// =============================================
let shootingPaused = false;
let currentShootingStage = "stage1";

function toggleShootingPause(){
  shootingPaused = !shootingPaused;
  const modal = document.getElementById("shootPauseModal");
  if(shootingPaused){
    // タイマーとアニメーション両方止める
    shootingGameActive = false;
    clearInterval(shootingTimerInterval);
    cancelAnimationFrame(shootingAnimFrame);
    if(s2QuizCountdown){ clearInterval(s2QuizCountdown); }
    if(s3QuizCountdown){ clearInterval(s3QuizCountdown); }
    if(s4QuizCountdown){ clearInterval(s4QuizCountdown); }
    if(modal) modal.style.display = "flex";
  } else {
    if(modal) modal.style.display = "none";
    lastFrameTime = performance.now(); // ← 現在時刻を入れる
    shootingGameActive = true;         // ← trueにしてからループ開始
    
    // タイマー再開（以下同じ）

    // タイマー再開
    shootingTimerInterval = setInterval(()=>{
      if(shootingPhase !== "survival") return;
      shootingTime--;
      updateShootHUD();

      // 各ステージのクイズトリガー
      if(currentShootingStage === "stage2"){
        if(shootingTime===40 && !s2QuizShown20){ s2QuizShown20=true; triggerS2Quiz(); }
        if(shootingTime===20 && !s2QuizShown40){ s2QuizShown40=true; triggerS2Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS2BossPhase(); }
      } else if(currentShootingStage === "stage3"){
        if(shootingTime===45 && !s3QuizShown15){ s3QuizShown15=true; triggerS3Quiz(); }
        if(shootingTime===30 && !s3QuizShown30){ s3QuizShown30=true; triggerS3Quiz(); }
        if(shootingTime===15 && !s3QuizShown45){ s3QuizShown45=true; triggerS3Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS3BossPhase(); }
      } else if(currentShootingStage === "stage4"){
        if(shootingTime===45 && !s4QuizShown15){ s4QuizShown15=true; triggerS4Quiz(); }
        if(shootingTime===30 && !s4QuizShown30){ s4QuizShown30=true; triggerS4Quiz(); }
        if(shootingTime===15 && !s4QuizShown45){ s4QuizShown45=true; triggerS4Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS4BossPhase(); }
      } else if(currentShootingStage === "stage5"){
        if(shootingTime===45 && !s5QuizShown15){ s5QuizShown15=true; triggerS5Quiz(); }
        if(shootingTime===30 && !s5QuizShown30){ s5QuizShown30=true; triggerS5Quiz(); }
        if(shootingTime===15 && !s5QuizShown45){ s5QuizShown45=true; triggerS5Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS5BossPhase(); }  
        } else if(currentShootingStage === "stage6"){
        if(shootingTime===45 && !s6QuizShown15){ s6QuizShown15=true; triggerS6Quiz(); }
        if(shootingTime===30 && !s6QuizShown30){ s6QuizShown30=true; triggerS6Quiz(); }
        if(shootingTime===15 && !s6QuizShown45){ s6QuizShown45=true; triggerS6Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS6BossPhase(); }
        } else if(currentShootingStage === "stage7"){
        if(shootingTime===45 && !s7QuizShown15){ s7QuizShown15=true; triggerS7Quiz(); }
        if(shootingTime===30 && !s7QuizShown30){ s7QuizShown30=true; triggerS7Quiz(); }
        if(shootingTime===15 && !s7QuizShown45){ s7QuizShown45=true; triggerS7Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS7BossPhase(); }
        } else if(currentShootingStage === "stage8"){
        if(shootingTime===45 && !s8QuizShown15){ s8QuizShown15=true; triggerS8Quiz(); }
        if(shootingTime===30 && !s8QuizShown30){ s8QuizShown30=true; triggerS8Quiz(); }
        if(shootingTime===15 && !s8QuizShown45){ s8QuizShown45=true; triggerS8Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS8BossPhase(); }
        } else if(currentShootingStage === "stage9"){
        if(shootingTime===45 && !s9QuizShown15){ s9QuizShown15=true; triggerS9Quiz(); }
        if(shootingTime===30 && !s9QuizShown30){ s9QuizShown30=true; triggerS9Quiz(); }
        if(shootingTime===15 && !s9QuizShown45){ s9QuizShown45=true; triggerS9Quiz(); }
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS9BossPhase(); }
        } else if(currentShootingStage === "stage10"){
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS10BossPhase(); }
        } else if(currentShootingStage === "stage11"){
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS11BossPhase(); }
        } else if(currentShootingStage === "stage12"){
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS12BossPhase(); }
        } else if(currentShootingStage === "stage13"){
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS13BossPhase(); }
        } else if(currentShootingStage === "stage14"){
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS14BossPhase(); }
        } else if(currentShootingStage === "stage15"){
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS15BossPhase(); }







      } else {
        // stage1
        if(shootingTime<=0){ clearInterval(shootingTimerInterval); startBossPhase(); }
      }
    }, 1000);
    

    // ループ再開
    const loopMap = {
      stage1: shootingLoop,
      stage2: stage2Loop,
      stage3: stage3Loop,
      stage4: stage4Loop,
      stage5: stage5Loop,
      stage6: stage6Loop,
      stage7: stage7Loop,
      stage8: stage8Loop,
      stage9: stage9Loop,
      stage10: stage10Loop,
      stage11: stage11Loop,
      stage12: stage12Loop,
      stage13: stage13Loop,
      stage14: stage14Loop,
      stage15: stage15Loop,

    };
    requestAnimationFrame(loopMap[currentShootingStage] || shootingLoop);
  }
}

function giveUpShooting(){
  removeDodgeButton();
  shootingGameActive = false;
  shootingPaused = false;
  clearInterval(shootingTimerInterval);
  if(s2QuizCountdown){ clearInterval(s2QuizCountdown); s2QuizCountdown=null; }
  if(s3QuizCountdown){ clearInterval(s3QuizCountdown); s3QuizCountdown=null; }
  if(s4QuizCountdown){ clearInterval(s4QuizCountdown); s4QuizCountdown=null; }
  if(s5QuizCountdown){ clearInterval(s5QuizCountdown); s5QuizCountdown=null; }
  if(s6QuizCountdown){ clearInterval(s6QuizCountdown); s6QuizCountdown=null; }
  if(s7QuizCountdown){ clearInterval(s7QuizCountdown); s7QuizCountdown=null; }
  if(s8QuizCountdown){ clearInterval(s8QuizCountdown); s8QuizCountdown=null; }
  if(s9QuizCountdown){ clearInterval(s9QuizCountdown); s9QuizCountdown=null; }
  if(s10QuizCountdown){ clearInterval(s10QuizCountdown); s10QuizCountdown=null; }
  if(s11QuizCountdown){ clearInterval(s11QuizCountdown); s11QuizCountdown=null; }
  if(s12QuizCountdown){ clearInterval(s12QuizCountdown); s12QuizCountdown=null; }
  if(s13QuizCountdown){ clearInterval(s13QuizCountdown); s13QuizCountdown=null; }
  if(s14QuizCountdown){ clearInterval(s14QuizCountdown); s14QuizCountdown=null; }
  if(s15QuizCountdown){ clearInterval(s15QuizCountdown); s15QuizCountdown=null; }
removeS15UltiButton();
  cancelAnimationFrame(shootingAnimFrame);
  removeShootListeners();
  unlockShootingUI();
  const modal = document.getElementById("shootPauseModal");
  if(modal) modal.style.display = "none";
  showNormalStageMenu();
}

// =============================================
//  STAGE 5
// =============================================
let s5PlayerElement  = "fire";
let s5BossElement    = "wood";
let s5BossMaxHP      = 16000;
let s5BossATK        = 500;
let s5QuizActive     = false;
let s5QuizAnswer     = "";
let s5QuizZones      = [];
let s5QuizTimer      = 0;
let s5QuizWord       = "";
let s5QuizCountdown  = null;
let s5QuizShown15    = false;
let s5QuizShown30    = false;
let s5QuizShown45    = false;
let s5BossQuizTimer  = 0;
let s5BossPhase      = false;
let s5Vortexes       = []; // 渦巻き重力場
let s5VortexTimer    = 0;

function showStage5DeckSelect(){
  const pool = owned.filter(c=>c.type==="target1900");
  const grouped = {};
  pool.forEach(c=>{ if(!grouped[c.word]) grouped[c.word]=c; });
  const cards = Object.values(grouped);

  const area = document.getElementById("spaceArea");
  area.innerHTML = `
    <div style="text-align:center;padding:12px">
      <div style="font-family:'Fredoka One',cursive;font-size:1.1rem;
        color:#C8A96E;margin-bottom:8px">🟤 ステージ５ デッキ選択</div>
      <div style="background:rgba(200,169,110,0.1);border:1px solid rgba(200,169,110,0.3);
        border-radius:12px;padding:10px;margin:0 auto 12px;max-width:320px;
        font-size:12px;color:rgba(255,255,255,0.7);text-align:left;line-height:1.8">
        🌀 <b>ステージ5 特殊ギミック</b><br>
        渦巻き重力場が出現！船が引き寄せられる！<br>
        🌿 ボス属性：<b style="color:#52D68A">木属性</b>（火属性が有利！）<br>
        謎の惑星が待ち受ける…<br>
        クイズ正解で💎×3獲得！
      </div>
      <div style="font-size:13px;color:#C8A96E;margin-bottom:8px">
        選択: <span id="s5SelectedCount">0</span> / 2
      </div>
      <div id="s5CardPicker"
        style="display:flex;flex-wrap:wrap;justify-content:center;
          gap:8px;margin-bottom:16px"></div>
      <div id="s5SelectedDisplay"
        style="display:flex;justify-content:center;gap:12px;
          margin-bottom:80px;min-height:60px"></div>
      <div style="position:fixed;bottom:70px;right:16px;z-index:1000">
        <button id="s5StartBtn" disabled
          style="background:linear-gradient(135deg,#C8A96E,#8B6914);
            font-size:1rem;padding:14px 20px;border-radius:20px;
            opacity:0.4;cursor:not-allowed;
            box-shadow:0 4px 20px rgba(0,0,0,0.4)">
          🚀 スタート！
        </button>
      </div>
      <br>
      <button onclick="showNormalStageMenu()"
        style="background:rgba(255,255,255,0.08);box-shadow:none;
          font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">← 戻る</button>
    </div>`;

  if(cards.length===0){
    document.getElementById("s5CardPicker").innerHTML=
      `<div style="color:rgba(255,255,255,0.4);font-size:13px;padding:20px">
        ターゲット1900カードがありません！
      </div>`;
    return;
  }

  let selected=[];

  function renderPicker(){
    document.getElementById("s5SelectedCount").textContent=selected.length;
    document.getElementById("s5CardPicker").innerHTML=cards.map(c=>{
      const idx=selected.findIndex(s=>s.word===c.word);
      const isSel=idx!==-1;
      return `
        <div onclick="s5ToggleCard('${c.word}')"
          style="cursor:pointer;width:95px;padding:10px 6px;border-radius:14px;
            background:${isSel?"rgba(255,217,61,0.2)":"rgba(255,255,255,0.06)"};
            border:2px solid ${isSel?c.elementColor:"rgba(255,255,255,0.15)"};
            text-align:center;transition:all 0.15s;position:relative">
          ${isSel?`<div style="position:absolute;top:-6px;right:-6px;
            background:#FFD93D;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#1a1a2e;font-weight:700">${idx+1}</div>`:""}
          <div style="font-size:1rem">${c.elementLabel.split(" ")[0]}</div>
          <div style="font-family:'Fredoka One',cursive;font-size:0.8rem;color:#fff">
            ${c.word}
          </div>
          <div style="font-size:10px;color:rgba(255,255,255,0.5)">${c.meaning}</div>
          <div style="font-size:10px;color:${c.elementColor}">
            ⚔️${c.atk} ❤️${c.hp}
          </div>
        </div>`;
    }).join("");

    document.getElementById("s5SelectedDisplay").innerHTML=[0,1].map(i=>{
      const c=selected[i];
      return c
        ?`<div style="background:rgba(255,255,255,0.08);
            border:1px solid ${c.elementColor};border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px">
            <div style="font-size:10px;color:rgba(255,255,255,0.4)">
              ${i===0?"1枚目（メイン）":"2枚目（予備）"}
            </div>
            <div style="font-family:'Fredoka One',cursive;font-size:0.85rem;color:#fff">
              ${c.word}
            </div>
            <div style="font-size:10px;color:${c.elementColor}">
              ⚔️${c.atk} ❤️${c.hp}
            </div>
          </div>`
        :`<div style="background:rgba(255,255,255,0.03);
            border:1px dashed rgba(255,255,255,0.15);border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px;
            color:rgba(255,255,255,0.25);font-size:12px">
            ${i===0?"1枚目":"2枚目"}<br>未選択
          </div>`;
    }).join("");

    const btn=document.getElementById("s5StartBtn");
    btn.disabled=selected.length!==2;
    btn.style.opacity=selected.length===2?"1":"0.4";
    btn.style.cursor=selected.length===2?"pointer":"not-allowed";
  }

  window.s5ToggleCard=function(word){
    const c=cards.find(x=>x.word===word);
    const idx=selected.findIndex(s=>s.word===word);
    if(idx!==-1){ selected.splice(idx,1); }
    else { if(selected.length>=2)return; selected.push(c); }
    renderPicker();
  };

  document.getElementById("s5StartBtn").onclick=()=>{
    if(selected.length<2)return;
    shootingDeck=selected;
    beginStage5();
  };
  renderPicker();
}

// =============================================
//  BEGIN STAGE 5
// =============================================
function beginStage5(){
  const area=document.getElementById("spaceArea");
  area.innerHTML=`
    <div style="position:relative;width:100%;max-width:420px;margin:0 auto">
      <canvas id="shootCanvas"
        style="display:block;width:100%;border-radius:16px;
          background:#0a0a00;touch-action:none"></canvas>
          <div id="shootQuizResult"
  style="position:absolute;bottom:30px;left:50%;transform:translateX(-50%);
    font-family:'Fredoka One',cursive;font-size:1rem;
    background:rgba(0,0,0,0.7);border-radius:12px;padding:6px 16px;
    pointer-events:none;display:none;text-align:center;
    white-space:pre-line;z-index:100;min-width:200px">
</div>
      <button onclick="toggleShootingPause()"
        style="position:absolute;top:8px;right:8px;
          background:rgba(0,0,0,0.5);border:1px solid rgba(255,255,255,0.3);
          color:#fff;font-size:12px;padding:5px 10px;border-radius:8px;
          z-index:2100;cursor:pointer">⏸ ポーズ</button>
      <div id="shootHUD"
        style="position:absolute;top:8px;left:8px;right:8px;
          display:flex;justify-content:space-between;pointer-events:none">
        <div id="shootHP"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#6BCB77;text-shadow:0 0 8px rgba(107,203,119,0.8)">❤️ 0</div>
        <div id="shootTimer"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#FFD93D;text-shadow:0 0 8px rgba(255,217,61,0.8)">⏱ 60</div>
        <div id="shootCard"
          style="font-family:'Fredoka One',cursive;font-size:11px;color:#C8A96E">
          🚀 1枚目
        </div>
      </div>
      <div id="shootBossHUD"
        style="position:absolute;top:36px;left:8px;right:8px;
          display:none;pointer-events:none">
        <div style="font-family:'Fredoka One',cursive;font-size:11px;
          color:#C8A96E;text-align:center;margin-bottom:2px">🟤 木星</div>
        <div style="background:rgba(0,0,0,0.4);border-radius:8px;
          height:10px;overflow:hidden">
          <div id="shootBossHPBar"
            style="height:100%;
              background:linear-gradient(90deg,#C8A96E,#8B6914);
              border-radius:8px;transition:width 0.3s;width:100%"></div>
        </div>
      </div>
      <div id="shootMessage"
        style="position:absolute;top:45%;left:50%;
          transform:translate(-50%,-50%);
          font-family:'Fredoka One',cursive;font-size:1.2rem;color:#fff;
          text-align:center;pointer-events:none;
          text-shadow:0 0 20px rgba(255,255,255,0.8);display:none;
          background:rgba(0,0,0,0.6);border-radius:12px;
          padding:8px 16px;white-space:pre-line"></div>
    </div>`;

  shootCanvas=document.getElementById("shootCanvas");
  const maxW=Math.min(420,window.innerWidth-32);
  shootCanvas.width=maxW;
  shootCanvas.height=Math.floor(maxW*1.5);
  shootCtx=shootCanvas.getContext("2d");

  // 状態リセット
  if(shootingTimerInterval){ clearInterval(shootingTimerInterval); shootingTimerInterval=null; }
  if(shootingAnimFrame){ cancelAnimationFrame(shootingAnimFrame); shootingAnimFrame=null; }

  shootingCurrentCard=0; shootingPhase="survival"; shootingTime=60;
  shipBullets=[]; meteors=[]; hitEffects=[]; s5Vortexes=[];
  bulletTimer=0; meteorTimer=0; bossTimer=0; s5VortexTimer=0;
  boss.bullets=[]; boss.hp=s5BossMaxHP;
  shootingBossActive=false; lastFrameTime=0;

  s5QuizActive=false; s5QuizShown15=false; s5QuizShown30=false; s5QuizShown45=false;
  s5BossPhase=false; s5BossQuizTimer=0; s5QuizZones=[];
  if(s5QuizCountdown){ clearInterval(s5QuizCountdown); s5QuizCountdown=null; }

  const c=shootingDeck[0];
  shootingPlayerMaxHP=c.hp; shootingPlayerHP=c.hp; shootingPlayerATK=c.atk;
  s5PlayerElement=c.element;

  ship.x=shootCanvas.width/2-ship.w/2;
  ship.y=shootCanvas.height-ship.h-20;

  shootCanvas.addEventListener("touchstart",onShootTouchStart,{passive:false});
  shootCanvas.addEventListener("touchmove", onShootTouchMove, {passive:false});
  shootCanvas.addEventListener("touchend",  onShootTouchEnd,  {passive:false});
  shootCanvas.addEventListener("mousedown", onShootMouseDown);
  shootCanvas.addEventListener("mousemove", onShootMouseMove);
  shootCanvas.addEventListener("mouseup",   onShootMouseUp);

  shootingPaused=false;
  // 小型機チェック
  const subUnlocked = localStorage.getItem("subShipUnlocked")==="true";
  if(subUnlocked){
    ship.subShips = [{offset:-35},{offset:35}];
  } else {
    ship.subShips = [];
  }
  currentShootingStage="stage5";

  shootingTimerInterval=setInterval(()=>{
    if(shootingPhase!=="survival")return;
    shootingTime--;
    updateShootHUD();
    if(shootingTime===45&&!s5QuizShown15){ s5QuizShown15=true; triggerS5Quiz(); }
    if(shootingTime===30&&!s5QuizShown30){ s5QuizShown30=true; triggerS5Quiz(); }
    if(shootingTime===15&&!s5QuizShown45){ s5QuizShown45=true; triggerS5Quiz(); }
    if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS5BossPhase(); }
  },1000);

  shootingGameActive=true;
  lockShootingUI();
  dodgeUnlocked = localStorage.getItem("dodgeUnlocked")==="true";
  dodgeCooldown = 0;
  dodgeActive   = false;
  dodgeActiveTimer = 0;
  renderDodgeButton();
  updateShootHUD();
  requestAnimationFrame(stage5Loop);
}

// =============================================
//  STAGE 5 BOSS
// =============================================
function startS5BossPhase(){
  shootingPhase="boss"; s5BossPhase=true; shootingBossActive=true;
  boss.x=shootCanvas.width/2-boss.w/2; boss.y=60;
  boss.hp=s5BossMaxHP; boss.vx=2.5; boss.bullets=[]; meteors=[];
  s5Vortexes=[]; bossTimer=0; s5BossQuizTimer=0;
  const bossHUD=document.getElementById("shootBossHUD");
  if(bossHUD) bossHUD.style.display="block";
  showShootMessage("🟤 木星 出現！\n重力場に引き寄せられるぞ！",2500);
  updateBossHUD();
}

// =============================================
//  STAGE 5 LOOP
// =============================================
function stage5Loop(timestamp){
  if(!shootingGameActive)return;
  const dt=Math.min((timestamp-(lastFrameTime||timestamp))/16.67,3);
  lastFrameTime=timestamp;
  update_stage5(dt);
  draw_stage5();
  shootingAnimFrame=requestAnimationFrame(stage5Loop);
}

// =============================================
//  UPDATE STAGE 5
// =============================================
function update_stage5(dt){
  const W=shootCanvas.width, H=shootCanvas.height;
  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // エフェクト更新
  hitEffects.forEach(e=>{
    e.life+=dt; e.alpha=Math.max(0,1-e.life/e.maxLife);
    if(e.type==="debris"){ e.x+=(e.vx||0)*dt; e.y+=(e.vy||0)*dt; e.r=Math.max(0,e.r-0.15*dt); }
    else { e.r+=(e.maxR-e.r)*0.18*dt; }
  });
  hitEffects=hitEffects.filter(e=>e.life<e.maxLife);
  // 回避・無敵タイマー更新
  if(dodgeActive){
    dodgeActiveTimer-=dt;
    if(dodgeActiveTimer<=0){
      dodgeActive=false;
      dodgeCooldown=600; // 10秒（600フレーム）
    }
  }
  if(dodgeCooldown>0){
    dodgeCooldown-=dt;
    if(dodgeCooldown<0) dodgeCooldown=0;
    updateDodgeButton();
  }
  if(dodgeActive) updateDodgeButton();

  // 弾発射　←この行の直後（全ステージ共通）
  bulletTimer+=dt;
  if(bulletTimer>=60){
    bulletTimer=0;
    // メイン弾
    shipBullets.push({x:ship.x+ship.w/2-4,y:ship.y-10,w:8,h:14,active:true});
    // 小型機の弾
    if(ship.subShips && ship.subShips.length>0){
      ship.subShips.forEach(ss=>{
        const angle=15*Math.PI/180;
        const dir=ss.offset<0?-1:1;
        shipBullets.push({
          x:ship.x+ship.w/2+ss.offset-4,
          y:ship.y-10,
          w:6, h:10,
          vx:Math.sin(angle)*4*dir,
          vy:-Math.cos(angle)*8,
          active:true,
          isSub:true,
        });
      });
    }
  }
  shipBullets.forEach(b=>{
    b.x+=(b.vx||0)*dt;
    b.y+=(b.vy||-8)*dt;
  });
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

  // ===== 渦巻き重力場更新 =====
  s5VortexTimer+=dt;
  const vortexInterval = shootingPhase==="boss" ? 400 : 600;
  if(s5VortexTimer>=vortexInterval){
    s5VortexTimer=0;
    s5Vortexes.push({
  x: W*0.1 + Math.random()*W*0.8,
  y: H*0.1 + Math.random()*H*0.5,
  r: 80+Math.random()*60,        // ← 40+30 から 80+60 に変更
  strength: 2.0+Math.random()*1.0, // ← 引き寄せる力も少し強く
  life: 0,
  maxLife: 300+Math.random()*200,
  angle: 0,
});
  }

  // 渦巻きの寿命更新
  s5Vortexes.forEach(v=>{
    v.life+=dt;
    v.angle+=0.05*dt;
  });
  s5Vortexes=s5Vortexes.filter(v=>v.life<v.maxLife);

  // 渦巻きが船を引き寄せる
  s5Vortexes.forEach(v=>{
    const dx=v.x-(ship.x+ship.w/2);
    const dy=v.y-(ship.y+ship.h/2);
    const dist=Math.sqrt(dx*dx+dy*dy);
    if(dist<v.r*4 && dist>1){  // ← v.r*2.5 から v.r*4 に変更
  const force = v.strength * (1-dist/(v.r*4)) * 0.8;  // ← こちらも合わせて変更
      ship.x += dx/dist * force * dt;
      ship.y += dy/dist * force * dt;
    }
  });

  // 船の範囲制限
  ship.x=Math.max(0,Math.min(W-ship.w,ship.x));
  ship.y=Math.max(0,Math.min(H-ship.h,ship.y));

  if(shootingPhase==="survival"){
    // 隕石生成
    meteorTimer+=dt;
    if(meteorTimer>=38+Math.random()*18){
      meteorTimer=0;
      const mw=30+Math.random()*20, mh=30+Math.random()*20;
      meteors.push({x:Math.random()*(W-mw),y:-mh,w:mw,h:mh,vy:2.5+Math.random()*2.5,hp:2,id:Date.now()+Math.random()});
    }
    meteors.forEach(m=>{ m.y+=m.vy*dt; });

    // 自弾 vs 隕石
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let mi=meteors.length-1;mi>=0;mi--){
        const m=meteors[mi]; if(m.hp<=0)continue;
        if(rectsOverlap(b,m)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#FFD93D");
          b.active=false; m.hp--;
          if(m.hp<=0){
            spawnMeteorBreakEffect(m.x+m.w/2,m.y+m.h/2);
            const heal=Math.floor(shootingPlayerMaxHP*0.015);
            shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
            spawnHealEffect(ship.x+ship.w/2,ship.y);
            updateShootHUD(); meteors.splice(mi,1);
          }
          break;
        }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
    meteors=meteors.filter(m=>m.hp>0&&m.y<H+50);

    // 隕石 vs プレイヤー
    for(let mi=meteors.length-1;mi>=0;mi--){
      const m=meteors[mi];
      if(rectsOverlap(ship,m)){
        meteors.splice(mi,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        shootingPlayerHP-=350; updateShootHUD();
        if(shootingPlayerHP<=0){ handlePlayerDeath(); return; }
      }
    }

  } else if(shootingPhase==="boss"){
    boss.x+=boss.vx*dt;
    if(boss.x<=0||boss.x+boss.w>=W) boss.vx*=-1;
    const minY=boss.y+boss.h+10;
    if(ship.y<minY) ship.y=minY;

    // ボスクイズ（20秒に1回）
    s5BossQuizTimer+=dt;
    if(s5BossQuizTimer>=1200){ s5BossQuizTimer=0; if(!s5QuizActive) triggerS5Quiz(); }

    // ボス攻撃（3パターン）
    bossTimer+=dt;
    if(bossTimer>=90+Math.random()*70){
      bossTimer=0;
      const roll=Math.random();
      const bx=boss.x+boss.w/2, by=boss.y+boss.h;
      if(roll<0.4){
        // 通常弾3発
        [-1,0,1].forEach(i=>{
          boss.bullets.push({x:bx-7+i*20,y:by,w:14,h:14,vx:i*1.5,vy:4,active:true,big:false});
        });
      } else if(roll<0.7){
        // でかい弾
        boss.bullets.push({x:bx-22,y:by,w:44,h:44,vx:0,vy:2.8,active:true,big:true});
      } else {
        // 追尾弾（プレイヤー方向）
        const dx=(ship.x+ship.w/2)-bx;
        const dy=(ship.y+ship.h/2)-by;
        const dist=Math.sqrt(dx*dx+dy*dy)||1;
        const speed=4.5;
        boss.bullets.push({x:bx-8,y:by,w:16,h:16,vx:dx/dist*speed,vy:dy/dist*speed,active:true,big:false,homing:true});
      }
    }

    boss.bullets.forEach(b=>{ b.x+=b.vx*dt; b.y+=b.vy*dt; });

    // ボス弾 vs プレイヤー
    for(let i=boss.bullets.length-1;i>=0;i--){
      const b=boss.bullets[i]; if(!b.active)continue;
      if(rectsOverlap(b,ship)){
        boss.bullets.splice(i,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#C8A96E");
        const mult=getElementMultiplier(s5BossElement,s5PlayerElement);
        const dmg=Math.floor(s5BossATK*(b.big?2.5:1)*mult);
        shootingPlayerHP-=dmg; updateShootHUD();
        if(shootingPlayerHP<=0){ handlePlayerDeath(); return; }
      }
    }
    boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+50&&b.x>-50&&b.x<W+50);

    // 自弾 vs ボス
    const bossRect={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      if(rectsOverlap(b,bossRect)){
        spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
        b.active=false;
        const mult=getElementMultiplier(s5PlayerElement,s5BossElement);
        boss.hp-=Math.floor(shootingPlayerATK*mult);
        updateBossHUD();
        if(boss.hp<=0){ clearStage5(); return; }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
  }
}

// =============================================
//  STAGE 5 QUIZ
// =============================================
function triggerS5Quiz(){
  if(s5QuizActive)return;
  s5QuizActive=true;
  const card=target1900Cards[Math.floor(Math.random()*target1900Cards.length)];
  const q=card.quizzes[Math.floor(Math.random()*card.quizzes.length)];
  s5QuizAnswer=q.correct;
  s5QuizWord=card.word;
  const wrongs=q.choices.sort(()=>Math.random()-0.5).slice(0,3);
  const allChoices=[...wrongs,q.correct].sort(()=>Math.random()-0.5);

  const W=shootCanvas.width, H=shootCanvas.height;
  const zoneTop=H*0.55, zoneH=(H-zoneTop-20)/2, zoneW=W/2-8;
  s5QuizZones=[
    {label:allChoices[0],x:4,     y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[1],x:W/2+4, y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[2],x:4,     y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
    {label:allChoices[3],x:W/2+4, y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
  ];
  s5QuizTimer=5;
  if(s5QuizCountdown) clearInterval(s5QuizCountdown);
  s5QuizCountdown=setInterval(()=>{
    s5QuizTimer--;
    if(s5QuizTimer<=0){ clearInterval(s5QuizCountdown); s5QuizCountdown=null; judgeS5Quiz(); }
  },1000);
}

function judgeS5Quiz(){
  s5QuizActive=false;
  const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
  let chosen=null;
  for(const z of s5QuizZones){ if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){ chosen=z.label; break; } }
  s5QuizZones=[];
  if(chosen===s5QuizAnswer){  // ← 各ステージの変数名に合わせる
    diamonds+=3; saveGame();
    showQuizResult(true,"");
  } else {
    shootingPlayerHP-=600; updateShootHUD();
    showQuizResult(false, s5QuizAnswer); // ← 各ステージの変数名に合わせる
    const wrongCard=target1900Cards.find(c=>c.word===s5QuizWord);
    if(wrongCard) recordWrongWord("target1900", wrongCard.word, wrongCard.meaning);
    if(shootingPlayerHP<=0) handlePlayerDeath();
  }
}

// =============================================
//  DRAW STAGE 5
// =============================================
function draw_stage5(){
  const ctx=shootCtx, W=shootCanvas.width, H=shootCanvas.height;

  // 木星らしい黄褐色の宇宙背景
  ctx.fillStyle="#0a0800"; ctx.fillRect(0,0,W,H);

  // 星
  for(let i=0;i<70;i++){
    ctx.fillStyle=`rgba(255,${220+((i*37)%35)},${150+((i*53)%80)},${0.3+((i*73)%100)/100*0.4})`;
    ctx.fillRect((i*137+50)%W,(i*97+30)%H,1.5,1.5);
  }

  // 遠くの木星的な霧
  const nebula=ctx.createRadialGradient(W*0.5,H*0.3,0,W*0.5,H*0.3,W*0.7);
  nebula.addColorStop(0,"rgba(150,100,20,0.06)");
  nebula.addColorStop(1,"rgba(0,0,0,0)");
  ctx.fillStyle=nebula; ctx.fillRect(0,0,W,H);

  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // ===== 渦巻き重力場描画 =====
  s5Vortexes.forEach(v=>{
    const alpha=Math.min(1, Math.min(v.life/30, (v.maxLife-v.life)/30)) * 0.6;
    ctx.save();
    ctx.globalAlpha=alpha;
    ctx.translate(v.x, v.y);

    // 渦巻きエフェクト（同心円）
    for(let ri=0;ri<4;ri++){
      const r=v.r*(0.25+ri*0.25);
      const grad=ctx.createRadialGradient(0,0,0,0,0,r);
      grad.addColorStop(0,"rgba(107,203,119,0.4)");
      grad.addColorStop(1,"rgba(107,203,119,0)");
      ctx.strokeStyle=`rgba(107,203,119,${0.4-ri*0.08})`;
      ctx.lineWidth=2;
      ctx.beginPath();
      ctx.arc(0,0,r,v.angle+ri*0.5,v.angle+ri*0.5+Math.PI*1.5);
      ctx.stroke();
    }

    // 中心の光
    const cg=ctx.createRadialGradient(0,0,0,0,0,v.r*0.4);
    cg.addColorStop(0,"rgba(107,203,119,0.5)");
    cg.addColorStop(1,"rgba(107,203,119,0)");
    ctx.fillStyle=cg;
    ctx.beginPath(); ctx.arc(0,0,v.r*0.4,0,Math.PI*2); ctx.fill();

    ctx.restore();
  });

  // ===== クイズゾーン =====
  if(s5QuizActive&&s5QuizZones.length>0){
    ctx.save();
    ctx.fillStyle="rgba(0,0,0,0.82)";
    ctx.beginPath(); ctx.roundRect(W*0.03,H*0.47,W*0.94,46,8); ctx.fill();
    ctx.fillStyle="#C8A96E"; ctx.font=`bold ${Math.floor(W*0.034)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText(`「${s5QuizWord}」の意味は？`,W/2,H*0.47+16);
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.font=`${Math.floor(W*0.028)}px sans-serif`;
    ctx.fillText(`⏱ ${s5QuizTimer}秒 いるゾーンが回答！`,W/2,H*0.47+34);
    ctx.restore();

    const zoneColors=["rgba(200,169,110,0.3)","rgba(107,203,119,0.3)","rgba(77,150,255,0.3)","rgba(255,217,61,0.3)"];
    const zoneBorders=["#C8A96E","#6BCB77","#4D96FF","#FFD93D"];
    s5QuizZones.forEach((z,i)=>{
      ctx.save();
      ctx.fillStyle=zoneColors[i%4]; ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=2;
      ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.fill(); ctx.stroke();
      ctx.fillStyle="#fff"; ctx.textAlign="center"; ctx.textBaseline="middle";
      const fs=Math.floor(W*0.026); ctx.font=`bold ${fs}px sans-serif`;
      const lines=wrapText(ctx,z.label,z.w-14,fs);
      const lh=fs+3, sy=z.y+z.h/2-(lines.length-1)*lh/2;
      lines.forEach((l,li)=>ctx.fillText(l,z.x+z.w/2,sy+li*lh));
      const cx2=ship.x+ship.w/2, cy2=ship.y+ship.h/2;
      if(cx2>=z.x&&cx2<=z.x+z.w&&cy2>=z.y&&cy2<=z.y+z.h){
        ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=4;
        ctx.shadowColor=zoneBorders[i%4]; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.stroke();
      }
      ctx.restore();
    });
  }

  // 隕石
  meteors.forEach(m=>{
    ctx.save();
    ctx.fillStyle="#6B4A10"; ctx.shadowColor="rgba(150,100,20,0.5)"; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    ctx.fillStyle="#4A3008"; ctx.shadowBlur=0;
    ctx.beginPath(); ctx.ellipse(m.x+m.w*0.35,m.y+m.h*0.35,m.w*0.15,m.h*0.12,0.5,0,Math.PI*2); ctx.fill();
    if(m.hp===1){ ctx.strokeStyle="rgba(200,169,110,0.8)"; ctx.lineWidth=1.5; ctx.beginPath(); ctx.moveTo(m.x+m.w*0.4,m.y+m.h*0.2); ctx.lineTo(m.x+m.w*0.55,m.y+m.h*0.5); ctx.lineTo(m.x+m.w*0.45,m.y+m.h*0.8); ctx.stroke(); }
    ctx.restore();
  });

  // 自弾
  shipBullets.forEach(b=>{
    if(!b.active)return;
    ctx.save();
    const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+b.h);
    g.addColorStop(0,"#fff"); g.addColorStop(1,"#C8A96E");
    ctx.fillStyle=g; ctx.shadowColor="#C8A96E"; ctx.shadowBlur=10;
    ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h,4); ctx.fill();
    ctx.restore();
  });

  // ボスフェーズ
  if(shootingPhase==="boss"){
    // ボス弾
    boss.bullets.forEach(b=>{
      ctx.save();
      if(b.homing){
        ctx.fillStyle="#6BCB77"; ctx.shadowColor="#6BCB77"; ctx.shadowBlur=16;
      } else if(b.big){
        const fg=ctx.createRadialGradient(b.x+b.w/2,b.y+b.h/2,2,b.x+b.w/2,b.y+b.h/2,b.w/2);
        fg.addColorStop(0,"#fff"); fg.addColorStop(0.4,"#C8A96E"); fg.addColorStop(1,"rgba(139,105,20,0.3)");
        ctx.fillStyle=fg; ctx.shadowColor="#C8A96E"; ctx.shadowBlur=20;
      } else {
        ctx.fillStyle="#8B6914"; ctx.shadowColor="#8B6914"; ctx.shadowBlur=12;
      }
      ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
      ctx.restore();
    });

    // 木星ボス描画
    const bossHPRatio=Math.max(0,boss.hp/s5BossMaxHP);
    ctx.save();
    ctx.shadowColor=`rgba(200,169,110,0.8)`; ctx.shadowBlur=25+(1-bossHPRatio)*35;

    // 本体グラデーション
    const pg=ctx.createRadialGradient(
      boss.x+boss.w*0.35,boss.y+boss.h*0.3,boss.w*0.05,
      boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2
    );
    pg.addColorStop(0,"#E8C88A"); pg.addColorStop(0.3,"#C8A050"); pg.addColorStop(0.7,"#8B6010"); pg.addColorStop(1,"#5A3A00");
    ctx.fillStyle=pg;
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.fill();

    // 木星の縞模様
    ctx.save();
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.clip();
    const stripes=[
      {y:0.15,h:0.08,color:"rgba(180,120,40,0.5)"},
      {y:0.28,h:0.06,color:"rgba(220,180,100,0.4)"},
      {y:0.42,h:0.10,color:"rgba(150,90,20,0.5)"},
      {y:0.58,h:0.07,color:"rgba(200,160,80,0.4)"},
      {y:0.72,h:0.08,color:"rgba(170,110,30,0.5)"},
    ];
    stripes.forEach(s=>{
      ctx.fillStyle=s.color;
      ctx.fillRect(boss.x,boss.y+boss.h*s.y,boss.w,boss.h*s.h);
    });

    // 大赤斑（木星の特徴）
    ctx.fillStyle="rgba(200,60,20,0.6)";
    ctx.beginPath();
    ctx.ellipse(boss.x+boss.w*0.55,boss.y+boss.h*0.55,boss.w*0.15,boss.h*0.1,0,0,Math.PI*2);
    ctx.fill();
    ctx.fillStyle="rgba(220,80,40,0.4)";
    ctx.beginPath();
    ctx.ellipse(boss.x+boss.w*0.55,boss.y+boss.h*0.55,boss.w*0.1,boss.h*0.07,0,0,Math.PI*2);
    ctx.fill();
    ctx.restore();

    // HP低下でひび
    if(bossHPRatio<0.5){
      ctx.strokeStyle=`rgba(200,150,50,${0.5+(1-bossHPRatio)*0.5})`; ctx.lineWidth=2.5; ctx.shadowBlur=0;
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.25,boss.y+boss.h*0.1); ctx.lineTo(boss.x+boss.w*0.45,boss.y+boss.h*0.5); ctx.lineTo(boss.x+boss.w*0.7,boss.y+boss.h*0.85); ctx.stroke();
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.65,boss.y+boss.h*0.15); ctx.lineTo(boss.x+boss.w*0.45,boss.y+boss.h*0.5); ctx.stroke();
    }
    ctx.restore();
  }

  // エフェクト
  hitEffects.forEach(e=>{
    if(e.alpha<=0)return;
    ctx.save(); ctx.globalAlpha=e.alpha;
    if(e.type==="debris"){ ctx.fillStyle=e.color; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill(); }
    else if(e.type==="heal"){ ctx.strokeStyle=e.color; ctx.lineWidth=3; ctx.shadowColor=e.color; ctx.shadowBlur=12; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.font=`bold ${Math.max(8,Math.floor(e.r*0.8))}px sans-serif`; ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.fillText("+",e.x,e.y-Math.max(0,e.r)*1.2); }
    else { ctx.strokeStyle=e.color; ctx.lineWidth=2.5; ctx.shadowColor=e.color; ctx.shadowBlur=14; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.globalAlpha=e.alpha*0.3; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r*0.5),0,Math.PI*2); ctx.fill(); }
    ctx.restore();
  });

  // 宇宙船
  drawSpaceShip(ctx,ship.x,ship.y,ship.w,ship.h);
  if(dodgeActive){
    ctx.save();
    const pulse=Math.sin(Date.now()*0.02)*0.3+0.7;
    ctx.strokeStyle=`rgba(255,255,255,${pulse})`;
    ctx.lineWidth=3;
    ctx.shadowColor="#fff";
    ctx.shadowBlur=20;
    ctx.beginPath();
    ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();
  }
  // 小型機描画
  if(ship.subShips && ship.subShips.length>0){
    ship.subShips.forEach(ss=>{
      const sx=ship.x+ship.w/2+ss.offset-12;
      const sy=ship.y+8;
      drawRVSubShip(ctx,sx,sy,"#4D96FF");
    });
  }

  // HPバー
  const hpRatio=Math.max(0,shootingPlayerHP/shootingPlayerMaxHP);
  const barW=W*0.5,barX=(W-barW)/2,barY=H-14;
  ctx.save();
  ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(barX,barY,barW,8,4); ctx.fill();
  const hpColor=hpRatio>0.5?"#6BCB77":hpRatio>0.25?"#FFD93D":"#FF6B6B";
  ctx.fillStyle=hpColor; ctx.shadowColor=hpColor; ctx.shadowBlur=6;
  ctx.beginPath(); ctx.roundRect(barX,barY,barW*hpRatio,8,4); ctx.fill();
  ctx.restore();

  // 属性バッジ
  drawElementBadge(ctx,W,s5PlayerElement);
}

// =============================================
//  STAGE 5 CLEAR
// =============================================
function clearStage5(){
  shootingPhase="clear"; shootingGameActive=false;
  clearInterval(shootingTimerInterval);
  if(s5QuizCountdown) clearInterval(s5QuizCountdown);
  cancelAnimationFrame(shootingAnimFrame);
  removeShootListeners();
  unlockShootingUI();
  const firstClear=!isStage5Cleared();
  if(firstClear){ markStage5Cleared(); diamonds+=15; saveGame(); }
  draw_stage5();
  setTimeout(()=>{
    document.getElementById("spaceArea").innerHTML=`
      <div style="text-align:center;padding:30px 16px">
        <div style="font-size:4rem;margin-bottom:10px">🏆</div>
        <div style="font-family:'Fredoka One',cursive;font-size:2rem;
          background:linear-gradient(90deg,#C8A96E,#8B6914);
          -webkit-background-clip:text;-webkit-text-fill-color:transparent;
          margin-bottom:8px">STAGE 5 CLEAR!</div>
        ${firstClear
          ?`<div style="font-family:'Fredoka One',cursive;font-size:1.3rem;color:#FFD93D;margin-bottom:6px">💎×15 獲得！</div>`
          :`<div style="font-size:13px;color:rgba(255,255,255,0.4);margin-bottom:6px">※2回目以降クリア報酬なし</div>`}
        <div style="font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:20px">
          🟤 木星を撃破した！<br>
          <span style="font-size:12px;color:rgba(255,255,255,0.4)">
            ※クイズ正解で💎×3（回数無制限）
          </span>
        </div>
        <button onclick="showStage5DeckSelect()"
          style="background:linear-gradient(135deg,#C8A96E,#8B6914);
            font-size:1rem;padding:14px 28px;margin:6px">
          🔄 もう一度
        </button>
        <br>
        <button onclick="showNormalStageMenu()"
          style="background:rgba(255,255,255,0.08);box-shadow:none;
            font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">
          ← ステージ選択へ
        </button>
      </div>`;
    spawnStars();
  },500);
}

// =============================================
//  STAGE 6
// =============================================
let s6PlayerElement  = "fire";
let s6BossElement    = "earth";
let s6BossMaxHP      = 16000;
let s6BossATK        = 600;
let s6QuizActive     = false;
let s6QuizAnswer     = "";
let s6QuizZones      = [];
let s6QuizTimer      = 0;
let s6QuizWord       = "";
let s6QuizCountdown  = null;
let s6QuizShown15    = false;
let s6QuizShown30    = false;
let s6QuizShown45    = false;
let s6BossQuizTimer  = 0;
let s6BossPhase      = false;
let s6Split          = false;
let s6Boss2          = null;

function showStage6DeckSelect(){
  const pool = owned.filter(c=>c.type==="target1900");
  const grouped = {};
  pool.forEach(c=>{ if(!grouped[c.word]) grouped[c.word]=c; });
  const cards = Object.values(grouped);

  const area = document.getElementById("spaceArea");
  area.innerHTML = `
    <div style="text-align:center;padding:12px">
      <div style="font-family:'Fredoka One',cursive;font-size:1.1rem;
        color:#C8A96E;margin-bottom:8px">🪐 ステージ６ デッキ選択</div>
      <div style="background:rgba(200,169,110,0.1);border:1px solid rgba(200,169,110,0.3);
        border-radius:12px;padding:10px;margin:0 auto 12px;max-width:320px;
        font-size:12px;color:rgba(255,255,255,0.7);text-align:left;line-height:1.8">
        🪐 <b>ステージ6 特殊ギミック</b><br>
        斜めに飛んでくる隕石！<br>
        ボスHP50%で2体に分裂！<br>
        曲がるリング攻撃に要注意！<br>
        🪨 ボス属性：<b style="color:#C8A96E">地属性</b>（木属性が有利！）<br>
        クイズ正解で💎×3獲得！
      </div>
      <div style="font-size:13px;color:#C8A96E;margin-bottom:8px">
        選択: <span id="s6SelectedCount">0</span> / 2
      </div>
      <div id="s6CardPicker"
        style="display:flex;flex-wrap:wrap;justify-content:center;
          gap:8px;margin-bottom:16px"></div>
      <div id="s6SelectedDisplay"
        style="display:flex;justify-content:center;gap:12px;
          margin-bottom:80px;min-height:60px"></div>
      <div style="position:fixed;bottom:70px;right:16px;z-index:1000">
        <button id="s6StartBtn" disabled
          style="background:linear-gradient(135deg,#C8A96E,#4D96FF);
            font-size:1rem;padding:14px 20px;border-radius:20px;
            opacity:0.4;cursor:not-allowed;
            box-shadow:0 4px 20px rgba(0,0,0,0.4)">
          🚀 スタート！
        </button>
      </div>
      <button onclick="showNormalStageMenu()"
        style="background:rgba(255,255,255,0.08);box-shadow:none;
          font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">← 戻る</button>
    </div>`;

  if(cards.length===0){
    document.getElementById("s6CardPicker").innerHTML=
      `<div style="color:rgba(255,255,255,0.4);font-size:13px;padding:20px">
        ターゲット1900カードがありません！
      </div>`;
    return;
  }

  let selected=[];

  function renderPicker(){
    document.getElementById("s6SelectedCount").textContent=selected.length;
    document.getElementById("s6CardPicker").innerHTML=cards.map(c=>{
      const idx=selected.findIndex(s=>s.word===c.word);
      const isSel=idx!==-1;
      return `
        <div onclick="s6ToggleCard('${c.word}')"
          style="cursor:pointer;width:95px;padding:10px 6px;border-radius:14px;
            background:${isSel?"rgba(255,217,61,0.2)":"rgba(255,255,255,0.06)"};
            border:2px solid ${isSel?c.elementColor:"rgba(255,255,255,0.15)"};
            text-align:center;transition:all 0.15s;position:relative">
          ${isSel?`<div style="position:absolute;top:-6px;right:-6px;
            background:#FFD93D;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#1a1a2e;font-weight:700">${idx+1}</div>`:""}
          <div style="font-size:1rem">${c.elementLabel.split(" ")[0]}</div>
          <div style="font-family:'Fredoka One',cursive;font-size:0.8rem;color:#fff">
            ${c.word}
          </div>
          <div style="font-size:10px;color:rgba(255,255,255,0.5)">${c.meaning}</div>
          <div style="font-size:10px;color:${c.elementColor}">
            ⚔️${c.atk} ❤️${c.hp}
          </div>
        </div>`;
    }).join("");

    document.getElementById("s6SelectedDisplay").innerHTML=[0,1].map(i=>{
      const c=selected[i];
      return c
        ?`<div style="background:rgba(255,255,255,0.08);
            border:1px solid ${c.elementColor};border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px">
            <div style="font-size:10px;color:rgba(255,255,255,0.4)">
              ${i===0?"1枚目（メイン）":"2枚目（予備）"}
            </div>
            <div style="font-family:'Fredoka One',cursive;font-size:0.85rem;color:#fff">
              ${c.word}
            </div>
            <div style="font-size:10px;color:${c.elementColor}">
              ⚔️${c.atk} ❤️${c.hp}
            </div>
          </div>`
        :`<div style="background:rgba(255,255,255,0.03);
            border:1px dashed rgba(255,255,255,0.15);border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px;
            color:rgba(255,255,255,0.25);font-size:12px">
            ${i===0?"1枚目":"2枚目"}<br>未選択
          </div>`;
    }).join("");

    const btn=document.getElementById("s6StartBtn");
    btn.disabled=selected.length!==2;
    btn.style.opacity=selected.length===2?"1":"0.4";
    btn.style.cursor=selected.length===2?"pointer":"not-allowed";
  }

  window.s6ToggleCard=function(word){
    const c=cards.find(x=>x.word===word);
    const idx=selected.findIndex(s=>s.word===word);
    if(idx!==-1){ selected.splice(idx,1); }
    else { if(selected.length>=2)return; selected.push(c); }
    renderPicker();
  };

  document.getElementById("s6StartBtn").onclick=()=>{
    if(selected.length<2)return;
    shootingDeck=selected;
    beginStage6();
  };
  renderPicker();
}

// =============================================
//  BEGIN STAGE 6
// =============================================
function beginStage6(){
  const area=document.getElementById("spaceArea");
  area.innerHTML=`
    <div style="position:relative;width:100%;max-width:420px;margin:0 auto">
      <canvas id="shootCanvas"
        style="display:block;width:100%;border-radius:16px;
          background:#05050f;touch-action:none"></canvas>
          <div id="shootQuizResult"
  style="position:absolute;bottom:30px;left:50%;transform:translateX(-50%);
    font-family:'Fredoka One',cursive;font-size:1rem;
    background:rgba(0,0,0,0.7);border-radius:12px;padding:6px 16px;
    pointer-events:none;display:none;text-align:center;
    white-space:pre-line;z-index:100;min-width:200px">
</div>
      <button onclick="toggleShootingPause()"
        style="position:absolute;top:8px;right:8px;
          background:rgba(0,0,0,0.5);border:1px solid rgba(255,255,255,0.3);
          color:#fff;font-size:12px;padding:5px 10px;border-radius:8px;
          z-index:2100;cursor:pointer">⏸ ポーズ</button>
      <div id="shootHUD"
        style="position:absolute;top:8px;left:8px;right:8px;
          display:flex;justify-content:space-between;pointer-events:none">
        <div id="shootHP"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#6BCB77;text-shadow:0 0 8px rgba(107,203,119,0.8)">❤️ 0</div>
        <div id="shootTimer"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#FFD93D;text-shadow:0 0 8px rgba(255,217,61,0.8)">⏱ 60</div>
        <div id="shootCard"
          style="font-family:'Fredoka One',cursive;font-size:11px;color:#C8A96E">
          🚀 1枚目
        </div>
      </div>
      <div id="shootBossHUD"
        style="position:absolute;top:36px;left:8px;right:8px;
          display:none;pointer-events:none">
        <div style="font-family:'Fredoka One',cursive;font-size:11px;
          color:#C8A96E;text-align:center;margin-bottom:2px">🪐 土星</div>
        <div style="background:rgba(0,0,0,0.4);border-radius:8px;
          height:10px;overflow:hidden">
          <div id="shootBossHPBar"
            style="height:100%;
              background:linear-gradient(90deg,#C8A96E,#4D96FF);
              border-radius:8px;transition:width 0.3s;width:100%"></div>
        </div>
        <div id="s6Boss2HUD" style="display:none;margin-top:4px">
          <div style="font-family:'Fredoka One',cursive;font-size:10px;
            color:#C8A96E;text-align:center;margin-bottom:2px">🪐 土星B</div>
          <div style="background:rgba(0,0,0,0.4);border-radius:8px;
            height:8px;overflow:hidden">
            <div id="s6Boss2HPBar"
              style="height:100%;
                background:linear-gradient(90deg,#4D96FF,#C8A96E);
                border-radius:8px;width:100%"></div>
          </div>
        </div>
      </div>
      <div id="shootMessage"
        style="position:absolute;top:45%;left:50%;
          transform:translate(-50%,-50%);
          font-family:'Fredoka One',cursive;font-size:1.2rem;color:#fff;
          text-align:center;pointer-events:none;
          text-shadow:0 0 20px rgba(255,255,255,0.8);display:none;
          background:rgba(0,0,0,0.6);border-radius:12px;
          padding:8px 16px;white-space:pre-line"></div>
    </div>`;

  shootCanvas=document.getElementById("shootCanvas");
  const maxW=Math.min(420,window.innerWidth-32);
  shootCanvas.width=maxW;
  shootCanvas.height=Math.floor(maxW*1.5);
  shootCtx=shootCanvas.getContext("2d");

  if(shootingTimerInterval){ clearInterval(shootingTimerInterval); shootingTimerInterval=null; }
  if(shootingAnimFrame){ cancelAnimationFrame(shootingAnimFrame); shootingAnimFrame=null; }

  shootingCurrentCard=0; shootingPhase="survival"; shootingTime=60;
  shipBullets=[]; meteors=[]; hitEffects=[];
  bulletTimer=0; meteorTimer=0; bossTimer=0;
  boss.bullets=[]; boss.hp=s6BossMaxHP; boss.vx=2.5;
  shootingBossActive=false; lastFrameTime=0;
  s6Split=false; s6Boss2=null;

  s6QuizActive=false; s6QuizShown15=false; s6QuizShown30=false; s6QuizShown45=false;
  s6BossPhase=false; s6BossQuizTimer=0; s6QuizZones=[];
  if(s6QuizCountdown){ clearInterval(s6QuizCountdown); s6QuizCountdown=null; }

  const c=shootingDeck[0];
  shootingPlayerMaxHP=c.hp; shootingPlayerHP=c.hp; shootingPlayerATK=c.atk;
  s6PlayerElement=c.element;

  ship.x=shootCanvas.width/2-ship.w/2;
  ship.y=shootCanvas.height-ship.h-20;

  shootCanvas.addEventListener("touchstart",onShootTouchStart,{passive:false});
  shootCanvas.addEventListener("touchmove", onShootTouchMove, {passive:false});
  shootCanvas.addEventListener("touchend",  onShootTouchEnd,  {passive:false});
  shootCanvas.addEventListener("mousedown", onShootMouseDown);
  shootCanvas.addEventListener("mousemove", onShootMouseMove);
  shootCanvas.addEventListener("mouseup",   onShootMouseUp);

  shootingPaused=false;
  // 小型機チェック
  const subUnlocked = localStorage.getItem("subShipUnlocked")==="true";
  if(subUnlocked){
    ship.subShips = [{offset:-35},{offset:35}];
  } else {
    ship.subShips = [];
  }
  currentShootingStage="stage6";

  shootingTimerInterval=setInterval(()=>{
    if(shootingPhase!=="survival")return;
    shootingTime--;
    updateShootHUD();
    if(shootingTime===45&&!s6QuizShown15){ s6QuizShown15=true; triggerS6Quiz(); }
    if(shootingTime===30&&!s6QuizShown30){ s6QuizShown30=true; triggerS6Quiz(); }
    if(shootingTime===15&&!s6QuizShown45){ s6QuizShown45=true; triggerS6Quiz(); }
    if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS6BossPhase(); }
  },1000);

  shootingGameActive=true;
  lockShootingUI();
  dodgeUnlocked = localStorage.getItem("dodgeUnlocked")==="true";
  dodgeCooldown = 0;
  dodgeActive   = false;
  dodgeActiveTimer = 0;
  renderDodgeButton();
  updateShootHUD();
  requestAnimationFrame(stage6Loop);
}

// =============================================
//  STAGE 6 BOSS PHASE
// =============================================
function startS6BossPhase(){
  shootingPhase="boss"; s6BossPhase=true; shootingBossActive=true;
  boss.x=shootCanvas.width/2-boss.w/2; boss.y=60;
  boss.hp=s6BossMaxHP; boss.vx=2.5; boss.bullets=[];
  meteors=[]; bossTimer=0; s6BossQuizTimer=0;
  s6Split=false; s6Boss2=null;
  const bossHUD=document.getElementById("shootBossHUD");
  if(bossHUD) bossHUD.style.display="block";
  showShootMessage("🪐 土星 出現！\nHP50%で分裂するぞ！",2500);
  updateBossHUD();
}

// =============================================
//  STAGE 6 LOOP
// =============================================
function stage6Loop(timestamp){
  if(!shootingGameActive)return;
  const dt=Math.min((timestamp-(lastFrameTime||timestamp))/16.67,3);
  lastFrameTime=timestamp;
  update_stage6(dt);
  draw_stage6();
  shootingAnimFrame=requestAnimationFrame(stage6Loop);
}

// =============================================
//  UPDATE STAGE 6
// =============================================
function update_stage6(dt){
  const W=shootCanvas.width, H=shootCanvas.height;
  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  hitEffects.forEach(e=>{
    e.life+=dt; e.alpha=Math.max(0,1-e.life/e.maxLife);
    if(e.type==="debris"){ e.x+=(e.vx||0)*dt; e.y+=(e.vy||0)*dt; e.r=Math.max(0,e.r-0.15*dt); }
    else { e.r+=(e.maxR-e.r)*0.18*dt; }
  });
  hitEffects=hitEffects.filter(e=>e.life<e.maxLife);
  // 回避・無敵タイマー更新
  if(dodgeActive){
    dodgeActiveTimer-=dt;
    if(dodgeActiveTimer<=0){
      dodgeActive=false;
      dodgeCooldown=600; // 10秒（600フレーム）
    }
  }
  if(dodgeCooldown>0){
    dodgeCooldown-=dt;
    if(dodgeCooldown<0) dodgeCooldown=0;
    updateDodgeButton();
  }
  if(dodgeActive) updateDodgeButton();

  // 弾発射　←この行の直後（全ステージ共通）
  bulletTimer+=dt;
  if(bulletTimer>=60){
    bulletTimer=0;
    // メイン弾
    shipBullets.push({x:ship.x+ship.w/2-4,y:ship.y-10,w:8,h:14,active:true});
    // 小型機の弾
    if(ship.subShips && ship.subShips.length>0){
      ship.subShips.forEach(ss=>{
        const angle=15*Math.PI/180;
        const dir=ss.offset<0?-1:1;
        shipBullets.push({
          x:ship.x+ship.w/2+ss.offset-4,
          y:ship.y-10,
          w:6, h:10,
          vx:Math.sin(angle)*4*dir,
          vy:-Math.cos(angle)*8,
          active:true,
          isSub:true,
        });
      });
    }
  }
  shipBullets.forEach(b=>{
    b.x+=(b.vx||0)*dt;
    b.y+=(b.vy||-8)*dt;
  });
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

  if(shootingPhase==="survival"){
    meteorTimer+=dt;
    if(meteorTimer>=35+Math.random()*15){
      meteorTimer=0;
      const mw=30+Math.random()*20, mh=30+Math.random()*20;
      const roll=Math.random();

      if(roll<0.4){
        // 上から真下
        meteors.push({
          x:Math.random()*(W-mw), y:-mh,
          w:mw, h:mh,
          vx:0, vy:3+Math.random()*2,
          hp:2, diagonal:false,
          id:Date.now()+Math.random()
        });
      } else if(roll<0.7){
        // 左から斜め
        meteors.push({
          x:-mw, y:Math.random()*H*0.6,
          w:mw, h:mh,
          vx:3+Math.random()*1.5,
          vy:2+Math.random()*2,
          hp:2, diagonal:true,
          id:Date.now()+Math.random()
        });
      } else {
        // 右から斜め
        meteors.push({
          x:W+mw, y:Math.random()*H*0.6,
          w:mw, h:mh,
          vx:-(3+Math.random()*1.5),
          vy:2+Math.random()*2,
          hp:2, diagonal:true,
          id:Date.now()+Math.random()
        });
      }
    }

    meteors.forEach(m=>{
      m.x+=(m.vx||0)*dt;
      m.y+=(m.vy||0)*dt;
      if(m.diagonal){
        if(m.x<=0){ m.x=1; m.vx=Math.abs(m.vx); }
        if(m.x+m.w>=W){ m.x=W-m.w-1; m.vx=-Math.abs(m.vx); }
      }
    });

    // 自弾 vs 隕石
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let mi=meteors.length-1;mi>=0;mi--){
        const m=meteors[mi]; if(m.hp<=0)continue;
        if(rectsOverlap(b,m)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#C8A96E");
          b.active=false; m.hp--;
          if(m.hp<=0){
            spawnMeteorBreakEffect(m.x+m.w/2,m.y+m.h/2);
            const heal=Math.floor(shootingPlayerMaxHP*0.015);
            shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
            spawnHealEffect(ship.x+ship.w/2,ship.y);
            updateShootHUD(); meteors.splice(mi,1);
          }
          break;
        }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
    meteors=meteors.filter(m=>m.hp>0&&m.y<H+50&&m.x>-200&&m.x<W+200);

    // 隕石 vs プレイヤー
    for(let mi=meteors.length-1;mi>=0;mi--){
      const m=meteors[mi];
      if(rectsOverlap(ship,m)){
        meteors.splice(mi,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        shootingPlayerHP-=350; updateShootHUD();
        if(shootingPlayerHP<=0){ handlePlayerDeath(); return; }
      }
    }

  } else if(shootingPhase==="boss"){
    // ボス1は倒されたら移動・攻撃しない
    if(boss.hp>0){
      boss.x+=boss.vx*dt;
      if(boss.x<=10){
        boss.x=10;
        boss.vx=Math.abs(boss.vx);
      }
      if(boss.x+boss.w>=W-10){
        boss.x=W-boss.w-10;
        boss.vx=-Math.abs(boss.vx);
      }
    } else {
      boss.bullets=[];
    }

    const minY=(boss.hp>0?boss.y+boss.h:0);
    if(s6Split&&s6Boss2&&s6Boss2.hp>0){
      const minY2=s6Boss2.y+s6Boss2.h;
      if(ship.y<Math.max(minY,minY2)) ship.y=Math.max(minY,minY2);
    } else if(boss.hp>0){
      if(ship.y<minY) ship.y=minY;
    }

    // 分裂チェック
    if(!s6Split && boss.hp<=s6BossMaxHP*0.5){
      s6Split=true;
      s6Boss2={
        x: W*0.6,  // 右側に生成（壁から離す）
        y: boss.y,
        w: boss.w*0.8,
        h: boss.h*0.8,
        hp: Math.floor(s6BossMaxHP*0.32), // 0.4から20%減
        maxHP: Math.floor(s6BossMaxHP*0.32),
        vx: -2.2,  // 最初は左向き
        bullets: [],
        bossTimer: 0, // すぐ攻撃しないよう少し遅らせる
      };
      boss.vx = 2.2; // ボス1は右向き（離れる方向）
      showShootMessage("💥 分裂した！\n2体とも倒せ！",2000);
      const hud2=document.getElementById("s6Boss2HUD");
      if(hud2) hud2.style.display="block";
    }

    // 分裂後ボス2
    if(s6Split&&s6Boss2&&s6Boss2.hp>0){
      // ボス2移動
      s6Boss2.x+=s6Boss2.vx*dt;
      if(s6Boss2.x<=10){
        s6Boss2.x=10;
        s6Boss2.vx=Math.abs(s6Boss2.vx);
      }
      if(s6Boss2.x+s6Boss2.w>=W-10){
        s6Boss2.x=W-s6Boss2.w-10;
        s6Boss2.vx=-Math.abs(s6Boss2.vx);
      }

      // ボス2攻撃（ブーメラン弾）
      s6Boss2.bossTimer=(s6Boss2.bossTimer||0)+dt;
      if(s6Boss2.bossTimer>=120){
        s6Boss2.bossTimer=0;
        const bx2=s6Boss2.x+s6Boss2.w/2;
        const by2=s6Boss2.y+s6Boss2.h;
        const dir=Math.random()<0.5?1:-1;
        s6Boss2.bullets.push({
          x:bx2-24, y:by2,
          w:48, h:48,
          vx:0, vy:4,
          curve:dir*0.06,
          active:true,
          isRing:true,
          boomerang:true,
        });
      }

      // ボス2弾移動
      s6Boss2.bullets.forEach(b=>{
        b.vx+=(b.curve||0)*dt;
        b.vx=Math.max(-4,Math.min(4,b.vx));
        b.x+=b.vx*dt;
        b.y+=b.vy*dt;
      });
      s6Boss2.bullets=s6Boss2.bullets.filter(
        b=>b.active&&b.y<H+50&&b.x>-50&&b.x<W+50
      );

      // ボス2弾 vs プレイヤー
      for(let i=s6Boss2.bullets.length-1;i>=0;i--){
        const b=s6Boss2.bullets[i]; if(!b.active)continue;
        if(rectsOverlap(b,ship)){
          s6Boss2.bullets.splice(i,1);
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#4D96FF");
          const mult=getElementMultiplier(s6BossElement,s6PlayerElement);
          shootingPlayerHP-=Math.floor(s6BossATK*0.7*mult);
          updateShootHUD();
          if(shootingPlayerHP<=0){ handlePlayerDeath(); return; }
        }
      }

      // 自弾 vs ボス2
      const boss2Rect={x:s6Boss2.x,y:s6Boss2.y,w:s6Boss2.w,h:s6Boss2.h};
      for(let bi=shipBullets.length-1;bi>=0;bi--){
        const b=shipBullets[bi]; if(!b.active)continue;
        if(rectsOverlap(b,boss2Rect)){
          spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
          b.active=false;
          const mult=getElementMultiplier(s6PlayerElement,s6BossElement);
          s6Boss2.hp-=Math.floor(shootingPlayerATK*mult);
          updateS6Boss2HUD();
          if(s6Boss2.hp<=0){
            spawnMeteorBreakEffect(s6Boss2.x+s6Boss2.w/2,s6Boss2.y+s6Boss2.h/2);
            s6Boss2.hp=0;
            s6Boss2.bullets=[];
            showShootMessage("💥 土星B 撃破！\n残り1体！",1500);
          }
        }
      }
    }

    // ボスクイズ
    s6BossQuizTimer+=dt;
    if(s6BossQuizTimer>=1200){ s6BossQuizTimer=0; if(!s6QuizActive) triggerS6Quiz(); }

    // ボス1攻撃（生きている時だけ）
    if(boss.hp>0){
      bossTimer+=dt;
      if(bossTimer>=90+Math.random()*60){
        bossTimer=0;
        const bx=boss.x+boss.w/2, by=boss.y+boss.h;
        const roll=Math.random();
        if(roll<0.4){
          boss.bullets.push({x:bx-7,y:by,w:14,h:14,vx:0,vy:4,active:true,curve:0});
        } else if(roll<0.7){
          // ブーメラン弾1つ（まっすぐ落ちながら左右に曲がる）
          const dir=Math.random()<0.5?1:-1;
          boss.bullets.push({
            x:bx-24, y:by,
            w:48, h:48,
            vx:0, vy:4,
            curve:dir*0.06,
            active:true,
            isRing:true,
          });
          
        } else {
          boss.bullets.push({x:bx-22,y:by,w:44,h:44,vx:0,vy:2.8,active:true,big:true,curve:0});
        }
      }

      boss.bullets.forEach(b=>{
        b.vx+=(b.curve||0)*dt;
        b.vx=Math.max(-4,Math.min(4,b.vx)); // 横移動を制限
        b.x+=b.vx*dt;
        b.y+=b.vy*dt;
      });

      // ボス1弾 vs プレイヤー
      for(let i=boss.bullets.length-1;i>=0;i--){
        const b=boss.bullets[i]; if(!b.active)continue;
        if(rectsOverlap(b,ship)){
          boss.bullets.splice(i,1);
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#C8A96E");
          const mult=getElementMultiplier(s6BossElement,s6PlayerElement);
          const dmg=Math.floor(s6BossATK*(b.big?2.5:1)*mult);
          if(applyPlayerDamage(dmg, true)) return;
        }
      }
      boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+50&&b.x>-50&&b.x<W+50);

      // 自弾 vs ボス1
      const bossRect={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
      for(let bi=shipBullets.length-1;bi>=0;bi--){
        const b=shipBullets[bi]; if(!b.active)continue;
        if(rectsOverlap(b,bossRect)){
          spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
          b.active=false;
          const mult=getElementMultiplier(s6PlayerElement,s6BossElement);
          boss.hp-=Math.floor(shootingPlayerATK*mult);
          if(boss.hp<0) boss.hp=0;
          updateBossHUD();
          if(boss.hp<=0){
            boss.bullets=[];
            if(s6Split&&s6Boss2&&s6Boss2.hp>0){
              showShootMessage("💥 土星A 撃破！\n土星Bを倒せ！",1500);
            }
          }
        }
      }
    }

    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

    // 両方倒したかチェック
    if(boss.hp<=0&&(!s6Split||(s6Boss2&&s6Boss2.hp<=0)||!s6Boss2)){
      if(s6Split){
        // 分裂済み→両方倒した
        if(s6Boss2&&s6Boss2.hp<=0||!s6Boss2){ clearStage6(); return; }
      } else {
        // 分裂前に倒した
        clearStage6(); return;
      }
    }
  }
 }

function updateS6Boss2HUD(){
  const bar=document.getElementById("s6Boss2HPBar");
  if(!bar||!s6Boss2)return;
  bar.style.width=Math.max(0,s6Boss2.hp/s6Boss2.maxHP*100)+"%";
}

// =============================================
//  STAGE 6 QUIZ
// =============================================
function triggerS6Quiz(){
  if(s6QuizActive)return;
  s6QuizActive=true;
  const card=target1900Cards[Math.floor(Math.random()*target1900Cards.length)];
  const q=card.quizzes[Math.floor(Math.random()*card.quizzes.length)];
  s6QuizAnswer=q.correct;
  s6QuizWord=card.word;
  const wrongs=q.choices.sort(()=>Math.random()-0.5).slice(0,3);
  const allChoices=[...wrongs,q.correct].sort(()=>Math.random()-0.5);

  const W=shootCanvas.width, H=shootCanvas.height;
  const zoneTop=H*0.55, zoneH=(H-zoneTop-20)/2, zoneW=W/2-8;
  s6QuizZones=[
    {label:allChoices[0],x:4,     y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[1],x:W/2+4, y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[2],x:4,     y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
    {label:allChoices[3],x:W/2+4, y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
  ];
  s6QuizTimer=5;
  if(s6QuizCountdown) clearInterval(s6QuizCountdown);
  s6QuizCountdown=setInterval(()=>{
    s6QuizTimer--;
    if(s6QuizTimer<=0){ clearInterval(s6QuizCountdown); s6QuizCountdown=null; judgeS6Quiz(); }
  },1000);
}

function judgeS6Quiz(){
  s6QuizActive=false;
  const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
  let chosen=null;
  for(const z of s6QuizZones){ if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){ chosen=z.label; break; } }
  s6QuizZones=[];
  if(chosen===s6QuizAnswer){  // ← 各ステージの変数名に合わせる
    diamonds+=3; saveGame();
    showQuizResult(true,"");
  } else {
    shootingPlayerHP-=600; updateShootHUD();
    showQuizResult(false, s6QuizAnswer); // ← 各ステージの変数名に合わせる
    const wrongCard=target1900Cards.find(c=>c.word===s6QuizWord);
    if(wrongCard) recordWrongWord("target1900", wrongCard.word, wrongCard.meaning);
    if(shootingPlayerHP<=0) handlePlayerDeath();
  }
}

// =============================================
//  DRAW STAGE 6
// =============================================
function draw_stage6(){
  const ctx=shootCtx, W=shootCanvas.width, H=shootCanvas.height;

  ctx.fillStyle="#05050f"; ctx.fillRect(0,0,W,H);

  // 星
  for(let i=0;i<80;i++){
    ctx.fillStyle=`rgba(200,180,${220+((i*37)%35)},${0.3+((i*73)%100)/100*0.4})`;
    ctx.fillRect((i*137+50)%W,(i*97+30)%H,1.5,1.5);
  }

  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // クイズゾーン
  if(s6QuizActive&&s6QuizZones.length>0){
    ctx.save();
    ctx.fillStyle="rgba(0,0,0,0.82)";
    ctx.beginPath(); ctx.roundRect(W*0.03,H*0.47,W*0.94,46,8); ctx.fill();
    ctx.fillStyle="#C8A96E"; ctx.font=`bold ${Math.floor(W*0.034)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText(`「${s6QuizWord}」の意味は？`,W/2,H*0.47+16);
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.font=`${Math.floor(W*0.028)}px sans-serif`;
    ctx.fillText(`⏱ ${s6QuizTimer}秒 いるゾーンが回答！`,W/2,H*0.47+34);
    ctx.restore();

    const zoneColors=["rgba(200,169,110,0.3)","rgba(77,150,255,0.3)","rgba(107,203,119,0.3)","rgba(255,217,61,0.3)"];
    const zoneBorders=["#C8A96E","#4D96FF","#6BCB77","#FFD93D"];
    s6QuizZones.forEach((z,i)=>{
      ctx.save();
      ctx.fillStyle=zoneColors[i%4]; ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=2;
      ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.fill(); ctx.stroke();
      ctx.fillStyle="#fff"; ctx.textAlign="center"; ctx.textBaseline="middle";
      const fs=Math.floor(W*0.026); ctx.font=`bold ${fs}px sans-serif`;
      const lines=wrapText(ctx,z.label,z.w-14,fs);
      const lh=fs+3, sy=z.y+z.h/2-(lines.length-1)*lh/2;
      lines.forEach((l,li)=>ctx.fillText(l,z.x+z.w/2,sy+li*lh));
      const cx2=ship.x+ship.w/2, cy2=ship.y+ship.h/2;
      if(cx2>=z.x&&cx2<=z.x+z.w&&cy2>=z.y&&cy2<=z.y+z.h){
        ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=4;
        ctx.shadowColor=zoneBorders[i%4]; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.stroke();
      }
      ctx.restore();
    });
  }

  // 斜め隕石
  meteors.forEach(m=>{
    ctx.save();
    ctx.fillStyle="#5A4A80"; ctx.shadowColor="rgba(100,80,180,0.5)"; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    ctx.fillStyle="#3A2A60"; ctx.shadowBlur=0;
    ctx.beginPath(); ctx.ellipse(m.x+m.w*0.35,m.y+m.h*0.35,m.w*0.15,m.h*0.12,0.5,0,Math.PI*2); ctx.fill();
    ctx.restore();
  });

  // 自弾
  shipBullets.forEach(b=>{
    if(!b.active)return;
    ctx.save();
    const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+b.h);
    g.addColorStop(0,"#fff"); g.addColorStop(1,"#C8A96E");
    ctx.fillStyle=g; ctx.shadowColor="#C8A96E"; ctx.shadowBlur=10;
    ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h,4); ctx.fill();
    ctx.restore();
  });

  // ボスフェーズ描画
  if(shootingPhase==="boss"){
    // ボス弾
    const drawBossBullets=(bullets)=>{
      bullets.forEach(b=>{
        if(!b.active)return;
        ctx.save();
        if(b.isRing){
          ctx.strokeStyle="#4D96FF"; ctx.lineWidth=4;
          ctx.shadowColor="#4D96FF"; ctx.shadowBlur=18;
          ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.stroke();
          ctx.fillStyle="rgba(77,150,255,0.25)";
          ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
          ctx.fillStyle="rgba(150,200,255,0.4)";
          ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w*0.25,0,Math.PI*2); ctx.fill();
        } else if(b.big){
          const fg=ctx.createRadialGradient(b.x+b.w/2,b.y+b.h/2,2,b.x+b.w/2,b.y+b.h/2,b.w/2);
          fg.addColorStop(0,"#fff"); fg.addColorStop(0.4,"#C8A96E"); fg.addColorStop(1,"rgba(139,105,20,0.3)");
          ctx.fillStyle=fg; ctx.shadowColor="#C8A96E"; ctx.shadowBlur=20;
          ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
        } else {
          ctx.fillStyle="#C8A96E"; ctx.shadowColor="#C8A96E"; ctx.shadowBlur=12;
          ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
        }
        ctx.restore();
      });
    };

    drawBossBullets(boss.bullets);
    if(s6Split && s6Boss2) drawBossBullets(s6Boss2.bullets);

    // 土星ボス描画関数
    const drawSaturn=(bx,by,bw,bh,hpRatio,isSmall)=>{
      ctx.save();
      ctx.shadowColor=`rgba(200,169,110,0.8)`; ctx.shadowBlur=20+(1-hpRatio)*25;

      // リング（後ろ）
      ctx.save();
      ctx.strokeStyle=`rgba(200,169,110,0.5)`; ctx.lineWidth=isSmall?6:10;
      ctx.shadowColor="rgba(200,169,110,0.4)"; ctx.shadowBlur=8;
      ctx.beginPath();
      ctx.ellipse(bx+bw/2,by+bh/2,bw*0.75,bh*0.2,-0.2,0,Math.PI*2);
      ctx.stroke();
      ctx.restore();

      // 本体
      const pg=ctx.createRadialGradient(
        bx+bw*0.35,by+bh*0.3,bw*0.05,
        bx+bw/2,by+bh/2,bw/2
      );
      pg.addColorStop(0,"#E8D8A0");
      pg.addColorStop(0.4,"#C8A850");
      pg.addColorStop(0.8,"#8B7030");
      pg.addColorStop(1,"#5A4010");
      ctx.fillStyle=pg;
      ctx.beginPath(); ctx.arc(bx+bw/2,by+bh/2,bw/2,0,Math.PI*2); ctx.fill();

      // 縞模様
      ctx.save();
      ctx.beginPath(); ctx.arc(bx+bw/2,by+bh/2,bw/2,0,Math.PI*2); ctx.clip();
      [{y:0.2,h:0.07,c:"rgba(180,140,60,0.4)"},{y:0.35,h:0.05,c:"rgba(140,100,30,0.5)"},{y:0.55,h:0.08,c:"rgba(160,120,50,0.4)"},{y:0.72,h:0.06,c:"rgba(140,100,30,0.4)"}].forEach(s=>{
        ctx.fillStyle=s.c;
        ctx.fillRect(bx,by+bh*s.y,bw,bh*s.h);
      });
      ctx.restore();

      // リング（前）
      ctx.save();
      ctx.strokeStyle=`rgba(200,169,110,0.8)`; ctx.lineWidth=isSmall?4:8;
      ctx.shadowColor="rgba(200,169,110,0.6)"; ctx.shadowBlur=10;
      ctx.beginPath();
      ctx.ellipse(bx+bw/2,by+bh/2,bw*0.75,bh*0.2,-0.2,Math.PI,Math.PI*2);
      ctx.stroke();
      ctx.restore();

      // HP低下でひび
      if(hpRatio<0.5){
        ctx.strokeStyle=`rgba(255,200,100,${0.5+(1-hpRatio)*0.5})`; ctx.lineWidth=2; ctx.shadowBlur=0;
        ctx.beginPath(); ctx.moveTo(bx+bw*0.3,by+bh*0.15); ctx.lineTo(bx+bw*0.5,by+bh*0.5); ctx.lineTo(bx+bw*0.7,by+bh*0.85); ctx.stroke();
      }
      ctx.restore();
    };

    // ボス1描画（HPが0より大きい時のみ）
    if(boss.hp>0){
      const bossHPRatio=Math.max(0,boss.hp/s6BossMaxHP);
      drawSaturn(boss.x,boss.y,boss.w,boss.h,bossHPRatio,false);
    }

    // ボス2描画
    if(s6Split && s6Boss2 && s6Boss2.hp>0){
      const boss2HPRatio=Math.max(0,s6Boss2.hp/s6Boss2.maxHP);
      drawSaturn(s6Boss2.x,s6Boss2.y,s6Boss2.w,s6Boss2.h,boss2HPRatio,true);
    }
  }

  // エフェクト
  hitEffects.forEach(e=>{
    if(e.alpha<=0)return;
    ctx.save(); ctx.globalAlpha=e.alpha;
    if(e.type==="debris"){ ctx.fillStyle=e.color; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill(); }
    else if(e.type==="heal"){ ctx.strokeStyle=e.color; ctx.lineWidth=3; ctx.shadowColor=e.color; ctx.shadowBlur=12; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.font=`bold ${Math.max(8,Math.floor(e.r*0.8))}px sans-serif`; ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.fillText("+",e.x,e.y-Math.max(0,e.r)*1.2); }
    else { ctx.strokeStyle=e.color; ctx.lineWidth=2.5; ctx.shadowColor=e.color; ctx.shadowBlur=14; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.globalAlpha=e.alpha*0.3; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r*0.5),0,Math.PI*2); ctx.fill(); }
    ctx.restore();
  });

  // 宇宙船
  drawSpaceShip(ctx,ship.x,ship.y,ship.w,ship.h);
  if(dodgeActive){
    ctx.save();
    const pulse=Math.sin(Date.now()*0.02)*0.3+0.7;
    ctx.strokeStyle=`rgba(255,255,255,${pulse})`;
    ctx.lineWidth=3;
    ctx.shadowColor="#fff";
    ctx.shadowBlur=20;
    ctx.beginPath();
    ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();
  }
  // 小型機描画
  if(ship.subShips && ship.subShips.length>0){
    ship.subShips.forEach(ss=>{
      const sx=ship.x+ship.w/2+ss.offset-12;
      const sy=ship.y+8;
      drawRVSubShip(ctx,sx,sy,"#4D96FF");
    });
  }

  // HPバー
  const hpRatio=Math.max(0,shootingPlayerHP/shootingPlayerMaxHP);
  const barW=W*0.5,barX=(W-barW)/2,barY=H-14;
  ctx.save();
  ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(barX,barY,barW,8,4); ctx.fill();
  const hpColor=hpRatio>0.5?"#6BCB77":hpRatio>0.25?"#FFD93D":"#FF6B6B";
  ctx.fillStyle=hpColor; ctx.shadowColor=hpColor; ctx.shadowBlur=6;
  ctx.beginPath(); ctx.roundRect(barX,barY,barW*hpRatio,8,4); ctx.fill();
  ctx.restore();

  drawElementBadge(ctx,W,s6PlayerElement);
}

// =============================================
//  STAGE 6 CLEAR
// =============================================
function clearStage6(){
  shootingPhase="clear"; shootingGameActive=false;
  clearInterval(shootingTimerInterval);
  if(s6QuizCountdown) clearInterval(s6QuizCountdown);
  cancelAnimationFrame(shootingAnimFrame);
  removeShootListeners();
  unlockShootingUI();
  const firstClear=!isStage6Cleared();
  if(firstClear){ markStage6Cleared(); diamonds+=20; saveGame(); }
  draw_stage6();
  setTimeout(()=>{
    document.getElementById("spaceArea").innerHTML=`
      <div style="text-align:center;padding:30px 16px">
        <div style="font-size:4rem;margin-bottom:10px">🏆</div>
        <div style="font-family:'Fredoka One',cursive;font-size:2rem;
          background:linear-gradient(90deg,#C8A96E,#4D96FF);
          -webkit-background-clip:text;-webkit-text-fill-color:transparent;
          margin-bottom:8px">STAGE 6 CLEAR!</div>
        ${firstClear
          ?`<div style="font-family:'Fredoka One',cursive;font-size:1.3rem;color:#FFD93D;margin-bottom:6px">💎×20 獲得！</div>`
          :`<div style="font-size:13px;color:rgba(255,255,255,0.4);margin-bottom:6px">※2回目以降クリア報酬なし</div>`}
        <div style="font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:20px">
          🪐 土星を撃破した！<br>
          <span style="font-size:12px;color:rgba(255,255,255,0.4)">
            ※クイズ正解で💎×3（回数無制限）
          </span>
        </div>
        <button onclick="showStage6DeckSelect()"
          style="background:linear-gradient(135deg,#C8A96E,#4D96FF);
            font-size:1rem;padding:14px 28px;margin:6px">
          🔄 もう一度
        </button>
        <br>
        <button onclick="showNormalStageMenu()"
          style="background:rgba(255,255,255,0.08);box-shadow:none;
            font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">
          ← ステージ選択へ
        </button>
      </div>`;
    spawnStars();
  },500);
}

// =============================================
//  STAGE 7
// =============================================
let s7PlayerElement   = "fire";
let s7BossElement     = "thunder";
let s7BossMaxHP       = 25000;
let s7BossATK         = 700;
let s7QuizActive      = false;
let s7QuizAnswer      = "";
let s7QuizZones       = [];
let s7QuizTimer       = 0;
let s7QuizWord        = "";
let s7QuizCountdown   = null;
let s7QuizShown15     = false;
let s7QuizShown30     = false;
let s7QuizShown45     = false;
let s7BossQuizTimer   = 0;
let s7BossPhase       = false;
let s7CometTimer      = 0;
let s7Comets          = [];
let s7AoeTimer        = 0;
let s7AoeActive       = false;
let s7AoeRadius       = 0;
let s7AoeX            = 0;
let s7AoeY            = 0;
let s7AoeLife         = 0;
let s7UShield         = false; // Uつきカードシールド

function showStage7DeckSelect(){
  const pool = owned.filter(c=>c.type==="target1900");
  const grouped = {};
  pool.forEach(c=>{ if(!grouped[c.word]) grouped[c.word]=c; });
  const cards = Object.values(grouped);

  const area = document.getElementById("spaceArea");
  area.innerHTML = `
    <div style="text-align:center;padding:12px">
      <div style="font-family:'Fredoka One',cursive;font-size:1.1rem;
        color:#4D96FF;margin-bottom:8px">⚡ ステージ７ デッキ選択</div>
      <div style="background:rgba(77,150,255,0.1);border:1px solid rgba(77,150,255,0.3);
        border-radius:12px;padding:10px;margin:0 auto 12px;max-width:320px;
        font-size:12px;color:rgba(255,255,255,0.7);text-align:left;line-height:1.8">
        ⚡ <b>ステージ7 特殊ギミック</b><br>
        「U」のつくカードをデッキに入れると被ダメ0.5倍！<br>
        球が壁で3分裂して反射！<br>
        25秒ごとに範囲攻撃！<br>
        彗星に触れるとHP20%回復！<br>
        ⚡ ボス属性：<b style="color:#FFD700">雷属性</b>（地属性が有利！）<br>
        クイズ正解で💎×3獲得！
      </div>
      <div style="font-size:13px;color:#4D96FF;margin-bottom:8px">
        選択: <span id="s7SelectedCount">0</span> / 2
      </div>
      <div id="s7CardPicker"
        style="display:flex;flex-wrap:wrap;justify-content:center;
          gap:8px;margin-bottom:16px"></div>
      <div id="s7SelectedDisplay"
        style="display:flex;justify-content:center;gap:12px;
          margin-bottom:80px;min-height:60px"></div>
      <div style="position:fixed;bottom:70px;right:16px;z-index:1000">
        <button id="s7StartBtn" disabled
          style="background:linear-gradient(135deg,#4D96FF,#C77DFF);
            font-size:1rem;padding:14px 20px;border-radius:20px;
            opacity:0.4;cursor:not-allowed;
            box-shadow:0 4px 20px rgba(0,0,0,0.4)">
          🚀 スタート！
        </button>
      </div>
      <button onclick="showNormalStageMenu()"
        style="background:rgba(255,255,255,0.08);box-shadow:none;
          font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">← 戻る</button>
    </div>`;

  if(cards.length===0){
    document.getElementById("s7CardPicker").innerHTML=
      `<div style="color:rgba(255,255,255,0.4);font-size:13px;padding:20px">
        ターゲット1900カードがありません！
      </div>`;
    return;
  }

  let selected=[];

  function renderPicker(){
    document.getElementById("s7SelectedCount").textContent=selected.length;
    document.getElementById("s7CardPicker").innerHTML=cards.map(c=>{
      const idx=selected.findIndex(s=>s.word===c.word);
      const isSel=idx!==-1;
      const hasU=c.word.toUpperCase().includes("U");
      return `
        <div onclick="s7ToggleCard('${c.word}')"
          style="cursor:pointer;width:95px;padding:10px 6px;border-radius:14px;
            background:${isSel?"rgba(255,217,61,0.2)":"rgba(255,255,255,0.06)"};
            border:2px solid ${isSel?c.elementColor:hasU?"rgba(77,150,255,0.6)":"rgba(255,255,255,0.15)"};
            text-align:center;transition:all 0.15s;position:relative">
          ${isSel?`<div style="position:absolute;top:-6px;right:-6px;
            background:#FFD93D;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#1a1a2e;font-weight:700">${idx+1}</div>`:""}
          ${hasU?`<div style="position:absolute;top:-6px;left:-6px;
            background:#4D96FF;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#fff;font-weight:700">🛡</div>`:""}
          <div style="font-size:1rem">${c.elementLabel.split(" ")[0]}</div>
          <div style="font-family:'Fredoka One',cursive;font-size:0.8rem;color:#fff">
            ${c.word}
          </div>
          <div style="font-size:10px;color:rgba(255,255,255,0.5)">${c.meaning}</div>
          <div style="font-size:10px;color:${c.elementColor}">
            ⚔️${c.atk} ❤️${c.hp}
          </div>
          ${hasU?`<div style="font-size:9px;color:#4D96FF;font-weight:700">🛡 Uシールド</div>`:""}
        </div>`;
    }).join("");

    document.getElementById("s7SelectedDisplay").innerHTML=[0,1].map(i=>{
      const c=selected[i];
      return c
        ?`<div style="background:rgba(255,255,255,0.08);
            border:1px solid ${c.elementColor};border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px">
            <div style="font-size:10px;color:rgba(255,255,255,0.4)">
              ${i===0?"1枚目（メイン）":"2枚目（予備）"}
            </div>
            <div style="font-family:'Fredoka One',cursive;font-size:0.85rem;color:#fff">
              ${c.word}
            </div>
            <div style="font-size:10px;color:${c.elementColor}">
              ⚔️${c.atk} ❤️${c.hp}
            </div>
          </div>`
        :`<div style="background:rgba(255,255,255,0.03);
            border:1px dashed rgba(255,255,255,0.15);border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px;
            color:rgba(255,255,255,0.25);font-size:12px">
            ${i===0?"1枚目":"2枚目"}<br>未選択
          </div>`;
    }).join("");

    const btn=document.getElementById("s7StartBtn");
    btn.disabled=selected.length!==2;
    btn.style.opacity=selected.length===2?"1":"0.4";
    btn.style.cursor=selected.length===2?"pointer":"not-allowed";
  }

  window.s7ToggleCard=function(word){
    const c=cards.find(x=>x.word===word);
    const idx=selected.findIndex(s=>s.word===word);
    if(idx!==-1){ selected.splice(idx,1); }
    else { if(selected.length>=2)return; selected.push(c); }
    renderPicker();
  };

  document.getElementById("s7StartBtn").onclick=()=>{
    if(selected.length<2)return;
    shootingDeck=selected;
    beginStage7();
  };
  renderPicker();
}

// =============================================
//  BEGIN STAGE 7
// =============================================
function beginStage7(){
  const area=document.getElementById("spaceArea");
  area.innerHTML=`
    <div style="position:relative;width:100%;max-width:420px;margin:0 auto">
      <canvas id="shootCanvas"
        style="display:block;width:100%;border-radius:16px;
          background:#000820;touch-action:none"></canvas>
          <div id="shootQuizResult"
  style="position:absolute;bottom:30px;left:50%;transform:translateX(-50%);
    font-family:'Fredoka One',cursive;font-size:1rem;
    background:rgba(0,0,0,0.7);border-radius:12px;padding:6px 16px;
    pointer-events:none;display:none;text-align:center;
    white-space:pre-line;z-index:100;min-width:200px">
</div>
      <button onclick="toggleShootingPause()"
        style="position:absolute;top:8px;right:8px;
          background:rgba(0,0,0,0.5);border:1px solid rgba(255,255,255,0.3);
          color:#fff;font-size:12px;padding:5px 10px;border-radius:8px;
          z-index:2100;cursor:pointer">⏸ ポーズ</button>
      <div id="shootHUD"
        style="position:absolute;top:8px;left:8px;right:8px;
          display:flex;justify-content:space-between;pointer-events:none">
        <div id="shootHP"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#6BCB77;text-shadow:0 0 8px rgba(107,203,119,0.8)">❤️ 0</div>
        <div id="shootTimer"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#FFD93D;text-shadow:0 0 8px rgba(255,217,61,0.8)">⏱ 60</div>
        <div id="shootCard"
          style="font-family:'Fredoka One',cursive;font-size:11px;color:#4D96FF">
          🚀 1枚目
        </div>
      </div>
      <div id="s7ShieldBadge"
        style="position:absolute;top:36px;left:8px;pointer-events:none;
          display:none;font-family:'Fredoka One',cursive;font-size:11px;
          color:#4D96FF;background:rgba(77,150,255,0.2);
          border:1px solid rgba(77,150,255,0.4);border-radius:8px;padding:3px 8px">
        🛡 Uシールド発動中
      </div>
      <div id="shootBossHUD"
        style="position:absolute;top:36px;left:8px;right:8px;
          display:none;pointer-events:none">
        <div style="font-family:'Fredoka One',cursive;font-size:11px;
          color:#4D96FF;text-align:center;margin-bottom:2px">⚡ 天王星</div>
        <div style="background:rgba(0,0,0,0.4);border-radius:8px;
          height:10px;overflow:hidden">
          <div id="shootBossHPBar"
            style="height:100%;
              background:linear-gradient(90deg,#4D96FF,#C77DFF);
              border-radius:8px;transition:width 0.3s;width:100%"></div>
        </div>
      </div>
      <div id="shootMessage"
        style="position:absolute;top:45%;left:50%;
          transform:translate(-50%,-50%);
          font-family:'Fredoka One',cursive;font-size:1.2rem;color:#fff;
          text-align:center;pointer-events:none;
          text-shadow:0 0 20px rgba(255,255,255,0.8);display:none;
          background:rgba(0,0,0,0.6);border-radius:12px;
          padding:8px 16px;white-space:pre-line"></div>
    </div>`;

  shootCanvas=document.getElementById("shootCanvas");
  const maxW=Math.min(420,window.innerWidth-32);
  shootCanvas.width=maxW;
  shootCanvas.height=Math.floor(maxW*1.5);
  shootCtx=shootCanvas.getContext("2d");

  if(shootingTimerInterval){ clearInterval(shootingTimerInterval); shootingTimerInterval=null; }
  if(shootingAnimFrame){ cancelAnimationFrame(shootingAnimFrame); shootingAnimFrame=null; }

  shootingCurrentCard=0; shootingPhase="survival"; shootingTime=60;
  shipBullets=[]; meteors=[]; hitEffects=[];
  bulletTimer=0; meteorTimer=0; bossTimer=0;
  boss.bullets=[]; boss.hp=s7BossMaxHP; boss.vx=2.8;
  shootingBossActive=false; lastFrameTime=0;
  s7Comets=[]; s7CometTimer=0; s7AoeTimer=0;
  s7AoeActive=false; s7AoeLife=0;

  s7QuizActive=false; s7QuizShown15=false; s7QuizShown30=false; s7QuizShown45=false;
  s7BossPhase=false; s7BossQuizTimer=0; s7QuizZones=[];
  if(s7QuizCountdown){ clearInterval(s7QuizCountdown); s7QuizCountdown=null; }

  const c=shootingDeck[0];
  shootingPlayerMaxHP=c.hp; shootingPlayerHP=c.hp; shootingPlayerATK=c.atk;
  s7PlayerElement=c.element;

  // Uシールドチェック
  s7UShield=shootingDeck.some(card=>card.word.toUpperCase().includes("U"));
  const badge=document.getElementById("s7ShieldBadge");
  if(badge) badge.style.display=s7UShield?"block":"none";

  ship.x=shootCanvas.width/2-ship.w/2;
  ship.y=shootCanvas.height-ship.h-20;

  shootCanvas.addEventListener("touchstart",onShootTouchStart,{passive:false});
  shootCanvas.addEventListener("touchmove", onShootTouchMove, {passive:false});
  shootCanvas.addEventListener("touchend",  onShootTouchEnd,  {passive:false});
  shootCanvas.addEventListener("mousedown", onShootMouseDown);
  shootCanvas.addEventListener("mousemove", onShootMouseMove);
  shootCanvas.addEventListener("mouseup",   onShootMouseUp);

  shootingPaused=false;
  // 小型機チェック
  const subUnlocked = localStorage.getItem("subShipUnlocked")==="true";
  if(subUnlocked){
    ship.subShips = [{offset:-35},{offset:35}];
  } else {
    ship.subShips = [];
  }
  currentShootingStage="stage7";

  shootingTimerInterval=setInterval(()=>{
    if(shootingPhase!=="survival")return;
    shootingTime--;
    updateShootHUD();
    if(shootingTime===45&&!s7QuizShown15){ s7QuizShown15=true; triggerS7Quiz(); }
    if(shootingTime===30&&!s7QuizShown30){ s7QuizShown30=true; triggerS7Quiz(); }
    if(shootingTime===15&&!s7QuizShown45){ s7QuizShown45=true; triggerS7Quiz(); }
    if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS7BossPhase(); }
  },1000);

  shootingGameActive=true;
  lockShootingUI();
  dodgeUnlocked = localStorage.getItem("dodgeUnlocked")==="true";
  dodgeCooldown = 0;
  dodgeActive   = false;
  dodgeActiveTimer = 0;
  renderDodgeButton();
  updateShootHUD();
  requestAnimationFrame(stage7Loop);
}

// =============================================
//  STAGE 7 BOSS PHASE
// =============================================
function startS7BossPhase(){
  shootingPhase="boss"; s7BossPhase=true; shootingBossActive=true;
  boss.x=shootCanvas.width/2-boss.w/2; boss.y=60;
  boss.hp=s7BossMaxHP; boss.vx=2.8; boss.bullets=[];
  meteors=[]; bossTimer=0; s7BossQuizTimer=0;
  s7CometTimer=0; s7AoeTimer=0; s7AoeActive=false;
  const bossHUD=document.getElementById("shootBossHUD");
  if(bossHUD) bossHUD.style.display="block";
  // シールドバッジを非表示に
  const badge=document.getElementById("s7ShieldBadge");
  if(badge) badge.style.display="none";
  showShootMessage("⚡ 天王星 出現！\n壁で弾が分裂するぞ！",2500);
  updateBossHUD();
}

// =============================================
//  STAGE 7 LOOP
// =============================================
function stage7Loop(timestamp){
  if(!shootingGameActive)return;
  const dt=Math.min((timestamp-(lastFrameTime||timestamp))/16.67,3);
  lastFrameTime=timestamp;
  update_stage7(dt);
  draw_stage7();
  shootingAnimFrame=requestAnimationFrame(stage7Loop);
}

// =============================================
//  UPDATE STAGE 7
// =============================================
function update_stage7(dt){
  const W=shootCanvas.width, H=shootCanvas.height;
  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  hitEffects.forEach(e=>{
    e.life+=dt; e.alpha=Math.max(0,1-e.life/e.maxLife);
    if(e.type==="debris"){ e.x+=(e.vx||0)*dt; e.y+=(e.vy||0)*dt; e.r=Math.max(0,e.r-0.15*dt); }
    else { e.r+=(e.maxR-e.r)*0.18*dt; }
  });
  hitEffects=hitEffects.filter(e=>e.life<e.maxLife);
  // 回避・無敵タイマー更新
  if(dodgeActive){
    dodgeActiveTimer-=dt;
    if(dodgeActiveTimer<=0){
      dodgeActive=false;
      dodgeCooldown=600; // 10秒（600フレーム）
    }
  }
  if(dodgeCooldown>0){
    dodgeCooldown-=dt;
    if(dodgeCooldown<0) dodgeCooldown=0;
    updateDodgeButton();
  }
  if(dodgeActive) updateDodgeButton();

  // 弾発射　←この行の直後（全ステージ共通）
  bulletTimer+=dt;
  if(bulletTimer>=60){
    bulletTimer=0;
    // メイン弾
    shipBullets.push({x:ship.x+ship.w/2-4,y:ship.y-10,w:8,h:14,active:true});
    // 小型機の弾
    if(ship.subShips && ship.subShips.length>0){
      ship.subShips.forEach(ss=>{
        const angle=15*Math.PI/180;
        const dir=ss.offset<0?-1:1;
        shipBullets.push({
          x:ship.x+ship.w/2+ss.offset-4,
          y:ship.y-10,
          w:6, h:10,
          vx:Math.sin(angle)*4*dir,
          vy:-Math.cos(angle)*8,
          active:true,
          isSub:true,
        });
      });
    }
  }
  shipBullets.forEach(b=>{
    b.x+=(b.vx||0)*dt;
    b.y+=(b.vy||-8)*dt;
  });
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

  // 彗星更新（両フェーズ共通）　←この行の直後
  s7CometTimer+=dt;
  if(s7CometTimer>=1500){
    s7CometTimer=0;
    const fromLeft=Math.random()<0.5;
    const minY = shootingPhase==="boss" ? boss.y+boss.h+20 : H*0.1;
    const maxY = H*0.8;
    s7Comets.push({
      x: fromLeft ? -40 : W+40,
      y: minY+Math.random()*(maxY-minY),
      w:40, h:20,
      vx: fromLeft ? 3.5 : -3.5,
      life:0, maxLife:400,
    });
  }
  s7Comets.forEach(c=>{ c.x+=c.vx*dt; c.life+=dt; });

  // 彗星 vs プレイヤー（回復）
  for(let i=s7Comets.length-1;i>=0;i--){
    const c=s7Comets[i];
    if(rectsOverlap({x:c.x-c.w/2,y:c.y-c.h/2,w:c.w,h:c.h},ship)){
      const heal=Math.floor(shootingPlayerMaxHP*0.2);
      shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
      spawnHealEffect(ship.x+ship.w/2,ship.y);
      showShootMessage("☄️ 彗星！HP+20%！",1500);
      updateShootHUD();
      s7Comets.splice(i,1);
    }
  }
  s7Comets=s7Comets.filter(c=>c.life<c.maxLife&&c.x>-100&&c.x<W+100);

  // 範囲攻撃更新　←この行の直後
  if(s7AoeActive){
    s7AoeLife+=dt;
    // 3秒（180フレーム）かけて広がる
    s7AoeRadius = (s7AoeLife/180) * 150;

    // 3秒後（180フレーム）に爆発判定
    if(s7AoeLife>=180){
      const dx=(ship.x+ship.w/2)-s7AoeX;
      const dy=(ship.y+ship.h/2)-s7AoeY;
      const dist=Math.sqrt(dx*dx+dy*dy);
      if(dist<150){
        const mult=getElementMultiplier(s7BossElement,s7PlayerElement);
        let dmg=Math.floor(s7BossATK*1.5*mult);
        if(s7UShield) dmg=Math.floor(dmg*0.5);
        
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#C77DFF");
        if(applyPlayerDamage(dmg, true)) return;
      }
      s7AoeActive=false;
    }
  }

  if(shootingPhase==="survival"){
    // 通常隕石＋巨大隕石
    meteorTimer+=dt;
    if(meteorTimer>=40+Math.random()*20){
      meteorTimer=0;
      const isBig=Math.random()<0.15;
        const mw=isBig?80+Math.random()*30:30+Math.random()*20;
        const mh=isBig?80+Math.random()*30:30+Math.random()*20;
        meteors.push({
          x:Math.random()*(W-mw), y:-mh,
          w:mw, h:mh,
          vy:isBig?1.5+Math.random():2.5+Math.random()*2,
          hp:isBig?4:2,  // 6→4に変更
          isBig,
          id:Date.now()+Math.random()
        });
    }
    meteors.forEach(m=>{ m.y+=m.vy*dt; });

    // 自弾 vs 隕石
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let mi=meteors.length-1;mi>=0;mi--){
        const m=meteors[mi]; if(m.hp<=0)continue;
        if(rectsOverlap(b,m)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#4D96FF");
          b.active=false; m.hp--;
          if(m.hp<=0){
            spawnMeteorBreakEffect(m.x+m.w/2,m.y+m.h/2);
            const heal=Math.floor(shootingPlayerMaxHP*(m.isBig?0.03:0.015));
            shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
            spawnHealEffect(ship.x+ship.w/2,ship.y);
            updateShootHUD(); meteors.splice(mi,1);
          }
          break;
        }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
    meteors=meteors.filter(m=>m.hp>0&&m.y<H+100);

    // 隕石 vs プレイヤー
    for(let mi=meteors.length-1;mi>=0;mi--){
      const m=meteors[mi];
      if(rectsOverlap(ship,m)){
        meteors.splice(mi,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        let dmg=m.isBig?600:350;
        if(s7UShield) dmg=Math.floor(dmg*0.5);
        if(applyPlayerDamage(dmg, true)) return;
      }
    }

  } else if(shootingPhase==="boss"){
    boss.x+=boss.vx*dt;
    if(boss.x<=10){ boss.x=10; boss.vx=Math.abs(boss.vx); }
    if(boss.x+boss.w>=W-10){ boss.x=W-boss.w-10; boss.vx=-Math.abs(boss.vx); }
    const minY=boss.y+boss.h+10;
    if(ship.y<minY) ship.y=minY;

    // ボスクイズ
    s7BossQuizTimer+=dt;
    if(s7BossQuizTimer>=1200){ s7BossQuizTimer=0; if(!s7QuizActive) triggerS7Quiz(); }

    // 範囲攻撃タイマー（25秒=1500フレーム）　←この行の直後
    s7AoeTimer+=dt;
    if(s7AoeTimer>=1500){
      s7AoeTimer=0;
      if(!s7AoeActive){
        s7AoeActive=true;
        s7AoeRadius=0;
        s7AoeLife=0;
        s7AoeX=ship.x+ship.w/2;
        s7AoeY=ship.y+ship.h/2;
        showShootMessage("⚡ 範囲攻撃！3秒以内に逃げろ！",1500);
      }
    }

    // ボス攻撃
    bossTimer+=dt;
    if(bossTimer>=100+Math.random()*80){
      bossTimer=0;
      const bx=boss.x+boss.w/2, by=boss.y+boss.h;
      const roll=Math.random();
      if(roll<0.5){
        // 通常弾（壁で3分裂）
        boss.bullets.push({
          x:bx-10, y:by,
          w:20, h:20,
          vx:(Math.random()-0.5)*3,
          vy:4,
          active:true,
          canSplit:true,
          splitCount:0,
        });
         } else {
        // 大きな球1つ（壁で3分裂）
        boss.bullets.push({
          x:bx-20, y:by,
          w:40, h:40,
          vx:(Math.random()-0.5)*2,
          vy:3.5,
          active:true,
          canSplit:true,
          splitCount:0,
          isBig:true,
        });
      }
    }

    // ボス弾移動＆壁反射・分裂
    const newBullets=[];
    boss.bullets.forEach(b=>{
      b.x+=b.vx*dt; b.y+=b.vy*dt;

      // 壁に当たったら分裂
      if(b.canSplit&&b.splitCount<1){
        const hitWall=(b.x<=0||b.x+b.w>=W||b.y+b.h>=H);
        if(hitWall){
          b.active=false;
          const angles=[-0.5,0,0.5];
          angles.forEach(a=>{
            let newVx=-b.vx+a*3;
            let newVy=b.y+b.h>=H ? -Math.abs(b.vy)*0.9 : Math.abs(b.vy)*0.9;
            newBullets.push({
              x:b.x, y:b.y,
              w:14, h:14,
              vx:newVx,
              vy:newVy,
              active:true,
              canSplit:false,
              splitCount:1,
              isSplit:true,
            });
          });
        }
      } else {
        if(b.x<=0){ b.x=1; b.vx=Math.abs(b.vx); }
        if(b.x+b.w>=W){ b.x=W-b.w-1; b.vx=-Math.abs(b.vx); }
        if(b.y+b.h>=H){ b.y=H-b.h-1; b.vy=-Math.abs(b.vy); }
      }
    });
    boss.bullets=[...boss.bullets,...newBullets];

    // ボス弾 vs プレイヤー
    for(let i=boss.bullets.length-1;i>=0;i--){
      const b=boss.bullets[i]; if(!b.active)continue;
      if(rectsOverlap(b,ship)){
        boss.bullets.splice(i,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#4D96FF");
        const mult=getElementMultiplier(s7BossElement,s7PlayerElement);
        let dmg=Math.floor(s7BossATK*(b.isSplit?0.6:1)*mult);
        if(s7UShield) dmg=Math.floor(dmg*0.5);
        if(applyPlayerDamage(dmg, true)) return;
        
      }
    }
    boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+50&&b.x>-50&&b.x<W+50);

    // 自弾 vs ボス
    const bossRect={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      if(rectsOverlap(b,bossRect)){
        spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
        b.active=false;
        const mult=getElementMultiplier(s7PlayerElement,s7BossElement);
        boss.hp-=Math.floor(shootingPlayerATK*mult);
        if(boss.hp<0) boss.hp=0;
        updateBossHUD();
        if(boss.hp<=0){ clearStage7(); return; }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
  }
}

// =============================================
//  STAGE 7 QUIZ
// =============================================
function triggerS7Quiz(){
  if(s7QuizActive)return;
  s7QuizActive=true;
  const card=target1900Cards[Math.floor(Math.random()*target1900Cards.length)];
  const q=card.quizzes[Math.floor(Math.random()*card.quizzes.length)];
  s7QuizAnswer=q.correct;
  s7QuizWord=card.word;
  const wrongs=q.choices.sort(()=>Math.random()-0.5).slice(0,3);
  const allChoices=[...wrongs,q.correct].sort(()=>Math.random()-0.5);
  const W=shootCanvas.width, H=shootCanvas.height;
  const zoneTop=H*0.55, zoneH=(H-zoneTop-20)/2, zoneW=W/2-8;
  s7QuizZones=[
    {label:allChoices[0],x:4,     y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[1],x:W/2+4, y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[2],x:4,     y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
    {label:allChoices[3],x:W/2+4, y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
  ];
  s7QuizTimer=5;
  if(s7QuizCountdown) clearInterval(s7QuizCountdown);
  s7QuizCountdown=setInterval(()=>{
    s7QuizTimer--;
    if(s7QuizTimer<=0){ clearInterval(s7QuizCountdown); s7QuizCountdown=null; judgeS7Quiz(); }
  },1000);
}

function judgeS7Quiz(){
  s7QuizActive=false;
  const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
  let chosen=null;
  for(const z of s7QuizZones){ if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){ chosen=z.label; break; } }
  s7QuizZones=[];
  if(chosen===s7QuizAnswer){  // ← 各ステージの変数名に合わせる
    diamonds+=3; saveGame();
    showQuizResult(true,"");
  } else {
    shootingPlayerHP-=600; updateShootHUD();
    showQuizResult(false, s7QuizAnswer); // ← 各ステージの変数名に合わせる
    const wrongCard=target1900Cards.find(c=>c.word===s7QuizWord);
    if(wrongCard) recordWrongWord("target1900", wrongCard.word, wrongCard.meaning);
    if(shootingPlayerHP<=0) handlePlayerDeath();
  }
}

// =============================================
//  DRAW STAGE 7
// =============================================
function draw_stage7(){
  const ctx=shootCtx, W=shootCanvas.width, H=shootCanvas.height;
  ctx.fillStyle="#000820"; ctx.fillRect(0,0,W,H);

  // 星（青白い）
  for(let i=0;i<80;i++){
    ctx.fillStyle=`rgba(${150+((i*37)%80)},${180+((i*53)%60)},255,${0.3+((i*73)%100)/100*0.4})`;
    ctx.fillRect((i*137+50)%W,(i*97+30)%H,1.5,1.5);
  }
  // 青い霧
  const nebula=ctx.createRadialGradient(W*0.5,H*0.3,0,W*0.5,H*0.3,W*0.6);
  nebula.addColorStop(0,"rgba(30,80,200,0.08)");
  nebula.addColorStop(1,"rgba(0,0,0,0)");
  ctx.fillStyle=nebula; ctx.fillRect(0,0,W,H);

  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // 彗星描画
  s7Comets.forEach(c=>{
    ctx.save();
    const alpha=Math.min(1,Math.min(c.life/20,(c.maxLife-c.life)/20));
    ctx.globalAlpha=alpha;
    // 尾
    const tailLen=60;
    const tailDir=c.vx>0?-1:1;
    const grad=ctx.createLinearGradient(c.x,c.y,c.x+tailDir*tailLen,c.y);
    grad.addColorStop(0,"rgba(107,203,119,0.8)");
    grad.addColorStop(1,"rgba(107,203,119,0)");
    ctx.fillStyle=grad;
    ctx.beginPath();
    ctx.moveTo(c.x,c.y-5);
    ctx.lineTo(c.x+tailDir*tailLen,c.y);
    ctx.lineTo(c.x,c.y+5);
    ctx.closePath(); ctx.fill();
    // 本体
    ctx.fillStyle="#6BCB77"; ctx.shadowColor="#6BCB77"; ctx.shadowBlur=16;
    ctx.beginPath(); ctx.arc(c.x,c.y,10,0,Math.PI*2); ctx.fill();
    ctx.fillStyle="#fff"; ctx.shadowBlur=0;
    ctx.beginPath(); ctx.arc(c.x-2,c.y-2,4,0,Math.PI*2); ctx.fill();
    ctx.restore();
  });

  // 範囲攻撃エフェクト　←この行の直後
  if(s7AoeActive){
    ctx.save();
    const progress=s7AoeLife/180;
    // 3秒間は警告色、爆発直前は赤くなる
    const r=Math.floor(150+progress*100);
    const warningColor=`rgba(${r},50,255,0.7)`;
    ctx.strokeStyle=warningColor; ctx.lineWidth=4;
    ctx.shadowColor=warningColor; ctx.shadowBlur=20;
    ctx.beginPath(); ctx.arc(s7AoeX,s7AoeY,s7AoeRadius,0,Math.PI*2); ctx.stroke();
    ctx.fillStyle=`rgba(${r},50,255,${0.05+progress*0.1})`;
    ctx.beginPath(); ctx.arc(s7AoeX,s7AoeY,s7AoeRadius,0,Math.PI*2); ctx.fill();
    // カウントダウン表示
    const countdown=Math.ceil((180-s7AoeLife)/60);
    ctx.fillStyle=warningColor;
    ctx.font=`bold ${Math.floor(W*0.06)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.shadowBlur=16;
    ctx.fillText(countdown>0?countdown:"💥",s7AoeX,s7AoeY);
    ctx.restore();
  }

  // 隕石
  meteors.forEach(m=>{
    ctx.save();
    if(m.isBig){
      ctx.fillStyle="#2A3A6A"; ctx.shadowColor="rgba(77,150,255,0.5)"; ctx.shadowBlur=12;
      ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
      ctx.fillStyle="#1A2A5A"; ctx.shadowBlur=0;
      [[0.3,0.3,0.12],[0.6,0.55,0.08],[0.45,0.7,0.06]].forEach(([rx,ry,rs])=>{
        ctx.beginPath(); ctx.arc(m.x+m.w*rx,m.y+m.h*ry,m.w*rs,0,Math.PI*2); ctx.fill();
      });
      // HPゲージ
      const hpR=m.hp/6;
      ctx.fillStyle="rgba(0,0,0,0.4)";
      ctx.beginPath(); ctx.roundRect(m.x,m.y-10,m.w,6,3); ctx.fill();
      ctx.fillStyle="#4D96FF";
      ctx.beginPath(); ctx.roundRect(m.x,m.y-10,m.w*hpR,6,3); ctx.fill();
    } else {
      ctx.fillStyle="#2A3060"; ctx.shadowColor="rgba(77,100,200,0.4)"; ctx.shadowBlur=6;
      ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    }
    ctx.restore();
  });

  // クイズゾーン
  if(s7QuizActive&&s7QuizZones.length>0){
    ctx.save();
    ctx.fillStyle="rgba(0,0,0,0.82)";
    ctx.beginPath(); ctx.roundRect(W*0.03,H*0.47,W*0.94,46,8); ctx.fill();
    ctx.fillStyle="#4D96FF"; ctx.font=`bold ${Math.floor(W*0.034)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText(`「${s7QuizWord}」の意味は？`,W/2,H*0.47+16);
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.font=`${Math.floor(W*0.028)}px sans-serif`;
    ctx.fillText(`⏱ ${s7QuizTimer}秒 いるゾーンが回答！`,W/2,H*0.47+34);
    ctx.restore();

    const zoneColors=["rgba(77,150,255,0.3)","rgba(199,125,255,0.3)","rgba(107,203,119,0.3)","rgba(255,217,61,0.3)"];
    const zoneBorders=["#4D96FF","#C77DFF","#6BCB77","#FFD93D"];
    s7QuizZones.forEach((z,i)=>{
      ctx.save();
      ctx.fillStyle=zoneColors[i%4]; ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=2;
      ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.fill(); ctx.stroke();
      ctx.fillStyle="#fff"; ctx.textAlign="center"; ctx.textBaseline="middle";
      const fs=Math.floor(W*0.026); ctx.font=`bold ${fs}px sans-serif`;
      const lines=wrapText(ctx,z.label,z.w-14,fs);
      const lh=fs+3, sy=z.y+z.h/2-(lines.length-1)*lh/2;
      lines.forEach((l,li)=>ctx.fillText(l,z.x+z.w/2,sy+li*lh));
      const cx2=ship.x+ship.w/2, cy2=ship.y+ship.h/2;
      if(cx2>=z.x&&cx2<=z.x+z.w&&cy2>=z.y&&cy2<=z.y+z.h){
        ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=4;
        ctx.shadowColor=zoneBorders[i%4]; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.stroke();
      }
      ctx.restore();
    });
  }

  // 自弾
  shipBullets.forEach(b=>{
    if(!b.active)return;
    ctx.save();
    const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+b.h);
    g.addColorStop(0,"#fff"); g.addColorStop(1,"#4D96FF");
    ctx.fillStyle=g; ctx.shadowColor="#4D96FF"; ctx.shadowBlur=10;
    ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h,4); ctx.fill();
    ctx.restore();
  });

  // ボスフェーズ
  if(shootingPhase==="boss"){
    // ボス弾　←この行の直後
      boss.bullets.forEach(b=>{
        if(!b.active)return;
        ctx.save();
        if(b.isSplit){
          ctx.fillStyle="#C77DFF"; ctx.shadowColor="#C77DFF"; ctx.shadowBlur=14;
        } else if(b.isBig){
          // 大きな球は虹色っぽく
          const bg=ctx.createRadialGradient(b.x+b.w/2,b.y+b.h/2,2,b.x+b.w/2,b.y+b.h/2,b.w/2);
          bg.addColorStop(0,"#fff");
          bg.addColorStop(0.4,"#4D96FF");
          bg.addColorStop(1,"rgba(199,125,255,0.6)");
          ctx.fillStyle=bg; ctx.shadowColor="#4D96FF"; ctx.shadowBlur=20;
        } else {
          ctx.fillStyle="#4D96FF"; ctx.shadowColor="#4D96FF"; ctx.shadowBlur=14;
        }
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
        if(!b.isSplit&&!b.isBig){
          ctx.fillStyle="rgba(255,255,255,0.4)";
          ctx.beginPath(); ctx.arc(b.x+b.w/2-2,b.y+b.h/2-2,b.w*0.2,0,Math.PI*2); ctx.fill();
        }
        ctx.restore();
      });

    // 天王星ボス
    const bossHPRatio=Math.max(0,boss.hp/s7BossMaxHP);
    ctx.save();
    ctx.shadowColor="rgba(77,150,255,0.9)"; ctx.shadowBlur=25+(1-bossHPRatio)*30;

    // リング（後ろ）
    ctx.save();
    ctx.strokeStyle="rgba(77,150,255,0.4)"; ctx.lineWidth=14;
    ctx.shadowColor="rgba(77,150,255,0.3)"; ctx.shadowBlur=10;
    ctx.beginPath();
    ctx.ellipse(boss.x+boss.w/2,boss.y+boss.h/2,boss.w*0.85,boss.h*0.18,0.3,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();

    // 本体（青白い天王星）
    const pg=ctx.createRadialGradient(
      boss.x+boss.w*0.38,boss.y+boss.h*0.32,boss.w*0.05,
      boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2
    );
    pg.addColorStop(0,"#C0E8FF");
    pg.addColorStop(0.4,"#60B8F0");
    pg.addColorStop(0.8,"#2060A0");
    pg.addColorStop(1,"#103060");
    ctx.fillStyle=pg;
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.fill();

    // 縞模様（薄め）
    ctx.save();
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.clip();
    [{y:0.25,h:0.06,c:"rgba(100,180,255,0.3)"},{y:0.45,h:0.08,c:"rgba(80,150,220,0.3)"},{y:0.65,h:0.06,c:"rgba(100,180,255,0.25)"}].forEach(s=>{
      ctx.fillStyle=s.c; ctx.fillRect(boss.x,boss.y+boss.h*s.y,boss.w,boss.h*s.h);
    });
    ctx.restore();

    // リング（前）
    ctx.save();
    ctx.strokeStyle="rgba(77,150,255,0.7)"; ctx.lineWidth=10;
    ctx.shadowColor="rgba(77,150,255,0.5)"; ctx.shadowBlur=12;
    ctx.beginPath();
    ctx.ellipse(boss.x+boss.w/2,boss.y+boss.h/2,boss.w*0.85,boss.h*0.18,0.3,Math.PI,Math.PI*2);
    ctx.stroke();
    ctx.restore();

    // HP低下でひび
    if(bossHPRatio<0.5){
      ctx.strokeStyle=`rgba(150,200,255,${0.5+(1-bossHPRatio)*0.5})`; ctx.lineWidth=2; ctx.shadowBlur=0;
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.3,boss.y+boss.h*0.1); ctx.lineTo(boss.x+boss.w*0.5,boss.y+boss.h*0.5); ctx.lineTo(boss.x+boss.w*0.72,boss.y+boss.h*0.88); ctx.stroke();
    }
    ctx.restore();
  }

  // エフェクト
  hitEffects.forEach(e=>{
    if(e.alpha<=0)return;
    ctx.save(); ctx.globalAlpha=e.alpha;
    if(e.type==="debris"){ ctx.fillStyle=e.color; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill(); }
    else if(e.type==="heal"){ ctx.strokeStyle=e.color; ctx.lineWidth=3; ctx.shadowColor=e.color; ctx.shadowBlur=12; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.font=`bold ${Math.max(8,Math.floor(e.r*0.8))}px sans-serif`; ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.fillText("+",e.x,e.y-Math.max(0,e.r)*1.2); }
    else { ctx.strokeStyle=e.color; ctx.lineWidth=2.5; ctx.shadowColor=e.color; ctx.shadowBlur=14; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.globalAlpha=e.alpha*0.3; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r*0.5),0,Math.PI*2); ctx.fill(); }
    ctx.restore();
  });

  // 宇宙船
  drawSpaceShip(ctx,ship.x,ship.y,ship.w,ship.h);
  if(dodgeActive){
    ctx.save();
    const pulse=Math.sin(Date.now()*0.02)*0.3+0.7;
    ctx.strokeStyle=`rgba(255,255,255,${pulse})`;
    ctx.lineWidth=3;
    ctx.shadowColor="#fff";
    ctx.shadowBlur=20;
    ctx.beginPath();
    ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();
  }
  // 小型機描画
  if(ship.subShips && ship.subShips.length>0){
    ship.subShips.forEach(ss=>{
      const sx=ship.x+ship.w/2+ss.offset-12;
      const sy=ship.y+8;
      drawRVSubShip(ctx,sx,sy,"#4D96FF");
    });
  }
  // Uシールド発動中は船に青いオーラ
  if(s7UShield && shootingPhase==="survival"){
    ctx.save();
    ctx.strokeStyle="rgba(77,150,255,0.5)"; ctx.lineWidth=3;
    ctx.shadowColor="#4D96FF"; ctx.shadowBlur=14;
    ctx.beginPath(); ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2); ctx.stroke();
    ctx.restore();
  }

  // HPバー
  const hpRatio=Math.max(0,shootingPlayerHP/shootingPlayerMaxHP);
  const barW=W*0.5,barX=(W-barW)/2,barY=H-14;
  ctx.save();
  ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(barX,barY,barW,8,4); ctx.fill();
  const hpColor=hpRatio>0.5?"#6BCB77":hpRatio>0.25?"#FFD93D":"#FF6B6B";
  ctx.fillStyle=hpColor; ctx.shadowColor=hpColor; ctx.shadowBlur=6;
  ctx.beginPath(); ctx.roundRect(barX,barY,barW*hpRatio,8,4); ctx.fill();
  ctx.restore();

  drawElementBadge(ctx,W,s7PlayerElement);
}

// =============================================
//  STAGE 7 CLEAR
// =============================================
function clearStage7(){
  shootingPhase="clear"; shootingGameActive=false;
  clearInterval(shootingTimerInterval);
  if(s7QuizCountdown) clearInterval(s7QuizCountdown);
  cancelAnimationFrame(shootingAnimFrame);
  removeShootListeners();
  unlockShootingUI();
  const firstClear=!isStage7Cleared();
  if(firstClear){ 
    markStage7Cleared(); 
    diamonds+=20; 
    // 小型機アンロック
    localStorage.setItem("subShipUnlocked","true");
    saveGame(); 
  }
  draw_stage7();
  setTimeout(()=>{
    document.getElementById("spaceArea").innerHTML=`
      <div style="text-align:center;padding:30px 16px">
        <div style="font-size:4rem;margin-bottom:10px">🏆</div>
        <div style="font-family:'Fredoka One',cursive;font-size:2rem;
          background:linear-gradient(90deg,#4D96FF,#C77DFF);
          -webkit-background-clip:text;-webkit-text-fill-color:transparent;
          margin-bottom:8px">STAGE 7 CLEAR!</div>
        ${firstClear
          ?`<div style="font-family:'Fredoka One',cursive;font-size:1.3rem;color:#FFD93D;margin-bottom:6px">💎×20 獲得！</div>`
          :`<div style="font-size:13px;color:rgba(255,255,255,0.4);margin-bottom:6px">※2回目以降クリア報酬なし</div>`}
        <div style="font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:20px">
          ⚡ 天王星を撃破した！<br>
          <span style="font-size:12px;color:rgba(255,255,255,0.4)">
            ※クイズ正解で💎×3（回数無制限）
          </span>
        </div>
        <button onclick="showStage7DeckSelect()"
          style="background:linear-gradient(135deg,#4D96FF,#C77DFF);
            font-size:1rem;padding:14px 28px;margin:6px">
          🔄 もう一度
        </button>
        <br>
        <button onclick="showNormalStageMenu()"
          style="background:rgba(255,255,255,0.08);box-shadow:none;
            font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">
          ← ステージ選択へ
        </button>
      </div>`;
    spawnStars();
  },500);
}

// =============================================
//  STAGE 8
// =============================================
let s8PlayerElement  = "fire";
let s8BossElement    = "water";
let s8BossMaxHP      = 40000;
let s8BossATK        = 800;
let s8QuizActive     = false;
let s8QuizAnswer     = "";
let s8QuizZones      = [];
let s8QuizTimer      = 0;
let s8QuizWord       = "";
let s8QuizCountdown  = null;
let s8QuizShown15    = false;
let s8QuizShown30    = false;
let s8QuizShown45    = false;
let s8BossQuizTimer  = 0;
let s8BossPhase      = false;
let s8NShield        = false;
let s8CometTimer     = 0;
let s8Comets         = [];
let s8Rods           = []; // 回転する細長い物体
let s8RodTimer       = 0;
let s8SuckActive     = false; // 吸い寄せ
let s8SuckTimer      = 0;
let s8SuckPhase      = 0; // 0=なし 1=吸い寄せ中 2=範囲攻撃
let s8SuckLife       = 0;
let s8AoeRadius      = 0;
let s8SuckWall = "left"; // ←s8AoeRadius の下に追加

function showStage8DeckSelect(){
  const pool = owned.filter(c=>c.type==="target1900");
  const grouped = {};
  pool.forEach(c=>{ if(!grouped[c.word]) grouped[c.word]=c; });
  const cards = Object.values(grouped);

  const area = document.getElementById("spaceArea");
  area.innerHTML = `
    <div style="text-align:center;padding:12px">
      <div style="font-family:'Fredoka One',cursive;font-size:1.1rem;
        color:#00BFFF;margin-bottom:8px"> ステージ８ デッキ選択</div>
      <div style="background:rgba(0,191,255,0.1);border:1px solid rgba(0,191,255,0.3);
        border-radius:12px;padding:10px;margin:0 auto 12px;max-width:320px;
        font-size:12px;color:rgba(255,255,255,0.7);text-align:left;line-height:1.8">
         <b>ステージ8 特殊ギミック</b><br>
        「N」のつくカードで被ダメ0.5倍！<br>
        吸い寄せ→範囲攻撃に要注意！<br>
        回転する細長い障害物が落下！<br>
        彗星でHP回復！<br>
        💧 ボス属性：<b style="color:#00BFFF">水属性</b>（雷属性が有利！）<br>
        クイズ正解で💎×3獲得！
      </div>
      <div style="font-size:13px;color:#00BFFF;margin-bottom:8px">
        選択: <span id="s8SelectedCount">0</span> / 2
      </div>
      <div id="s8CardPicker"
        style="display:flex;flex-wrap:wrap;justify-content:center;
          gap:8px;margin-bottom:16px"></div>
      <div id="s8SelectedDisplay"
        style="display:flex;justify-content:center;gap:12px;
          margin-bottom:80px;min-height:60px"></div>
      <div style="position:fixed;bottom:70px;right:16px;z-index:1000">
        <button id="s8StartBtn" disabled
          style="background:linear-gradient(135deg,#00BFFF,#4D96FF);
            font-size:1rem;padding:14px 20px;border-radius:20px;
            opacity:0.4;cursor:not-allowed;
            box-shadow:0 4px 20px rgba(0,0,0,0.4)">
          🚀 スタート！
        </button>
      </div>
      <button onclick="showNormalStageMenu()"
        style="background:rgba(255,255,255,0.08);box-shadow:none;
          font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">← 戻る</button>
    </div>`;

  if(cards.length===0){
    document.getElementById("s8CardPicker").innerHTML=
      `<div style="color:rgba(255,255,255,0.4);font-size:13px;padding:20px">
        ターゲット1900カードがありません！
      </div>`;
    return;
  }

  let selected=[];

  function renderPicker(){
    document.getElementById("s8SelectedCount").textContent=selected.length;
    document.getElementById("s8CardPicker").innerHTML=cards.map(c=>{
      const idx=selected.findIndex(s=>s.word===c.word);
      const isSel=idx!==-1;
      const hasN=c.word.toUpperCase().includes("N");
      return `
        <div onclick="s8ToggleCard('${c.word}')"
          style="cursor:pointer;width:95px;padding:10px 6px;border-radius:14px;
            background:${isSel?"rgba(255,217,61,0.2)":"rgba(255,255,255,0.06)"};
            border:2px solid ${isSel?c.elementColor:hasN?"rgba(0,191,255,0.6)":"rgba(255,255,255,0.15)"};
            text-align:center;transition:all 0.15s;position:relative">
          ${isSel?`<div style="position:absolute;top:-6px;right:-6px;
            background:#FFD93D;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#1a1a2e;font-weight:700">${idx+1}</div>`:""}
          ${hasN?`<div style="position:absolute;top:-6px;left:-6px;
            background:#00BFFF;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#fff;font-weight:700">🛡</div>`:""}
          <div style="font-size:1rem">${c.elementLabel.split(" ")[0]}</div>
          <div style="font-family:'Fredoka One',cursive;font-size:0.8rem;color:#fff">
            ${c.word}
          </div>
          <div style="font-size:10px;color:rgba(255,255,255,0.5)">${c.meaning}</div>
          <div style="font-size:10px;color:${c.elementColor}">
            ⚔️${c.atk} ❤️${c.hp}
          </div>
          ${hasN?`<div style="font-size:9px;color:#00BFFF;font-weight:700">🛡 Nシールド</div>`:""}
        </div>`;
    }).join("");

    document.getElementById("s8SelectedDisplay").innerHTML=[0,1].map(i=>{
      const c=selected[i];
      return c
        ?`<div style="background:rgba(255,255,255,0.08);
            border:1px solid ${c.elementColor};border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px">
            <div style="font-size:10px;color:rgba(255,255,255,0.4)">
              ${i===0?"1枚目（メイン）":"2枚目（予備）"}
            </div>
            <div style="font-family:'Fredoka One',cursive;font-size:0.85rem;color:#fff">
              ${c.word}
            </div>
            <div style="font-size:10px;color:${c.elementColor}">
              ⚔️${c.atk} ❤️${c.hp}
            </div>
          </div>`
        :`<div style="background:rgba(255,255,255,0.03);
            border:1px dashed rgba(255,255,255,0.15);border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px;
            color:rgba(255,255,255,0.25);font-size:12px">
            ${i===0?"1枚目":"2枚目"}<br>未選択
          </div>`;
    }).join("");

    const btn=document.getElementById("s8StartBtn");
    btn.disabled=selected.length!==2;
    btn.style.opacity=selected.length===2?"1":"0.4";
    btn.style.cursor=selected.length===2?"pointer":"not-allowed";
  }

  window.s8ToggleCard=function(word){
    const c=cards.find(x=>x.word===word);
    const idx=selected.findIndex(s=>s.word===word);
    if(idx!==-1){ selected.splice(idx,1); }
    else { if(selected.length>=2)return; selected.push(c); }
    renderPicker();
  };

  document.getElementById("s8StartBtn").onclick=()=>{
    if(selected.length<2)return;
    shootingDeck=selected;
    beginStage8();
  };
  renderPicker();
}

// =============================================
//  BEGIN STAGE 8
// =============================================
function beginStage8(){
  const area=document.getElementById("spaceArea");
  area.innerHTML=`
    <div style="position:relative;width:100%;max-width:420px;margin:0 auto">
      <canvas id="shootCanvas"
        style="display:block;width:100%;border-radius:16px;
          background:#000818;touch-action:none"></canvas>
          <div id="shootQuizResult"
  style="position:absolute;bottom:30px;left:50%;transform:translateX(-50%);
    font-family:'Fredoka One',cursive;font-size:1rem;
    background:rgba(0,0,0,0.7);border-radius:12px;padding:6px 16px;
    pointer-events:none;display:none;text-align:center;
    white-space:pre-line;z-index:100;min-width:200px">
</div>
      <button onclick="toggleShootingPause()"
        style="position:absolute;top:8px;right:8px;
          background:rgba(0,0,0,0.5);border:1px solid rgba(255,255,255,0.3);
          color:#fff;font-size:12px;padding:5px 10px;border-radius:8px;
          z-index:2100;cursor:pointer">⏸ ポーズ</button>
      <div id="shootHUD"
        style="position:absolute;top:8px;left:8px;right:8px;
          display:flex;justify-content:space-between;pointer-events:none">
        <div id="shootHP"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#6BCB77;text-shadow:0 0 8px rgba(107,203,119,0.8)">❤️ 0</div>
        <div id="shootTimer"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#FFD93D;text-shadow:0 0 8px rgba(255,217,61,0.8)">⏱ 60</div>
        <div id="shootCard"
          style="font-family:'Fredoka One',cursive;font-size:11px;color:#00BFFF">
          🚀 1枚目
        </div>
      </div>
      <div id="s8ShieldBadge"
        style="position:absolute;top:36px;left:8px;pointer-events:none;
          display:none;font-family:'Fredoka One',cursive;font-size:11px;
          color:#00BFFF;background:rgba(0,191,255,0.2);
          border:1px solid rgba(0,191,255,0.4);border-radius:8px;padding:3px 8px">
        🛡 Nシールド発動中
      </div>
      <div id="shootBossHUD"
        style="position:absolute;top:36px;left:8px;right:8px;
          display:none;pointer-events:none">
        <div style="font-family:'Fredoka One',cursive;font-size:11px;
          color:#00BFFF;text-align:center;margin-bottom:2px">💧 海王星</div>
        <div style="background:rgba(0,0,0,0.4);border-radius:8px;
          height:10px;overflow:hidden">
          <div id="shootBossHPBar"
            style="height:100%;
              background:linear-gradient(90deg,#00BFFF,#4D96FF);
              border-radius:8px;transition:width 0.3s;width:100%"></div>
        </div>
      </div>
      <div id="shootMessage"
        style="position:absolute;top:45%;left:50%;
          transform:translate(-50%,-50%);
          font-family:'Fredoka One',cursive;font-size:1.2rem;color:#fff;
          text-align:center;pointer-events:none;
          text-shadow:0 0 20px rgba(255,255,255,0.8);display:none;
          background:rgba(0,0,0,0.6);border-radius:12px;
          padding:8px 16px;white-space:pre-line"></div>
    </div>`;

  shootCanvas=document.getElementById("shootCanvas");
  const maxW=Math.min(420,window.innerWidth-32);
  shootCanvas.width=maxW;
  shootCanvas.height=Math.floor(maxW*1.5);
  shootCtx=shootCanvas.getContext("2d");

  if(shootingTimerInterval){ clearInterval(shootingTimerInterval); shootingTimerInterval=null; }
  if(shootingAnimFrame){ cancelAnimationFrame(shootingAnimFrame); shootingAnimFrame=null; }

  shootingCurrentCard=0; shootingPhase="survival"; shootingTime=60;
  shipBullets=[]; meteors=[]; hitEffects=[];
  s8Rods=[]; s8RodTimer=0;
  bulletTimer=0; meteorTimer=0; bossTimer=0;
  boss.bullets=[]; boss.hp=s8BossMaxHP; boss.vx=2.5;
  shootingBossActive=false; lastFrameTime=0;
  s8Comets=[]; s8CometTimer=0;
  s8SuckActive=false; s8SuckTimer=0; s8SuckPhase=0; s8SuckLife=0; s8AoeRadius=0;

  s8QuizActive=false; s8QuizShown15=false; s8QuizShown30=false; s8QuizShown45=false;
  s8BossPhase=false; s8BossQuizTimer=0; s8QuizZones=[];
  if(s8QuizCountdown){ clearInterval(s8QuizCountdown); s8QuizCountdown=null; }

  const c=shootingDeck[0];
  shootingPlayerMaxHP=c.hp; shootingPlayerHP=c.hp; shootingPlayerATK=c.atk;
  s8PlayerElement=c.element;

  s8NShield=shootingDeck.some(card=>card.word.toUpperCase().includes("N"));
  const badge=document.getElementById("s8ShieldBadge");
  if(badge) badge.style.display=s8NShield?"block":"none";

  // 小型機チェック
  const subUnlocked=localStorage.getItem("subShipUnlocked")==="true";
  if(subUnlocked){ ship.subShips=[{offset:-35},{offset:35}]; }
  else { ship.subShips=[]; }

  ship.x=shootCanvas.width/2-ship.w/2;
  ship.y=shootCanvas.height-ship.h-20;

  shootCanvas.addEventListener("touchstart",onShootTouchStart,{passive:false});
  shootCanvas.addEventListener("touchmove", onShootTouchMove, {passive:false});
  shootCanvas.addEventListener("touchend",  onShootTouchEnd,  {passive:false});
  shootCanvas.addEventListener("mousedown", onShootMouseDown);
  shootCanvas.addEventListener("mousemove", onShootMouseMove);
  shootCanvas.addEventListener("mouseup",   onShootMouseUp);

  shootingPaused=false;
  currentShootingStage="stage8";

  shootingTimerInterval=setInterval(()=>{
    if(shootingPhase!=="survival")return;
    shootingTime--;
    updateShootHUD();
    if(shootingTime===45&&!s8QuizShown15){ s8QuizShown15=true; triggerS8Quiz(); }
    if(shootingTime===30&&!s8QuizShown30){ s8QuizShown30=true; triggerS8Quiz(); }
    if(shootingTime===15&&!s8QuizShown45){ s8QuizShown45=true; triggerS8Quiz(); }
    if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS8BossPhase(); }
  },1000);

  shootingGameActive=true;
  lockShootingUI();
  dodgeUnlocked = localStorage.getItem("dodgeUnlocked")==="true";
  dodgeCooldown = 0;
  dodgeActive   = false;
  dodgeActiveTimer = 0;
  renderDodgeButton();
  updateShootHUD();
  requestAnimationFrame(stage8Loop);
}

// =============================================
//  STAGE 8 BOSS PHASE
// =============================================
function startS8BossPhase(){
  shootingPhase="boss"; s8BossPhase=true; shootingBossActive=true;
  boss.x=shootCanvas.width/2-boss.w/2; boss.y=60;
  boss.hp=s8BossMaxHP; boss.vx=2.5; boss.bullets=[];
  meteors=[]; s8Rods=[]; bossTimer=0; s8BossQuizTimer=0;
  s8SuckTimer=0; s8SuckPhase=0; s8SuckActive=false;
  const bossHUD=document.getElementById("shootBossHUD");
  if(bossHUD) bossHUD.style.display="block";
  const badge=document.getElementById("s8ShieldBadge");
  if(badge) badge.style.display="none";
  showShootMessage("💧 海王星 出現！\n吸い寄せに注意！",2500);
  updateBossHUD();
}

// =============================================
//  STAGE 8 LOOP
// =============================================
function stage8Loop(timestamp){
  if(!shootingGameActive)return;
  const dt=Math.min((timestamp-(lastFrameTime||timestamp))/16.67,3);
  lastFrameTime=timestamp;
  update_stage8(dt);
  draw_stage8();
  shootingAnimFrame=requestAnimationFrame(stage8Loop);
}

// =============================================
//  UPDATE STAGE 8
// =============================================
function update_stage8(dt){
  const W=shootCanvas.width, H=shootCanvas.height;
  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  hitEffects.forEach(e=>{
    e.life+=dt; e.alpha=Math.max(0,1-e.life/e.maxLife);
    if(e.type==="debris"){ e.x+=(e.vx||0)*dt; e.y+=(e.vy||0)*dt; e.r=Math.max(0,e.r-0.15*dt); }
    else { e.r+=(e.maxR-e.r)*0.18*dt; }
  });
  hitEffects=hitEffects.filter(e=>e.life<e.maxLife);
  // 回避・無敵タイマー更新
  if(dodgeActive){
    dodgeActiveTimer-=dt;
    if(dodgeActiveTimer<=0){
      dodgeActive=false;
      dodgeCooldown=600; // 10秒（600フレーム）
    }
  }
  if(dodgeCooldown>0){
    dodgeCooldown-=dt;
    if(dodgeCooldown<0) dodgeCooldown=0;
    updateDodgeButton();
  }
  if(dodgeActive) updateDodgeButton();

  // 弾発射
  bulletTimer+=dt;
  if(bulletTimer>=60){
    bulletTimer=0;
    shipBullets.push({x:ship.x+ship.w/2-4,y:ship.y-10,w:8,h:14,active:true});
    if(ship.subShips&&ship.subShips.length>0){
      ship.subShips.forEach(ss=>{
        const angle=15*Math.PI/180;
        const dir=ss.offset<0?-1:1;
        shipBullets.push({
          x:ship.x+ship.w/2+ss.offset-4,
          y:ship.y-10,
          w:6, h:10,
          vx:Math.sin(angle)*4*dir,
          vy:-Math.cos(angle)*8,
          active:true,
          isSub:true,
        });
      });
    }
  }
  shipBullets.forEach(b=>{ b.x+=(b.vx||0)*dt; b.y+=(b.vy||-8)*dt; });
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20&&b.x>-50&&b.x<W+50);

  // 彗星
  s8CometTimer+=dt;
  if(s8CometTimer>=1500){
    s8CometTimer=0;
    const fromLeft=Math.random()<0.5;
    const minY=shootingPhase==="boss"?boss.y+boss.h+20:H*0.1;
    s8Comets.push({
      x:fromLeft?-40:W+40,
      y:minY+Math.random()*(H*0.8-minY),
      w:40, h:20,
      vx:fromLeft?3.5:-3.5,
      life:0, maxLife:400,
    });
  }
  s8Comets.forEach(c=>{ c.x+=c.vx*dt; c.life+=dt; });
  for(let i=s8Comets.length-1;i>=0;i--){
    const c=s8Comets[i];
    if(rectsOverlap({x:c.x-c.w/2,y:c.y-c.h/2,w:c.w,h:c.h},ship)){
      const heal=Math.floor(shootingPlayerMaxHP*0.2);
      shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
      spawnHealEffect(ship.x+ship.w/2,ship.y);
      showShootMessage("☄️ 彗星！HP+20%！",1500);
      updateShootHUD(); s8Comets.splice(i,1);
    }
  }
  s8Comets=s8Comets.filter(c=>c.life<c.maxLife&&c.x>-100&&c.x<W+100);

  if(shootingPhase==="survival"){
    // 通常隕石
      meteorTimer+=dt;
      if(meteorTimer>=40+Math.random()*20){
        meteorTimer=0;
        const mw=30+Math.random()*20, mh=30+Math.random()*20;
        meteors.push({
          x:Math.random()*(W-mw), y:-mh,
          w:mw, h:mh,
          vy:2.5+Math.random()*2,
          hp:2,
          id:Date.now()+Math.random()
        });
      }
      meteors.forEach(m=>{ m.y+=m.vy*dt; }); // ← 追加
      meteors=meteors.filter(m=>m.hp>0&&m.y<H+50); // ← 追加
    // 回転する細長い物体　←この行の直後
      s8RodTimer+=dt;
      if(s8RodTimer>=300+Math.random()*200){
        s8RodTimer=0;
        s8Rods.push({
          x:W*0.1+Math.random()*W*0.8,
          y:-60,
          w:400, h:14, // 80→200に変更
          angle:Math.random()*Math.PI,
          rotSpeed:(Math.random()*0.03+0.02)*(Math.random()<0.5?1:-1),
          vy:0.8+Math.random()*0.5,
          hp:4,
          id:Date.now()+Math.random()
        });
      }

    // 吸い寄せ（サバイバル）　←この行の直後
    s8SuckTimer+=dt;
    if(s8SuckTimer>=600&&s8SuckPhase===0){
      s8SuckTimer=0;
      s8SuckPhase=1;
      s8SuckLife=0;
      // どの壁に吸い寄せるか決める
      s8SuckWall=["left","right","top","bottom"][Math.floor(Math.random()*4)];
      showShootMessage("💧 壁に吸い寄せ！",1000);
    }

    if(s8SuckPhase===1){
      s8SuckLife+=dt;
      // 壁方向に引き寄せ
      let tx=ship.x+ship.w/2, ty=ship.y+ship.h/2;
      if(s8SuckWall==="left")  tx=0;
      if(s8SuckWall==="right") tx=W;
      if(s8SuckWall==="top")   ty=0;
      if(s8SuckWall==="bottom")ty=H;
      const dx=tx-(ship.x+ship.w/2);
      const dy=ty-(ship.y+ship.h/2);
      const dist=Math.sqrt(dx*dx+dy*dy)||1;
      ship.x+=dx/dist*3*dt;
      ship.y+=dy/dist*3*dt;
      ship.x=Math.max(0,Math.min(W-ship.w,ship.x));
      ship.y=Math.max(0,Math.min(H-ship.h,ship.y));
      if(s8SuckLife>=120){
        s8SuckPhase=2;
        s8SuckLife=0;
        s8AoeRadius=0;
      }
    }

    if(s8SuckPhase===2){
      s8SuckLife+=dt;
      if(s8SuckLife>=60){
        // 壁に沿った長方形範囲攻撃
        let aoeX=0,aoeY=0,aoeW=0,aoeH=0;
        const thickness=80;
        if(s8SuckWall==="left")  { aoeX=0;         aoeY=0; aoeW=thickness; aoeH=H; }
        if(s8SuckWall==="right") { aoeX=W-thickness;aoeY=0; aoeW=thickness; aoeH=H; }
        if(s8SuckWall==="top")   { aoeX=0;         aoeY=0; aoeW=W; aoeH=thickness; }
        if(s8SuckWall==="bottom"){ aoeX=0; aoeY=H-thickness;aoeW=W; aoeH=thickness;}
        const inAoe=ship.x+ship.w>aoeX&&ship.x<aoeX+aoeW&&ship.y+ship.h>aoeY&&ship.y<aoeY+aoeH;
        if(inAoe){
          let dmg=500;
          if(s8NShield) dmg=Math.floor(dmg*0.5);
          
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#00BFFF");
          if(applyPlayerDamage(dmg, true)) return;
        }
        s8SuckPhase=0;
      }
    }

    // ロッド移動
    s8Rods.forEach(r=>{
      r.y+=r.vy*dt;
      r.angle+=r.rotSpeed*dt;
    });

    // 自弾 vs 隕石
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let mi=meteors.length-1;mi>=0;mi--){
        const m=meteors[mi]; if(m.hp<=0)continue;
        if(rectsOverlap(b,m)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#00BFFF");
          b.active=false; m.hp--;
          if(m.hp<=0){
            spawnMeteorBreakEffect(m.x+m.w/2,m.y+m.h/2);
            const heal=Math.floor(shootingPlayerMaxHP*0.01);
            shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
            updateShootHUD(); meteors.splice(mi,1);
          }
          break;
        }
      }
    }

    // 自弾 vs ロッド（回転当たり判定は簡易的に楕円で）
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let ri=s8Rods.length-1;ri>=0;ri--){
        const r=s8Rods[ri]; if(r.hp<=0)continue;
        // 簡易当たり判定（ロッド中心からの距離）
        const dx=(b.x+b.w/2)-r.x;
        const dy=(b.y+b.h/2)-r.y;
        // 回転を考慮した当たり判定
        const cos=Math.cos(-r.angle), sin=Math.sin(-r.angle);
        const lx=dx*cos-dy*sin;
        const ly=dx*sin+dy*cos;
        if(Math.abs(lx)<r.w/2+4&&Math.abs(ly)<r.h/2+4){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#00BFFF");
          b.active=false; r.hp--;
          if(r.hp<=0){
            spawnMeteorBreakEffect(r.x,r.y);
            s8Rods.splice(ri,1);
          }
          break;
        }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
    meteors=meteors.filter(m=>m.hp>0&&m.y<H+50);
    s8Rods=s8Rods.filter(r=>r.hp>0&&r.y<H+100);

    // 隕石 vs プレイヤー
    for(let mi=meteors.length-1;mi>=0;mi--){
      const m=meteors[mi];
      if(rectsOverlap(ship,m)){
        meteors.splice(mi,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        let dmg=300;
        if(s8NShield) dmg=Math.floor(dmg*0.5);
        if(applyPlayerDamage(dmg, true)) return;
      }
    }

    // ロッド vs プレイヤー
    for(let ri=s8Rods.length-1;ri>=0;ri--){
      const r=s8Rods[ri];
      const dx=(ship.x+ship.w/2)-r.x;
      const dy=(ship.y+ship.h/2)-r.y;
      const cos=Math.cos(-r.angle), sin=Math.sin(-r.angle);
      const lx=dx*cos-dy*sin;
      const ly=dx*sin+dy*cos;
      if(Math.abs(lx)<r.w/2+ship.w/2&&Math.abs(ly)<r.h/2+ship.h/2){
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        let dmg=400;
        if(s8NShield) dmg=Math.floor(dmg*0.5);
        
        s8Rods.splice(ri,1);
        if(applyPlayerDamage(dmg, true)) return;
      }
    }

  } else if(shootingPhase==="boss"){
    boss.x+=boss.vx*dt;
    if(boss.x<=10){ boss.x=10; boss.vx=Math.abs(boss.vx); }
    if(boss.x+boss.w>=W-10){ boss.x=W-boss.w-10; boss.vx=-Math.abs(boss.vx); }
    const minY=boss.y+boss.h+10;
    if(ship.y<minY) ship.y=minY;

    // ボスクイズ
    s8BossQuizTimer+=dt;
    if(s8BossQuizTimer>=1200){ s8BossQuizTimer=0; if(!s8QuizActive) triggerS8Quiz(); }

    // 吸い寄せ→範囲攻撃（ボス戦）　←この行の直後
    s8SuckTimer+=dt;
    if(s8SuckTimer>=900&&s8SuckPhase===0){
      s8SuckTimer=0;
      s8SuckPhase=1;
      s8SuckLife=0;
      s8SuckWall=["left","right","top","bottom"][Math.floor(Math.random()*4)];
      showShootMessage("💧 壁に吸い寄せ！逃げろ！",1200);
    }

    if(s8SuckPhase===1){
      s8SuckLife+=dt;
      let tx=ship.x+ship.w/2, ty=ship.y+ship.h/2;
      if(s8SuckWall==="left")  tx=0;
      if(s8SuckWall==="right") tx=W;
      if(s8SuckWall==="top")   ty=minY+20;
      if(s8SuckWall==="bottom")ty=H;
      const dx=tx-(ship.x+ship.w/2);
      const dy=ty-(ship.y+ship.h/2);
      const dist=Math.sqrt(dx*dx+dy*dy)||1;
      ship.x+=dx/dist*3*dt;
      ship.y+=dy/dist*3*dt;
      ship.x=Math.max(0,Math.min(W-ship.w,ship.x));
      ship.y=Math.max(minY,Math.min(H-ship.h,ship.y));
      if(s8SuckLife>=150){
        s8SuckPhase=2;
        s8SuckLife=0;
        s8AoeRadius=0;
      }
    }

    if(s8SuckPhase===2){
      s8SuckLife+=dt;
      if(s8SuckLife>=70){
        const thickness=80;
        let aoeX=0,aoeY=0,aoeW=0,aoeH=0;
        if(s8SuckWall==="left")  { aoeX=0;          aoeY=0; aoeW=thickness; aoeH=H; }
        if(s8SuckWall==="right") { aoeX=W-thickness; aoeY=0; aoeW=thickness; aoeH=H; }
        if(s8SuckWall==="top")   { aoeX=0; aoeY=minY;        aoeW=W; aoeH=thickness; }
        if(s8SuckWall==="bottom"){ aoeX=0; aoeY=H-thickness;  aoeW=W; aoeH=thickness; }
        const inAoe=ship.x+ship.w>aoeX&&ship.x<aoeX+aoeW&&ship.y+ship.h>aoeY&&ship.y<aoeY+aoeH;
        if(inAoe){
          const mult=getElementMultiplier(s8BossElement,s8PlayerElement);
          let dmg=Math.floor(s8BossATK*2*mult);
          if(s8NShield) dmg=Math.floor(dmg*0.5);
          
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#00BFFF");
          if(applyPlayerDamage(dmg, true)) return;
        }
        s8SuckPhase=0;
      }
    }

    // ボス攻撃
    bossTimer+=dt;
    if(bossTimer>=110+Math.random()*70){
      bossTimer=0;
      const bx=boss.x+boss.w/2, by=boss.y+boss.h;
      const roll=Math.random();
      if(roll<0.35){
        // 超巨大球予告演出　←この行の直後
        spawnBossHitEffect(boss.x+boss.w/2,boss.y+boss.h/2);
        spawnBossHitEffect(boss.x+boss.w/2,boss.y+boss.h/2);
        spawnBossHitEffect(boss.x+boss.w/2,boss.y+boss.h/2);
        setTimeout(()=>{
          if(!shootingGameActive||shootingPhase!=="boss")return;
          const bx2=boss.x+boss.w/2;
          const by2=boss.y+boss.h;
          boss.bullets.push({
            x:bx2-70, y:by2,
            w:140, h:140,
            vx:(Math.random()-0.5)*2,
            vy:2,
            active:true,
            isGiant:true,
          });
        },800);
      } else if(roll<0.75){
        // 5way弾
        for(let i=0;i<5;i++){
          const spread=(i-2)*0.6;
          boss.bullets.push({
            x:bx-8+i*15, y:by,
            w:16, h:16,
            vx:spread*2,
            vy:4,
            active:true,
          });
        }
      } else {
        // 通常弾3発
        [-1,0,1].forEach(i=>{
          boss.bullets.push({
            x:bx-8+i*25, y:by,
            w:16, h:16,
            vx:i*1.5,
            vy:4,
            active:true,
          });
        });
      }
    }

    boss.bullets.forEach(b=>{ b.x+=b.vx*dt; b.y+=b.vy*dt; });

    // ボス弾 vs プレイヤー
    for(let i=boss.bullets.length-1;i>=0;i--){
      const b=boss.bullets[i]; if(!b.active)continue;
      if(rectsOverlap(b,ship)){
        boss.bullets.splice(i,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#00BFFF");
        const mult=getElementMultiplier(s8BossElement,s8PlayerElement);
        let dmg=Math.floor(s8BossATK*(b.isGiant?3:1)*mult);
        if(s8NShield) dmg=Math.floor(dmg*0.5);
        if(applyPlayerDamage(dmg, true)) return;
      }
    }
    boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+80&&b.x>-80&&b.x<W+80);

    // 自弾 vs ボス
    const bossRect={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      if(rectsOverlap(b,bossRect)){
        spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
        b.active=false;
        const mult=getElementMultiplier(s8PlayerElement,s8BossElement);
        boss.hp-=Math.floor(shootingPlayerATK*mult);
        if(boss.hp<0) boss.hp=0;
        updateBossHUD();
        if(boss.hp<=0){ clearStage8(); return; }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
  }
}

// =============================================
//  STAGE 8 QUIZ
// =============================================
function triggerS8Quiz(){
  if(s8QuizActive)return;
  s8QuizActive=true;
  const card=target1900Cards[Math.floor(Math.random()*target1900Cards.length)];
  const q=card.quizzes[Math.floor(Math.random()*card.quizzes.length)];
  s8QuizAnswer=q.correct;
  s8QuizWord=card.word;
  const wrongs=q.choices.sort(()=>Math.random()-0.5).slice(0,3);
  const allChoices=[...wrongs,q.correct].sort(()=>Math.random()-0.5);
  const W=shootCanvas.width, H=shootCanvas.height;
  const zoneTop=H*0.55, zoneH=(H-zoneTop-20)/2, zoneW=W/2-8;
  s8QuizZones=[
    {label:allChoices[0],x:4,     y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[1],x:W/2+4, y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[2],x:4,     y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
    {label:allChoices[3],x:W/2+4, y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
  ];
  s8QuizTimer=5;
  if(s8QuizCountdown) clearInterval(s8QuizCountdown);
  s8QuizCountdown=setInterval(()=>{
    s8QuizTimer--;
    if(s8QuizTimer<=0){ clearInterval(s8QuizCountdown); s8QuizCountdown=null; judgeS8Quiz(); }
  },1000);
}

function judgeS8Quiz(){
  s8QuizActive=false;
  const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
  let chosen=null;
  for(const z of s8QuizZones){ if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){ chosen=z.label; break; } }
  s8QuizZones=[];
  if(chosen===s8QuizAnswer){  // ← 各ステージの変数名に合わせる
    diamonds+=3; saveGame();
    showQuizResult(true,"");
  } else {
    shootingPlayerHP-=600; updateShootHUD();
    showQuizResult(false, s8QuizAnswer); // ← 各ステージの変数名に合わせる
    const wrongCard=target1900Cards.find(c=>c.word===s8QuizWord);
    if(wrongCard) recordWrongWord("target1900", wrongCard.word, wrongCard.meaning);
    if(shootingPlayerHP<=0) handlePlayerDeath();
  }
}

// =============================================
//  DRAW STAGE 8
// =============================================
function draw_stage8(){
  const ctx=shootCtx, W=shootCanvas.width, H=shootCanvas.height;
  ctx.fillStyle="#000818"; ctx.fillRect(0,0,W,H);

  // 星（青白い深海色）
  for(let i=0;i<80;i++){
    ctx.fillStyle=`rgba(${100+((i*37)%80)},${160+((i*53)%80)},255,${0.3+((i*73)%100)/100*0.4})`;
    ctx.fillRect((i*137+50)%W,(i*97+30)%H,1.5,1.5);
  }
  const nebula=ctx.createRadialGradient(W*0.5,H*0.4,0,W*0.5,H*0.4,W*0.7);
  nebula.addColorStop(0,"rgba(0,80,180,0.1)");
  nebula.addColorStop(1,"rgba(0,0,0,0)");
  ctx.fillStyle=nebula; ctx.fillRect(0,0,W,H);

  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // 彗星
  s8Comets.forEach(c=>{
    const alpha=Math.min(1,Math.min(c.life/20,(c.maxLife-c.life)/20));
    ctx.save(); ctx.globalAlpha=alpha;
    const tailDir=c.vx>0?-1:1;
    const grad=ctx.createLinearGradient(c.x,c.y,c.x+tailDir*60,c.y);
    grad.addColorStop(0,"rgba(107,203,119,0.8)"); grad.addColorStop(1,"rgba(107,203,119,0)");
    ctx.fillStyle=grad;
    ctx.beginPath(); ctx.moveTo(c.x,c.y-5); ctx.lineTo(c.x+tailDir*60,c.y); ctx.lineTo(c.x,c.y+5); ctx.closePath(); ctx.fill();
    ctx.fillStyle="#6BCB77"; ctx.shadowColor="#6BCB77"; ctx.shadowBlur=16;
    ctx.beginPath(); ctx.arc(c.x,c.y,10,0,Math.PI*2); ctx.fill();
    ctx.restore();
  });

  // 吸い寄せエフェクト　←この行の直後
  if(s8SuckPhase===1){
    ctx.save();
    // 壁方向に矢印エフェクト
    const thickness=80;
    let aoeX=0,aoeY=0,aoeW=0,aoeH=0;
    if(s8SuckWall==="left")  { aoeX=0;          aoeY=0; aoeW=thickness; aoeH=H; }
    if(s8SuckWall==="right") { aoeX=W-thickness; aoeY=0; aoeW=thickness; aoeH=H; }
    if(s8SuckWall==="top")   { aoeX=0;           aoeY=0; aoeW=W; aoeH=thickness; }
    if(s8SuckWall==="bottom"){ aoeX=0; aoeY=H-thickness; aoeW=W; aoeH=thickness; }
    ctx.fillStyle="rgba(0,191,255,0.15)";
    ctx.strokeStyle="rgba(0,191,255,0.5)"; ctx.lineWidth=2;
    ctx.beginPath(); ctx.rect(aoeX,aoeY,aoeW,aoeH); ctx.fill(); ctx.stroke();
    ctx.restore();
  }

  if(s8SuckPhase===2){
    const thickness=80;
    let aoeX=0,aoeY=0,aoeW=0,aoeH=0;
    if(s8SuckWall==="left")  { aoeX=0;          aoeY=0; aoeW=thickness; aoeH=H; }
    if(s8SuckWall==="right") { aoeX=W-thickness; aoeY=0; aoeW=thickness; aoeH=H; }
    if(s8SuckWall==="top")   { aoeX=0;           aoeY=0; aoeW=W; aoeH=thickness; }
    if(s8SuckWall==="bottom"){ aoeX=0; aoeY=H-thickness; aoeW=W; aoeH=thickness; }
    ctx.save();
    ctx.fillStyle="rgba(0,191,255,0.4)";
    ctx.strokeStyle="#00BFFF"; ctx.lineWidth=4;
    ctx.shadowColor="#00BFFF"; ctx.shadowBlur=20;
    ctx.beginPath(); ctx.rect(aoeX,aoeY,aoeW,aoeH); ctx.fill(); ctx.stroke();
    ctx.restore();
  }

  // 回転ロッド
  s8Rods.forEach(r=>{
    ctx.save();
    ctx.translate(r.x,r.y);
    ctx.rotate(r.angle);
    const hpRatio=r.hp/4;
    const col=hpRatio>0.5?"#00BFFF":hpRatio>0.25?"#FFD93D":"#FF6B6B";
    ctx.fillStyle=col; ctx.shadowColor=col; ctx.shadowBlur=8;
    ctx.fillRect(-r.w/2,-r.h/2,r.w,r.h);
    // HPゲージ
    ctx.fillStyle="rgba(0,0,0,0.4)";
    ctx.fillRect(-r.w/2,-r.h/2-10,r.w,6);
    ctx.fillStyle=col;
    ctx.fillRect(-r.w/2,-r.h/2-10,r.w*hpRatio,6);
    ctx.restore();
  });

  // 隕石　←この行の直後
  meteors.forEach(m=>{
    ctx.save();
    ctx.fillStyle="#888"; ctx.shadowColor="rgba(180,180,180,0.4)"; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    ctx.fillStyle="#666"; ctx.shadowBlur=0;
    ctx.beginPath(); ctx.ellipse(m.x+m.w*0.35,m.y+m.h*0.35,m.w*0.15,m.h*0.12,0.5,0,Math.PI*2); ctx.fill();
    if(m.hp===1){
      ctx.strokeStyle="rgba(255,107,107,0.8)"; ctx.lineWidth=1.5;
      ctx.beginPath(); ctx.moveTo(m.x+m.w*0.4,m.y+m.h*0.2); ctx.lineTo(m.x+m.w*0.55,m.y+m.h*0.5); ctx.lineTo(m.x+m.w*0.45,m.y+m.h*0.8); ctx.stroke();
    }
    ctx.restore();
  });

  // クイズゾーン
  if(s8QuizActive&&s8QuizZones.length>0){
    ctx.save();
    ctx.fillStyle="rgba(0,0,0,0.82)";
    ctx.beginPath(); ctx.roundRect(W*0.03,H*0.47,W*0.94,46,8); ctx.fill();
    ctx.fillStyle="#00BFFF"; ctx.font=`bold ${Math.floor(W*0.034)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText(`「${s8QuizWord}」の意味は？`,W/2,H*0.47+16);
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.font=`${Math.floor(W*0.028)}px sans-serif`;
    ctx.fillText(`⏱ ${s8QuizTimer}秒 いるゾーンが回答！`,W/2,H*0.47+34);
    ctx.restore();
    const zoneColors=["rgba(0,191,255,0.3)","rgba(77,150,255,0.3)","rgba(107,203,119,0.3)","rgba(255,217,61,0.3)"];
    const zoneBorders=["#00BFFF","#4D96FF","#6BCB77","#FFD93D"];
    s8QuizZones.forEach((z,i)=>{
      ctx.save();
      ctx.fillStyle=zoneColors[i%4]; ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=2;
      ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.fill(); ctx.stroke();
      ctx.fillStyle="#fff"; ctx.textAlign="center"; ctx.textBaseline="middle";
      const fs=Math.floor(W*0.026); ctx.font=`bold ${fs}px sans-serif`;
      const lines=wrapText(ctx,z.label,z.w-14,fs);
      const lh=fs+3, sy=z.y+z.h/2-(lines.length-1)*lh/2;
      lines.forEach((l,li)=>ctx.fillText(l,z.x+z.w/2,sy+li*lh));
      const cx2=ship.x+ship.w/2, cy2=ship.y+ship.h/2;
      if(cx2>=z.x&&cx2<=z.x+z.w&&cy2>=z.y&&cy2<=z.y+z.h){
        ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=4;
        ctx.shadowColor=zoneBorders[i%4]; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.stroke();
      }
      ctx.restore();
    });
  }

  // 自弾
  shipBullets.forEach(b=>{
    if(!b.active)return;
    ctx.save();
    const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+(b.h||14));
    g.addColorStop(0,"#fff"); g.addColorStop(1,"#00BFFF");
    ctx.fillStyle=g; ctx.shadowColor="#00BFFF"; ctx.shadowBlur=10;
    ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h||14,4); ctx.fill();
    ctx.restore();
  });

  // ボスフェーズ
  if(shootingPhase==="boss"){
    // ボス弾
    boss.bullets.forEach(b=>{
      if(!b.active)return;
      ctx.save();
      if(b.isGiant){
        const bg=ctx.createRadialGradient(b.x+b.w/2,b.y+b.h/2,4,b.x+b.w/2,b.y+b.h/2,b.w/2);
        bg.addColorStop(0,"#fff"); bg.addColorStop(0.3,"#00BFFF"); bg.addColorStop(1,"rgba(0,80,200,0.4)");
        ctx.fillStyle=bg; ctx.shadowColor="#00BFFF"; ctx.shadowBlur=28;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
        // 輪
        ctx.strokeStyle="rgba(0,191,255,0.6)"; ctx.lineWidth=4;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2+6,0,Math.PI*2); ctx.stroke();
      } else {
        ctx.fillStyle="#00BFFF"; ctx.shadowColor="#00BFFF"; ctx.shadowBlur=14;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
        ctx.fillStyle="rgba(255,255,255,0.4)";
        ctx.beginPath(); ctx.arc(b.x+b.w/2-2,b.y+b.h/2-2,b.w*0.2,0,Math.PI*2); ctx.fill();
      }
      ctx.restore();
    });

    // 海王星ボス
    const bossHPRatio=Math.max(0,boss.hp/s8BossMaxHP);
    ctx.save();
    ctx.shadowColor="rgba(0,191,255,0.9)"; ctx.shadowBlur=28+(1-bossHPRatio)*35;

    // リング（後ろ）
    ctx.save();
    ctx.strokeStyle="rgba(0,191,255,0.35)"; ctx.lineWidth=16;
    ctx.beginPath(); ctx.ellipse(boss.x+boss.w/2,boss.y+boss.h/2,boss.w*0.9,boss.h*0.2,0.1,0,Math.PI*2); ctx.stroke();
    ctx.restore();

    // 本体
    const pg=ctx.createRadialGradient(boss.x+boss.w*0.35,boss.y+boss.h*0.3,boss.w*0.05,boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2);
    pg.addColorStop(0,"#A0E8FF"); pg.addColorStop(0.3,"#00BFFF"); pg.addColorStop(0.7,"#0040C0"); pg.addColorStop(1,"#001880");
    ctx.fillStyle=pg;
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.fill();

    // 渦巻き模様
    ctx.save();
    ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.clip();
    ctx.strokeStyle="rgba(0,100,200,0.4)"; ctx.lineWidth=3;
    for(let i=0;i<3;i++){
      ctx.beginPath();
      ctx.ellipse(boss.x+boss.w/2,boss.y+boss.h/2,boss.w*(0.2+i*0.12),boss.h*(0.1+i*0.06),i*0.6,0,Math.PI*2);
      ctx.stroke();
    }
    ctx.restore();

    // リング（前）
    ctx.save();
    ctx.strokeStyle="rgba(0,191,255,0.7)"; ctx.lineWidth=12;
    ctx.shadowColor="rgba(0,191,255,0.5)"; ctx.shadowBlur=14;
    ctx.beginPath(); ctx.ellipse(boss.x+boss.w/2,boss.y+boss.h/2,boss.w*0.9,boss.h*0.2,0.1,Math.PI,Math.PI*2); ctx.stroke();
    ctx.restore();

    if(bossHPRatio<0.5){
      ctx.strokeStyle=`rgba(100,200,255,${0.5+(1-bossHPRatio)*0.5})`; ctx.lineWidth=2; ctx.shadowBlur=0;
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.28,boss.y+boss.h*0.1); ctx.lineTo(boss.x+boss.w*0.5,boss.y+boss.h*0.52); ctx.lineTo(boss.x+boss.w*0.72,boss.y+boss.h*0.88); ctx.stroke();
    }
    ctx.restore();
  }

  // エフェクト
  hitEffects.forEach(e=>{
    if(e.alpha<=0)return;
    ctx.save(); ctx.globalAlpha=e.alpha;
    if(e.type==="debris"){ ctx.fillStyle=e.color; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill(); }
    else if(e.type==="heal"){ ctx.strokeStyle=e.color; ctx.lineWidth=3; ctx.shadowColor=e.color; ctx.shadowBlur=12; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.font=`bold ${Math.max(8,Math.floor(e.r*0.8))}px sans-serif`; ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.fillText("+",e.x,e.y-Math.max(0,e.r)*1.2); }
    else { ctx.strokeStyle=e.color; ctx.lineWidth=2.5; ctx.shadowColor=e.color; ctx.shadowBlur=14; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.globalAlpha=e.alpha*0.3; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r*0.5),0,Math.PI*2); ctx.fill(); }
    ctx.restore();
  });

  // 宇宙船
  drawSpaceShip(ctx,ship.x,ship.y,ship.w,ship.h);
  if(dodgeActive){
    ctx.save();
    const pulse=Math.sin(Date.now()*0.02)*0.3+0.7;
    ctx.strokeStyle=`rgba(255,255,255,${pulse})`;
    ctx.lineWidth=3;
    ctx.shadowColor="#fff";
    ctx.shadowBlur=20;
    ctx.beginPath();
    ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();
  }
  if(ship.subShips&&ship.subShips.length>0){
    ship.subShips.forEach(ss=>{
      drawRVSubShip(ctx,ship.x+ship.w/2+ss.offset-12,ship.y+8,"#00BFFF");
    });
  }

  // HPバー
  const hpRatio=Math.max(0,shootingPlayerHP/shootingPlayerMaxHP);
  const barW=W*0.5,barX=(W-barW)/2,barY=H-14;
  ctx.save();
  ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(barX,barY,barW,8,4); ctx.fill();
  const hpColor=hpRatio>0.5?"#6BCB77":hpRatio>0.25?"#FFD93D":"#FF6B6B";
  ctx.fillStyle=hpColor; ctx.shadowColor=hpColor; ctx.shadowBlur=6;
  ctx.beginPath(); ctx.roundRect(barX,barY,barW*hpRatio,8,4); ctx.fill();
  ctx.restore();

  drawElementBadge(ctx,W,s8PlayerElement);
}

// =============================================
//  STAGE 8 CLEAR
// =============================================
function clearStage8(){
  shootingPhase="clear"; shootingGameActive=false;
  clearInterval(shootingTimerInterval);
  if(s8QuizCountdown) clearInterval(s8QuizCountdown);
  cancelAnimationFrame(shootingAnimFrame);
  removeShootListeners();
  unlockShootingUI();
  const firstClear=!isStage8Cleared();
  if(firstClear){ markStage8Cleared(); diamonds+=25; saveGame(); }
  draw_stage8();
  setTimeout(()=>{
    document.getElementById("spaceArea").innerHTML=`
      <div style="text-align:center;padding:30px 16px">
        <div style="font-size:4rem;margin-bottom:10px">🏆</div>
        <div style="font-family:'Fredoka One',cursive;font-size:2rem;
          background:linear-gradient(90deg,#00BFFF,#4D96FF);
          -webkit-background-clip:text;-webkit-text-fill-color:transparent;
          margin-bottom:8px">STAGE 8 CLEAR!</div>
        ${firstClear
          ?`<div style="font-family:'Fredoka One',cursive;font-size:1.3rem;color:#FFD93D;margin-bottom:6px">💎×25 獲得！</div>`
          :`<div style="font-size:13px;color:rgba(255,255,255,0.4);margin-bottom:6px">※2回目以降クリア報酬なし</div>`}
        <div style="font-size:13px;color:rgba(255,255,255,0.5);margin-bottom:20px">
          💧 海王星を撃破した！<br>
          <span style="font-size:12px;color:rgba(255,255,255,0.4)">
            ※クイズ正解で💎×3（回数無制限）
          </span>
        </div>
        <button onclick="showStage8DeckSelect()"
          style="background:linear-gradient(135deg,#00BFFF,#4D96FF);
            font-size:1rem;padding:14px 28px;margin:6px">
          🔄 もう一度
        </button>
        <br>
        <button onclick="showNormalStageMenu()"
          style="background:rgba(255,255,255,0.08);box-shadow:none;
            font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">
          ← ステージ選択へ
        </button>
      </div>`;
    spawnStars();
  },500);
}

// =============================================
//  STAGE 9
// =============================================
let s9PlayerElement   = "fire";
let s9BossElement     = "fire";
let s9Boss1MaxHP      = 40000;
let s9Boss2MaxHP      = 50000;
let s9BossATK         = 900;
let s9QuizActive      = false;
let s9QuizAnswer      = "";
let s9QuizZones       = [];
let s9QuizTimer       = 0;
let s9QuizWord        = "";
let s9QuizCountdown   = null;
let s9QuizShown15     = false;
let s9QuizShown30     = false;
let s9QuizShown45     = false;
let s9BossQuizTimer   = 0;
let s9BossPhase       = false;
let s9Phase2          = false; // 第2形態
let s9TransformAnim   = false; // 変身演出中
let s9TransformTimer  = 0;
let s9PShield         = false;
let s9GimmickPhase    = 0; // 0~4 サバイバルギミック順
let s9GimmickTimer    = 0;
let s9Walls           = []; // 岩壁
let s9WallTimer       = 0;
let s9Vortexes        = []; // 渦
let s9VortexTimer     = 0;
let s9Rods            = []; // 細長い
let s9RodTimer        = 0;
let s9SuckPhase       = 0;
let s9SuckTimer       = 0;
let s9SuckLife        = 0;
let s9SuckWall        = "left";
let s9AoeRadius       = 0;
let s9BossGlowTimer   = 0; // 透明球予告
let s9BossGlowing     = false;
let s9AoeActive       = false;
let s9AoeLife         = 0;
let s9AoeX            = 0;
let s9AoeY            = 0;
let s9Phase2SuckActive= false;
let s9Phase2SuckLife  = 0;
let s9Phase2SuckTimer = 0;
let s9Phase2GiantReady= false;
let s9BombMeteors     = []; // 爆弾隕石
let s9BombTimer       = 0;
let s9BounceTimer     = 0; // 5連反射球タイマー
let s9Comets   = []; // ←s9BombMeteorsの下に追加
let s9CometTimer = 0;

function showStage9DeckSelect(){
  const pool = owned.filter(c=>c.type==="target1900");
  const grouped = {};
  pool.forEach(c=>{ if(!grouped[c.word]) grouped[c.word]=c; });
  const cards = Object.values(grouped);

  const area = document.getElementById("spaceArea");
  area.innerHTML = `
    <div style="text-align:center;padding:12px">
      <div style="font-family:'Fredoka One',cursive;font-size:1.1rem;
        color:#FF4444;margin-bottom:8px">🔴 ステージ９ デッキ選択</div>
      <div style="background:rgba(255,68,68,0.1);border:1px solid rgba(255,68,68,0.3);
        border-radius:12px;padding:10px;margin:0 auto 12px;max-width:320px;
        font-size:12px;color:rgba(255,255,255,0.7);text-align:left;line-height:1.8">
        🔴 <b>ステージ9 特殊ギミック</b><br>
        「P」のつくカードで被ダメ0.5倍！<br>
        歴代ギミックが順番に出現！<br>
        🔥 ボス属性：<b style="color:#FF4444">火属性</b>（水属性が有利！）<br>
        クリアで💎×100獲得！さらに英単語URカードも獲得できるよ
      </div>
      <div style="font-size:13px;color:#FF4444;margin-bottom:8px">
        選択: <span id="s9SelectedCount">0</span> / 2
      </div>
      <div id="s9CardPicker"
        style="display:flex;flex-wrap:wrap;justify-content:center;
          gap:8px;margin-bottom:16px"></div>
      <div id="s9SelectedDisplay"
        style="display:flex;justify-content:center;gap:12px;
          margin-bottom:80px;min-height:60px"></div>
      <div style="position:fixed;bottom:70px;right:16px;z-index:1000">
        <button id="s9StartBtn" disabled
          style="background:linear-gradient(135deg,#FF4444,#8B0000);
            font-size:1rem;padding:14px 20px;border-radius:20px;
            opacity:0.4;cursor:not-allowed;
            box-shadow:0 4px 20px rgba(0,0,0,0.4)">
          🚀 スタート！
        </button>
      </div>
      <button onclick="showNormalStageMenu()"
        style="background:rgba(255,255,255,0.08);box-shadow:none;
          font-size:12px;margin-top:10px;color:rgba(255,255,255,0.5)">← 戻る</button>
    </div>`;

  if(cards.length===0){
    document.getElementById("s9CardPicker").innerHTML=
      `<div style="color:rgba(255,255,255,0.4);font-size:13px;padding:20px">
        ターゲット1900カードがありません！
      </div>`;
    return;
  }

  let selected=[];

  function renderPicker(){
    document.getElementById("s9SelectedCount").textContent=selected.length;
    document.getElementById("s9CardPicker").innerHTML=cards.map(c=>{
      const idx=selected.findIndex(s=>s.word===c.word);
      const isSel=idx!==-1;
      const hasP=c.word.toUpperCase().includes("P");
      return `
        <div onclick="s9ToggleCard('${c.word}')"
          style="cursor:pointer;width:95px;padding:10px 6px;border-radius:14px;
            background:${isSel?"rgba(255,217,61,0.2)":"rgba(255,255,255,0.06)"};
            border:2px solid ${isSel?c.elementColor:hasP?"rgba(255,68,68,0.6)":"rgba(255,255,255,0.15)"};
            text-align:center;transition:all 0.15s;position:relative">
          ${isSel?`<div style="position:absolute;top:-6px;right:-6px;
            background:#FFD93D;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#1a1a2e;font-weight:700">${idx+1}</div>`:""}
          ${hasP?`<div style="position:absolute;top:-6px;left:-6px;
            background:#FF4444;border-radius:50%;width:18px;height:18px;
            font-size:10px;display:flex;align-items:center;justify-content:center;
            color:#fff;font-weight:700">🛡</div>`:""}
          <div style="font-size:1rem">${c.elementLabel.split(" ")[0]}</div>
          <div style="font-family:'Fredoka One',cursive;font-size:0.8rem;color:#fff">
            ${c.word}
          </div>
          <div style="font-size:10px;color:rgba(255,255,255,0.5)">${c.meaning}</div>
          <div style="font-size:10px;color:${c.elementColor}">
            ⚔️${c.atk} ❤️${c.hp}
          </div>
          ${hasP?`<div style="font-size:9px;color:#FF4444;font-weight:700">🛡 Pシールド</div>`:""}
        </div>`;
    }).join("");

    document.getElementById("s9SelectedDisplay").innerHTML=[0,1].map(i=>{
      const c=selected[i];
      return c
        ?`<div style="background:rgba(255,255,255,0.08);
            border:1px solid ${c.elementColor};border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px">
            <div style="font-size:10px;color:rgba(255,255,255,0.4)">
              ${i===0?"1枚目（メイン）":"2枚目（予備）"}
            </div>
            <div style="font-family:'Fredoka One',cursive;font-size:0.85rem;color:#fff">
              ${c.word}
            </div>
            <div style="font-size:10px;color:${c.elementColor}">
              ⚔️${c.atk} ❤️${c.hp}
            </div>
          </div>`
        :`<div style="background:rgba(255,255,255,0.03);
            border:1px dashed rgba(255,255,255,0.15);border-radius:12px;
            padding:8px 14px;text-align:center;min-width:80px;
            color:rgba(255,255,255,0.25);font-size:12px">
            ${i===0?"1枚目":"2枚目"}<br>未選択
          </div>`;
    }).join("");

    const btn=document.getElementById("s9StartBtn");
    btn.disabled=selected.length!==2;
    btn.style.opacity=selected.length===2?"1":"0.4";
    btn.style.cursor=selected.length===2?"pointer":"not-allowed";
  }

  window.s9ToggleCard=function(word){
    const c=cards.find(x=>x.word===word);
    const idx=selected.findIndex(s=>s.word===word);
    if(idx!==-1){ selected.splice(idx,1); }
    else { if(selected.length>=2)return; selected.push(c); }
    renderPicker();
  };

  document.getElementById("s9StartBtn").onclick=()=>{
    if(selected.length<2)return;
    shootingDeck=selected;
    beginStage9();
  };
  renderPicker();
}

// =============================================
//  BEGIN STAGE 9
// =============================================
function beginStage9(){
  const area=document.getElementById("spaceArea");
  area.innerHTML=`
    <div style="position:relative;width:100%;max-width:420px;margin:0 auto">
      <canvas id="shootCanvas"
        style="display:block;width:100%;border-radius:16px;
          background:#0a0005;touch-action:none"></canvas>
      <button onclick="toggleShootingPause()"
        style="position:absolute;top:8px;right:8px;
          background:rgba(0,0,0,0.5);border:1px solid rgba(255,255,255,0.3);
          color:#fff;font-size:12px;padding:5px 10px;border-radius:8px;
          z-index:2100;cursor:pointer">⏸ ポーズ</button>
      <div id="shootHUD"
        style="position:absolute;top:8px;left:8px;right:8px;
          display:flex;justify-content:space-between;pointer-events:none">
        <div id="shootHP"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#6BCB77;text-shadow:0 0 8px rgba(107,203,119,0.8)">❤️ 0</div>
        <div id="shootTimer"
          style="font-family:'Fredoka One',cursive;font-size:14px;
            color:#FFD93D;text-shadow:0 0 8px rgba(255,217,61,0.8)">⏱ 60</div>
        <div id="shootCard"
          style="font-family:'Fredoka One',cursive;font-size:11px;color:#FF4444">
          🚀 1枚目
        </div>
      </div>
      <div id="s9ShieldBadge"
        style="position:absolute;top:36px;left:8px;pointer-events:none;
          display:none;font-family:'Fredoka One',cursive;font-size:11px;
          color:#FF4444;background:rgba(255,68,68,0.2);
          border:1px solid rgba(255,68,68,0.4);border-radius:8px;padding:3px 8px">
        🛡 Pシールド発動中
      </div>
      <div id="shootBossHUD"
        style="position:absolute;top:36px;left:8px;right:8px;
          display:none;pointer-events:none">
        <div id="s9BossLabel" style="font-family:'Fredoka One',cursive;font-size:11px;
          color:#FF4444;text-align:center;margin-bottom:2px">🔴 冥王星</div>
        <div style="background:rgba(0,0,0,0.4);border-radius:8px;
          height:10px;overflow:hidden">
          <div id="shootBossHPBar"
            style="height:100%;
              background:linear-gradient(90deg,#FF4444,#8B0000);
              border-radius:8px;transition:width 0.3s;width:100%"></div>
        </div>
      </div>
      <div id="shootMessage"
        style="position:absolute;top:45%;left:50%;
          transform:translate(-50%,-50%);
          font-family:'Fredoka One',cursive;font-size:1.2rem;color:#fff;
          text-align:center;pointer-events:none;
          text-shadow:0 0 20px rgba(255,255,255,0.8);display:none;
          background:rgba(0,0,0,0.6);border-radius:12px;
          padding:8px 16px;white-space:pre-line"></div>
      <div id="shootQuizResult"
        style="position:absolute;bottom:30px;left:50%;transform:translateX(-50%);
          font-family:'Fredoka One',cursive;font-size:1rem;
          background:rgba(0,0,0,0.7);border-radius:12px;padding:6px 16px;
          pointer-events:none;display:none;text-align:center;
          white-space:pre-line;z-index:100;min-width:200px">
      </div>
    </div>`;

  shootCanvas=document.getElementById("shootCanvas");
  const maxW=Math.min(420,window.innerWidth-32);
  shootCanvas.width=maxW;
  shootCanvas.height=Math.floor(maxW*1.5);
  shootCtx=shootCanvas.getContext("2d");

  if(shootingTimerInterval){ clearInterval(shootingTimerInterval); shootingTimerInterval=null; }
  if(shootingAnimFrame){ cancelAnimationFrame(shootingAnimFrame); shootingAnimFrame=null; }

  shootingCurrentCard=0; shootingPhase="survival"; shootingTime=60;
  shipBullets=[]; meteors=[]; hitEffects=[];
  s9Walls=[]; s9Vortexes=[]; s9Rods=[]; s9BombMeteors=[];
  s9Comets=[]; s9CometTimer=0; // ←s9BombMeteors=[];の下に追加
  bulletTimer=0; meteorTimer=0; bossTimer=0;
  s9WallTimer=0; s9VortexTimer=0; s9RodTimer=0; s9BombTimer=0; s9BounceTimer=0;
  boss.bullets=[]; boss.hp=s9Boss1MaxHP; boss.vx=3;
  shootingBossActive=false; lastFrameTime=0;
  s9GimmickPhase=0; s9GimmickTimer=0;
  s9SuckPhase=0; s9SuckTimer=0; s9SuckLife=0;
  s9AoeActive=false; s9AoeLife=0;
  s9BossGlowing=false; s9BossGlowTimer=0;
  s9Phase2=false; s9TransformAnim=false; s9TransformTimer=0;
  s9Phase2SuckActive=false; s9Phase2SuckLife=0; s9Phase2SuckTimer=0; s9Phase2GiantReady=false;

  s9QuizActive=false; s9QuizShown15=false; s9QuizShown30=false; s9QuizShown45=false;
  s9BossPhase=false; s9BossQuizTimer=0; s9QuizZones=[];
  if(s9QuizCountdown){ clearInterval(s9QuizCountdown); s9QuizCountdown=null; }

  const c=shootingDeck[0];
  shootingPlayerMaxHP=c.hp; shootingPlayerHP=c.hp; shootingPlayerATK=c.atk;
  s9PlayerElement=c.element;

  s9PShield=shootingDeck.some(card=>card.word.toUpperCase().includes("P"));
  const badge=document.getElementById("s9ShieldBadge");
  if(badge) badge.style.display=s9PShield?"block":"none";

  const subUnlocked=localStorage.getItem("subShipUnlocked")==="true";
  if(subUnlocked){ ship.subShips=[{offset:-35},{offset:35}]; }
  else { ship.subShips=[]; }

  ship.x=shootCanvas.width/2-ship.w/2;
  ship.y=shootCanvas.height-ship.h-20;

  shootCanvas.addEventListener("touchstart",onShootTouchStart,{passive:false});
  shootCanvas.addEventListener("touchmove", onShootTouchMove, {passive:false});
  shootCanvas.addEventListener("touchend",  onShootTouchEnd,  {passive:false});
  shootCanvas.addEventListener("mousedown", onShootMouseDown);
  shootCanvas.addEventListener("mousemove", onShootMouseMove);
  shootCanvas.addEventListener("mouseup",   onShootMouseUp);

  shootingPaused=false;
  currentShootingStage="stage9";

  shootingTimerInterval=setInterval(()=>{
    if(shootingPhase!=="survival")return;
    shootingTime--;
    updateShootHUD();
    if(shootingTime===45&&!s9QuizShown15){ s9QuizShown15=true; triggerS9Quiz(); }
    if(shootingTime===30&&!s9QuizShown30){ s9QuizShown30=true; triggerS9Quiz(); }
    if(shootingTime===15&&!s9QuizShown45){ s9QuizShown45=true; triggerS9Quiz(); }
    if(shootingTime<=0){ clearInterval(shootingTimerInterval); startS9BossPhase(); }
  },1000);

  shootingGameActive=true;
  lockShootingUI();
  dodgeUnlocked = localStorage.getItem("dodgeUnlocked")==="true";
  dodgeCooldown = 0;
  dodgeActive   = false;
  dodgeActiveTimer = 0;
  renderDodgeButton();
  updateShootHUD();
  requestAnimationFrame(stage9Loop);
}

// =============================================
//  STAGE 9 BOSS PHASE
// =============================================
function startS9BossPhase(){
  shootingPhase="boss"; s9BossPhase=true; shootingBossActive=true;
  boss.x=shootCanvas.width/2-boss.w/2; boss.y=60;
  boss.hp=s9Boss1MaxHP; boss.vx=3; boss.bullets=[];
  meteors=[]; s9Walls=[]; s9Vortexes=[]; s9Rods=[]; s9BombMeteors=[];
  bossTimer=0; s9BossQuizTimer=0;
  s9AoeActive=false; s9BossGlowing=false;
  s9Phase2=false; s9TransformAnim=false;
  s9Phase2SuckActive=false; s9Phase2SuckTimer=0;
  const bossHUD=document.getElementById("shootBossHUD");
  if(bossHUD) bossHUD.style.display="block";
  const badge=document.getElementById("s9ShieldBadge");
  if(badge) badge.style.display="none";
  showShootMessage("🔴 冥王星 出現！",2000);
  updateBossHUD();
}

// =============================================
//  STAGE 9 LOOP
// =============================================
function stage9Loop(timestamp){
  if(!shootingGameActive)return;
  const dt=Math.min((timestamp-(lastFrameTime||timestamp))/16.67,3);
  lastFrameTime=timestamp;
  update_stage9(dt);
  draw_stage9();
  shootingAnimFrame=requestAnimationFrame(stage9Loop);
}

// =============================================
//  UPDATE STAGE 9
// =============================================
function update_stage9(dt){
  const W=shootCanvas.width, H=shootCanvas.height;
  if(shootingPhase==="gameover"||shootingPhase==="clear")return;
  if(s9TransformAnim) return; // 変身中は更新停止

  hitEffects.forEach(e=>{
    e.life+=dt; e.alpha=Math.max(0,1-e.life/e.maxLife);
    if(e.type==="debris"){ e.x+=(e.vx||0)*dt; e.y+=(e.vy||0)*dt; e.r=Math.max(0,e.r-0.15*dt); }
    else { e.r+=(e.maxR-e.r)*0.18*dt; }
  });
  hitEffects=hitEffects.filter(e=>e.life<e.maxLife);
  // 回避・無敵タイマー更新
  if(dodgeActive){
    dodgeActiveTimer-=dt;
    if(dodgeActiveTimer<=0){
      dodgeActive=false;
      dodgeCooldown=600; // 10秒（600フレーム）
    }
  }
  if(dodgeCooldown>0){
    dodgeCooldown-=dt;
    if(dodgeCooldown<0) dodgeCooldown=0;
    updateDodgeButton();
  }
  if(dodgeActive) updateDodgeButton();

  // 弾発射
  bulletTimer+=dt;
  if(bulletTimer>=60){
    bulletTimer=0;
    shipBullets.push({x:ship.x+ship.w/2-4,y:ship.y-10,w:8,h:14,active:true});
    if(ship.subShips&&ship.subShips.length>0){
      ship.subShips.forEach(ss=>{
        const angle=15*Math.PI/180;
        const dir=ss.offset<0?-1:1;
        shipBullets.push({
          x:ship.x+ship.w/2+ss.offset-4, y:ship.y-10,
          w:6, h:10,
          vx:Math.sin(angle)*4*dir, vy:-Math.cos(angle)*8,
          active:true, isSub:true,
        });
      });
    }
  }
  shipBullets.forEach(b=>{ b.x+=(b.vx||0)*dt; b.y+=(b.vy||-8)*dt; });
  shipBullets=shipBullets.filter(b=>b.active&&b.y>-20&&b.x>-50&&b.x<W+50);

  // 彗星（両フェーズ共通）　←弾発射処理の直後
  s9CometTimer+=dt;
  if(s9CometTimer>=1800){
    s9CometTimer=0;
    const fromLeft=Math.random()<0.5;
    const minY=shootingPhase==="boss"?boss.y+boss.h+20:H*0.1;
    s9Comets.push({
      x:fromLeft?-40:W+40,
      y:minY+Math.random()*(H*0.8-minY),
      w:40, h:20,
      vx:fromLeft?3.5:-3.5,
      life:0, maxLife:400,
    });
  }
  s9Comets.forEach(c=>{ c.x+=c.vx*dt; c.life+=dt; });
  for(let i=s9Comets.length-1;i>=0;i--){
    const c=s9Comets[i];
    if(rectsOverlap({x:c.x-c.w/2,y:c.y-c.h/2,w:c.w,h:c.h},ship)){
      const heal=Math.floor(shootingPlayerMaxHP*0.2);
      shootingPlayerHP=Math.min(shootingPlayerHP+heal,shootingPlayerMaxHP);
      spawnHealEffect(ship.x+ship.w/2,ship.y);
      showShootMessage("☄️ 彗星！HP+20%！",1500);
      updateShootHUD(); s9Comets.splice(i,1);
    }
  }
  s9Comets=s9Comets.filter(c=>c.life<c.maxLife&&c.x>-100&&c.x<W+100);

  if(shootingPhase==="survival"){
    // 常時隕石
    
    meteorTimer+=dt;
    if(meteorTimer>=40+Math.random()*20){
      meteorTimer=0;
      const mw=28+Math.random()*18, mh=28+Math.random()*18;
      meteors.push({x:Math.random()*(W-mw),y:-mh,w:mw,h:mh,vy:2.5+Math.random()*2,hp:2,id:Date.now()+Math.random()});
    }
    meteors.forEach(m=>{ m.y+=m.vy*dt; });
    meteors=meteors.filter(m=>m.hp>0&&m.y<H+50);

    // ギミックフェーズ（各12秒=720フレーム）
    // 0秒〜12秒：岩壁
    // 12秒〜24秒：吸い込み（2個）
    // 24秒〜36秒：斜め隕石
    // 36秒〜48秒：巨大隕石
    // 48秒〜60秒：細長い物体
    s9GimmickTimer+=dt;
    const gPhase=Math.min(4,Math.floor(s9GimmickTimer/720));

    // フェーズ切り替え時にリセット
    if(gPhase!==s9GimmickPhase){
      s9GimmickPhase=gPhase;
      s9Walls=[]; s9Vortexes=[]; s9Rods=[];
      s9WallTimer=0; s9VortexTimer=0; s9RodTimer=0;
    }

    // ===== フェーズ0：岩壁 =====
    if(s9GimmickPhase===0){
      s9WallTimer+=dt;
      if(s9WallTimer>=350){
        s9WallTimer=0;
        const roll=Math.random();
        const wallH=18;
        const gapSize=100;
        if(roll<0.5){
          // 左から横断
          const gapY=H*0.3+Math.random()*H*0.3;
          s9Walls.push({x:-W,y:gapY-wallH-gapSize,w:W,h:wallH,vx:3,vy:0,dir:"left",id:Date.now()+"a"});
          s9Walls.push({x:-W,y:gapY+gapSize,      w:W,h:wallH,vx:3,vy:0,dir:"left",id:Date.now()+"b"});
        } else {
          // 右から横断
          const gapY=H*0.3+Math.random()*H*0.3;
          s9Walls.push({x:W,y:gapY-wallH-gapSize,w:W,h:wallH,vx:-3,vy:0,dir:"right",id:Date.now()+"c"});
          s9Walls.push({x:W,y:gapY+gapSize,      w:W,h:wallH,vx:-3,vy:0,dir:"right",id:Date.now()+"d"});
        }
      }
      s9Walls.forEach(w=>{ w.x+=w.vx*dt; });
      s9Walls=s9Walls.filter(w=>{
        if(w.dir==="left")  return w.x<W*2;  // 左から来る壁は右端を超えたら消す
        if(w.dir==="right") return w.x>-W;   // 右から来る壁は左端を超えたら消す
        return true;
      });
      // 岩壁 vs プレイヤー
      s9Walls.forEach(w=>{
        if(rectsOverlap(ship,w)){
          if(w.dir==="left"){ ship.x=w.x+w.w+2; }
          else { ship.x=w.x-ship.w-2; }
          ship.x=Math.max(0,Math.min(W-ship.w,ship.x));
        }
      });
      // 自弾 vs 岩壁
      for(let bi=shipBullets.length-1;bi>=0;bi--){
        const b=shipBullets[bi]; if(!b.active)continue;
        for(const w of s9Walls){
          if(rectsOverlap(b,w)){ b.active=false; break; }
        }
      }
    }

    // ===== フェーズ1：吸い込み2個 =====
    if(s9GimmickPhase===1){
      s9VortexTimer+=dt;
      // 2秒ごとに渦生成、最大2個まで
      if(s9VortexTimer>=120&&s9Vortexes.length<2){
        s9VortexTimer=0;
        s9Vortexes.push({
          x:W*0.2+Math.random()*W*0.6,
          y:H*0.15+Math.random()*H*0.45,
          r:80+Math.random()*60,
          strength:2.0+Math.random()*0.8,
          life:0, maxLife:999, angle:0,
        });
      }
      s9Vortexes.forEach(v=>{
        v.life+=dt; v.angle+=0.05*dt;
        const dx=v.x-(ship.x+ship.w/2), dy=v.y-(ship.y+ship.h/2);
        const dist=Math.sqrt(dx*dx+dy*dy)||1;
        if(dist<v.r*4){
          const force=v.strength*(1-dist/(v.r*4))*0.8;
          ship.x+=dx/dist*force*dt; ship.y+=dy/dist*force*dt;
        }
      });
      ship.x=Math.max(0,Math.min(W-ship.w,ship.x));
      ship.y=Math.max(0,Math.min(H-ship.h,ship.y));
    }

    // ===== フェーズ2：斜め隕石 =====
    if(s9GimmickPhase===2){
      s9WallTimer+=dt;
      if(s9WallTimer>=35+Math.random()*15){ s9WallTimer=0;
        const mw=30+Math.random()*20, mh=30+Math.random()*20;
        const fromLeft=Math.random()<0.5;
        meteors.push({
          x:fromLeft?-mw:W+mw, y:Math.random()*H*0.6,
          w:mw, h:mh,
          vx:fromLeft?3+Math.random()*1.5:-(3+Math.random()*1.5),
          vy:2+Math.random()*2,
          hp:2, diagonal:true, id:Date.now()+Math.random()
        });
      }
      meteors.forEach(m=>{
        if(m.diagonal){
          m.x+=(m.vx||0)*dt; m.y+=(m.vy||0)*dt;
          if(m.x<=0){ m.x=1; m.vx=Math.abs(m.vx||0); }
          if(m.x+m.w>=W){ m.x=W-m.w-1; m.vx=-Math.abs(m.vx||0); }
        }
      });
      meteors=meteors.filter(m=>m.hp>0&&m.y<H+50&&m.x>-200&&m.x<W+200);
    }

    // ===== フェーズ3：巨大隕石 =====
    if(s9GimmickPhase===3){
      s9WallTimer+=dt;
      if(s9WallTimer>=100+Math.random()*50){ s9WallTimer=0;
        const mw=70+Math.random()*30, mh=70+Math.random()*30;
        meteors.push({
          x:Math.random()*(W-mw), y:-mh,
          w:mw, h:mh,
          vy:1.5+Math.random(),
          hp:4, isBig:true, id:Date.now()+Math.random()
        });
      }
    }

    // ===== フェーズ4：細長い物体 =====
    if(s9GimmickPhase===4){
      s9RodTimer+=dt;
      if(s9RodTimer>=250+Math.random()*150){ s9RodTimer=0;
        s9Rods.push({
          x:W*0.1+Math.random()*W*0.8, y:-60,
          w:400, h:14,
          angle:Math.random()*Math.PI,
          rotSpeed:(Math.random()*0.03+0.02)*(Math.random()<0.5?1:-1),
          vy:0.8+Math.random()*0.5,
          hp:4, id:Date.now()+Math.random()
        });
      }
      s9Rods.forEach(r=>{ r.y+=r.vy*dt; r.angle+=r.rotSpeed*dt; });
      // ロッド vs プレイヤー
      for(let ri=s9Rods.length-1;ri>=0;ri--){
        const r=s9Rods[ri];
        const dx=(ship.x+ship.w/2)-r.x, dy=(ship.y+ship.h/2)-r.y;
        const cos=Math.cos(-r.angle), sin=Math.sin(-r.angle);
        const lx=dx*cos-dy*sin, ly=dx*sin+dy*cos;
        if(Math.abs(lx)<r.w/2+ship.w/2&&Math.abs(ly)<r.h/2+ship.h/2){
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
          let dmg=400; if(s9PShield) dmg=Math.floor(dmg*0.5);
           s9Rods.splice(ri,1);
          if(applyPlayerDamage(dmg, true)) return;
        }
      }
      // 自弾 vs ロッド
      for(let bi=shipBullets.length-1;bi>=0;bi--){
        const b=shipBullets[bi]; if(!b.active)continue;
        for(let ri=s9Rods.length-1;ri>=0;ri--){
          const r=s9Rods[ri];
          const dx=(b.x+b.w/2)-r.x, dy=(b.y+b.h/2)-r.y;
          const cos=Math.cos(-r.angle), sin=Math.sin(-r.angle);
          const lx=dx*cos-dy*sin, ly=dx*sin+dy*cos;
          if(Math.abs(lx)<r.w/2+4&&Math.abs(ly)<r.h/2+4){
            b.active=false; r.hp--;
            if(r.hp<=0){ spawnMeteorBreakEffect(r.x,r.y); s9Rods.splice(ri,1); }
            break;
          }
        }
      }
      s9Rods=s9Rods.filter(r=>r.hp>0&&r.y<H+100);
    }

    // 共通：自弾 vs 隕石
    for(let bi=shipBullets.length-1;bi>=0;bi--){
      const b=shipBullets[bi]; if(!b.active)continue;
      for(let mi=meteors.length-1;mi>=0;mi--){
        const m=meteors[mi]; if(m.hp<=0)continue;
        if(rectsOverlap(b,m)){
          spawnHitEffect(b.x+b.w/2,b.y+b.h/2,"#FF4444");
          b.active=false; m.hp--;
          if(m.hp<=0){ spawnMeteorBreakEffect(m.x+m.w/2,m.y+m.h/2); meteors.splice(mi,1); }
          break;
        }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);

    // 隕石 vs プレイヤー
    for(let mi=meteors.length-1;mi>=0;mi--){
      const m=meteors[mi];
      if(rectsOverlap(ship,m)){
        meteors.splice(mi,1);
        spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
        let dmg=m.isBig?600:350; if(s9PShield) dmg=Math.floor(dmg*0.5);
        if(applyPlayerDamage(dmg, true)) return;
      }
    }

  } else if(shootingPhase==="boss"){
    const minY=boss.y+boss.h+10;
    if(ship.y<minY) ship.y=minY;

    // ボスクイズ
    s9BossQuizTimer+=dt;
    if(s9BossQuizTimer>=1200){ s9BossQuizTimer=0; if(!s9QuizActive) triggerS9Quiz(); }

    if(!s9Phase2){
      // ===== 第1形態 =====
      boss.x+=boss.vx*dt;
      if(boss.x<=10){ boss.x=10; boss.vx=Math.abs(boss.vx); }
      if(boss.x+boss.w>=W-10){ boss.x=W-boss.w-10; boss.vx=-Math.abs(boss.vx); }

      // 範囲攻撃タイマー
      if(s9AoeActive){
        s9AoeLife+=dt;
        s9AoeRadius=(s9AoeLife/180)*150;
        if(s9AoeLife>=180){
          const dx=(ship.x+ship.w/2)-s9AoeX, dy=(ship.y+ship.h/2)-s9AoeY;
          if(Math.sqrt(dx*dx+dy*dy)<150){
            const mult=getElementMultiplier(s9BossElement,s9PlayerElement);
            let dmg=Math.floor(s9BossATK*1.5*mult); if(s9PShield) dmg=Math.floor(dmg*0.5);
            
            spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF4444");
            if(applyPlayerDamage(dmg, true)) return;
          }
          s9AoeActive=false;
        }
      }

      // 透明球予告光
      if(s9BossGlowing){
        s9BossGlowTimer+=dt;
        if(s9BossGlowTimer>=60){
          s9BossGlowing=false; s9BossGlowTimer=0;
          // 透明球発射　←この行の直後
          const bx=boss.x+boss.w/2;
          const by=boss.y+boss.h;
          boss.bullets.push({x:bx-15,y:by,w:30,h:30,vx:0,vy:6,active:true,invisible:true});}
      }

      bossTimer+=dt;
      if(bossTimer>=90+Math.random()*60){
        bossTimer=0;
        const bx=boss.x+boss.w/2, by=boss.y+boss.h;
        const roll=Math.random();
        if(roll<0.4){
          // 速い大きめの球
          boss.bullets.push({x:bx-18,y:by,w:36,h:36,vx:(Math.random()-0.5)*3,vy:7,active:true,fast:true});
        } else if(roll<0.7){
          // 透明球（予告光）
          s9BossGlowing=true; s9BossGlowTimer=0;
        } else {
          // 範囲攻撃
          if(!s9AoeActive){
            s9AoeActive=true; s9AoeLife=0; s9AoeRadius=0;
            s9AoeX=ship.x+ship.w/2; s9AoeY=ship.y+ship.h/2;
          }
        }
      }

      // ボス弾移動
      boss.bullets.forEach(b=>{ b.x+=b.vx*dt; b.y+=b.vy*dt; });

      // ボス弾 vs プレイヤー
      for(let i=boss.bullets.length-1;i>=0;i--){
        const b=boss.bullets[i]; if(!b.active)continue;
        if(rectsOverlap(b,ship)){
          boss.bullets.splice(i,1);
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF4444");
          const mult=getElementMultiplier(s9BossElement,s9PlayerElement);
          let dmg=Math.floor(s9BossATK*(b.fast?1.5:1)*mult); if(s9PShield) dmg=Math.floor(dmg*0.5);
          if(applyPlayerDamage(dmg, true)) return;
        }
      }
      boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+50&&b.x>-50&&b.x<W+50);

      // 自弾 vs ボス
      if(boss.hp>0){
        const bossRect={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
        for(let bi=shipBullets.length-1;bi>=0;bi--){
          const b=shipBullets[bi]; if(!b.active)continue;
          if(rectsOverlap(b,bossRect)){
            spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
            b.active=false;
            const mult=getElementMultiplier(s9PlayerElement,s9BossElement);
            boss.hp-=Math.floor(shootingPlayerATK*mult);
            if(boss.hp<0) boss.hp=0;
            updateBossHUD();
            if(boss.hp<=0){
              // 変身演出開始
              startS9Transform();
              return;
            }
          }
        }
      }

    } else {
      // ===== 第2形態 =====
      boss.x+=boss.vx*dt;
      if(boss.x<=10){ boss.x=10; boss.vx=Math.abs(boss.vx)*1.2; }
      if(boss.x+boss.w>=W-10){ boss.x=W-boss.w-10; boss.vx=-Math.abs(boss.vx)*1.2; }
      boss.vx=Math.max(-5,Math.min(5,boss.vx));

      // 吸い寄せ中は通常攻撃しない
      if(!s9Phase2SuckActive){
        // 爆弾隕石タイマー
        s9BombTimer+=dt;
        if(s9BombTimer>=200+Math.random()*100){
          s9BombTimer=0;
          s9BombMeteors.push({
            x:Math.random()*(W-40), y:-40,
            w:40, h:40,
            vy:2+Math.random()*1.5,
            hp:1,
            id:Date.now()+Math.random()
          });
        }
      }

      // 爆弾隕石移動
      s9BombMeteors.forEach(m=>{ m.y+=m.vy*dt; });

      // 自弾 vs 爆弾隕石　←この行の直後
      for(let bi=shipBullets.length-1;bi>=0;bi--){
        const b=shipBullets[bi]; if(!b.active)continue;
        for(let mi=s9BombMeteors.length-1;mi>=0;mi--){
          const m=s9BombMeteors[mi]; if(m.hp<=0)continue;
          if(rectsOverlap(b,m)){
            b.active=false; m.hp--;
            if(m.hp<=0){
              // 爆発演出追加
              spawnBombExplosion(m.x+m.w/2, m.y+m.h/2);
              // 広範囲ダメージ（半径120）
              const ex=m.x+m.w/2, ey=m.y+m.h/2;
              const dx2=(ship.x+ship.w/2)-ex;
              const dy2=(ship.y+ship.h/2)-ey;
              if(Math.sqrt(dx2*dx2+dy2*dy2)<120){
                const mult=getElementMultiplier(s9BossElement,s9PlayerElement);
                let dmg=Math.floor(s9BossATK*1.2*mult);
                if(s9PShield) dmg=Math.floor(dmg*0.5);
                
                spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
                if(applyPlayerDamage(dmg, true)) return;
              }
              s9BombMeteors.splice(mi,1);
            }
            break;
          }
        }
      }
      

      // 爆弾隕石 vs プレイヤー　←この行の直後
      for(let mi=s9BombMeteors.length-1;mi>=0;mi--){
        const m=s9BombMeteors[mi];
        if(rectsOverlap(ship,m)){
          spawnBombExplosion(m.x+m.w/2, m.y+m.h/2);
          const mult=getElementMultiplier(s9BossElement,s9PlayerElement);
          let dmg=Math.floor(s9BossATK*1.5*mult);
          if(s9PShield) dmg=Math.floor(dmg*0.5);
          
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF6B6B");
          s9BombMeteors.splice(mi,1);
          if(applyPlayerDamage(dmg, true)) return;
        }
      }
      s9BombMeteors=s9BombMeteors.filter(m=>m.hp>0&&m.y<H+50);

      // 5連反射球タイマー
        s9BounceTimer+=dt;
        if(s9BounceTimer>=400+Math.random()*200){
          s9BounceTimer=0;
          const bx=boss.x+boss.w/2, by=boss.y+boss.h;
          for(let i=0;i<5;i++){
            setTimeout(()=>{
              if(!shootingGameActive||!s9Phase2)return;
              const vx=(Math.random()-0.5)*5;
              boss.bullets.push({
                x:bx-12, y:by,
                w:24, h:24,
                vx:vx,
                vy:4.5,
                active:true,
                isBounce:true,
                bounceCount:0,
              });
            },i*120);
          }
        }


      // 真ん中吸い寄せ→超巨大球　←この行の直後
      s9Phase2SuckTimer+=dt;
      if(s9Phase2SuckTimer>=1200&&!s9Phase2SuckActive){
        s9Phase2SuckTimer=0;
        s9Phase2SuckActive=true;
        s9Phase2SuckLife=0;
        s9Phase2GiantReady=false;
        boss.bullets=boss.bullets.filter(b=>!b.isBounce); // 反射球を消す
        showShootMessage("🔴 吸い寄せ！",1000);
      }

      if(s9Phase2SuckActive){
        s9Phase2SuckLife+=dt;
        if(s9Phase2SuckLife<150){
          // 真ん中に引き寄せ
          const cx=W/2, cy=H/2;
          const dx=cx-(ship.x+ship.w/2), dy=cy-(ship.y+ship.h/2);
          const dist=Math.sqrt(dx*dx+dy*dy)||1;
          ship.x+=dx/dist*3.5*dt; ship.y+=dy/dist*3.5*dt;
          ship.x=Math.max(0,Math.min(W-ship.w,ship.x));
          ship.y=Math.max(minY,Math.min(H-ship.h,ship.y));
        } else if(!s9Phase2GiantReady){
          s9Phase2GiantReady=true;
          // 超巨大球を即座に発射（setTimeoutなし）
          const bx=boss.x+boss.w/2;
          const by=boss.y+boss.h;
          const tx=W/2, ty=H/2;
          const dx=tx-bx, dy=ty-by;
          const dist=Math.sqrt(dx*dx+dy*dy)||1;
          boss.bullets.push({
            x:bx-80, y:by,
            w:160, h:160,
            vx:dx/dist*4,
            vy:Math.abs(dy/dist*4)+1,
            active:true,
            isPhase2Giant:true,
          });
          s9Phase2SuckActive=false;
          s9Phase2SuckTimer=0;
        }
      }

      // ボス弾移動（反射球は壁で1回跳ね返るだけ）　←この行の直後
      boss.bullets.forEach(b=>{
        b.x+=b.vx*dt; b.y+=b.vy*dt;
        if(b.isBounce){
          if(b.bounceCount===undefined) b.bounceCount=0;
          if(b.bounceCount<1){
            let bounced=false;
            if(b.x<=0){
              b.x=2; b.vx=Math.abs(b.vx)+0.1; bounced=true;
            } else if(b.x+b.w>=W){
              b.x=W-b.w-2; b.vx=-(Math.abs(b.vx)+0.1); bounced=true;
            }
            if(!bounced&&b.y+b.h>=H){
              b.y=H-b.h-2; b.vy=-(Math.abs(b.vy)+0.1); bounced=true;
            } else if(!bounced&&b.y<=0){
              b.y=2; b.vy=Math.abs(b.vy)+0.1; bounced=true;
            }
            if(bounced) b.bounceCount++;
          }
        }
      });

      // ボス弾 vs プレイヤー
      for(let i=boss.bullets.length-1;i>=0;i--){
        const b=boss.bullets[i]; if(!b.active)continue;
        if(rectsOverlap(b,ship)){
          boss.bullets.splice(i,1);
          spawnHitEffect(ship.x+ship.w/2,ship.y+ship.h/2,"#FF0000");
          const mult=getElementMultiplier(s9BossElement,s9PlayerElement);
          let dmg=Math.floor(s9BossATK*(b.isPhase2Giant?4:b.isBounce?1.2:1)*mult);
          if(s9PShield) dmg=Math.floor(dmg*0.5);
          if(applyPlayerDamage(dmg, true)) return;
        }
      }
      boss.bullets=boss.bullets.filter(b=>b.active&&b.y<H+100&&b.x>-100&&b.x<W+100);

      // 自弾 vs ボス（第2形態）
      const bossRect2={x:boss.x,y:boss.y,w:boss.w,h:boss.h};
      for(let bi=shipBullets.length-1;bi>=0;bi--){
        const b=shipBullets[bi]; if(!b.active)continue;
        if(rectsOverlap(b,bossRect2)){
          spawnBossHitEffect(b.x+b.w/2,b.y+b.h/2);
          b.active=false;
          const mult=getElementMultiplier(s9PlayerElement,s9BossElement);
          boss.hp-=Math.floor(shootingPlayerATK*mult);
          if(boss.hp<0) boss.hp=0;
          updateBossHUD();
          if(boss.hp<=0){ clearStage9(); return; }
        }
      }
    }
    shipBullets=shipBullets.filter(b=>b.active&&b.y>-20);
  }
}

// =============================================
//  変身演出
// =============================================
function startS9Transform(){
  s9TransformAnim=true;
  s9TransformTimer=0;
  shootingGameActive=false;
  boss.bullets=[];
  let flashCount=0;
  const flashInterval=setInterval(()=>{
    flashCount++;
    if(flashCount>=8){
      clearInterval(flashInterval);
      // 第2形態へ
      s9Phase2=true;
      s9TransformAnim=false;
      boss.hp=s9Boss2MaxHP;
      boss.vx=3.5;
      s9BombTimer=0; s9BounceTimer=0; s9Phase2SuckTimer=0;
      // HUDラベル更新
      const label=document.getElementById("s9BossLabel");
      if(label) label.textContent="💀 冥王星 第2形態";
      const bar=document.getElementById("shootBossHPBar");
      if(bar) bar.style.background="linear-gradient(90deg,#FF0000,#FF6B6B)";
      updateBossHUD();
      shootingGameActive=true;
      lastFrameTime=performance.now();
      requestAnimationFrame(stage9Loop);
    }
  },200);
}

// =============================================
//  STAGE 9 QUIZ
// =============================================
function triggerS9Quiz(){
  if(s9QuizActive)return;
  s9QuizActive=true;
  const card=target1900Cards[Math.floor(Math.random()*target1900Cards.length)];
  const q=card.quizzes[Math.floor(Math.random()*card.quizzes.length)];
  s9QuizAnswer=q.correct;
  s9QuizWord=card.word;
  const wrongs=q.choices.sort(()=>Math.random()-0.5).slice(0,3);
  const allChoices=[...wrongs,q.correct].sort(()=>Math.random()-0.5);
  const W=shootCanvas.width, H=shootCanvas.height;
  const zoneTop=H*0.55, zoneH=(H-zoneTop-20)/2, zoneW=W/2-8;
  s9QuizZones=[
    {label:allChoices[0],x:4,     y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[1],x:W/2+4, y:zoneTop,         w:zoneW,h:zoneH-4},
    {label:allChoices[2],x:4,     y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
    {label:allChoices[3],x:W/2+4, y:zoneTop+zoneH+4, w:zoneW,h:zoneH-4},
  ];
  s9QuizTimer=5;
  if(s9QuizCountdown) clearInterval(s9QuizCountdown);
  s9QuizCountdown=setInterval(()=>{
    s9QuizTimer--;
    if(s9QuizTimer<=0){ clearInterval(s9QuizCountdown); s9QuizCountdown=null; judgeS9Quiz(); }
  },1000);
}

function judgeS9Quiz(){
  s9QuizActive=false;
  const cx=ship.x+ship.w/2, cy=ship.y+ship.h/2;
  let chosen=null;
  for(const z of s9QuizZones){ if(cx>=z.x&&cx<=z.x+z.w&&cy>=z.y&&cy<=z.y+z.h){ chosen=z.label; break; } }
  s9QuizZones=[];
  if(chosen===s9QuizAnswer){
    diamonds+=3; saveGame();
    showQuizResult(true,"");
  } else {
    let dmg=900; if(s9PShield) dmg=Math.floor(dmg*0.5);
    shootingPlayerHP-=dmg; updateShootHUD();
    showQuizResult(false,s9QuizAnswer);
    const wrongCard=target1900Cards.find(c=>c.word===s9QuizWord);
    if(wrongCard) recordWrongWord("target1900", wrongCard.word, wrongCard.meaning);
    if(shootingPlayerHP<=0) handlePlayerDeath();
  }
}

function spawnBombExplosion(x, y){
  // 複数のリング状エフェクトで爆発を表現
  for(let i=0;i<5;i++){
    hitEffects.push({
      x, y,
      r:0,
      maxR:40+i*20, // 最大半径120まで広がる
      alpha:1,
      life:0,
      maxLife:40+i*8,
      color:`rgba(255,${Math.floor(100-i*20)},0,1)`,
      type:"explosion",
    });
  }
  // デブリ
  for(let i=0;i<8;i++){
    const angle=(i/8)*Math.PI*2;
    hitEffects.push({
      x, y,
      r:6,
      maxR:6,
      alpha:1,
      life:0,
      maxLife:40,
      color:"#FF6B00",
      type:"debris",
      vx:Math.cos(angle)*4,
      vy:Math.sin(angle)*4,
    });
  }
}

// =============================================
//  DRAW STAGE 9
// =============================================
function draw_stage9(){
  const ctx=shootCtx, W=shootCanvas.width, H=shootCanvas.height;

  // 変身演出中は画面を赤く点滅
  if(s9TransformAnim){
    const flash=Math.sin(Date.now()*0.03)*0.5+0.5;
    ctx.fillStyle=`rgba(${Math.floor(50+flash*150)},0,0,1)`; ctx.fillRect(0,0,W,H);
    ctx.save();
    ctx.fillStyle=`rgba(255,${Math.floor(flash*100)},0,${0.8+flash*0.2})`;
    ctx.font=`bold ${Math.floor(W*0.07)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.shadowColor="#FF4444"; ctx.shadowBlur=30;
    ctx.fillText("💀 変身！！",W/2,H/2);
    ctx.restore();
    return;
  }

  ctx.fillStyle="#0a0005"; ctx.fillRect(0,0,W,H);

  // 星（赤みがかった）
  for(let i=0;i<80;i++){
    ctx.fillStyle=`rgba(255,${80+((i*37)%100)},${80+((i*53)%80)},${0.3+((i*73)%100)/100*0.4})`;
    ctx.fillRect((i*137+50)%W,(i*97+30)%H,1.5,1.5);
  }
  const nebula=ctx.createRadialGradient(W*0.5,H*0.4,0,W*0.5,H*0.4,W*0.7);
  nebula.addColorStop(0,"rgba(150,0,50,0.1)"); nebula.addColorStop(1,"rgba(0,0,0,0)");
  ctx.fillStyle=nebula; ctx.fillRect(0,0,W,H);

  if(shootingPhase==="gameover"||shootingPhase==="clear")return;

  // ギミック描画
  // 岩壁
  s9Walls.forEach(w=>{
    ctx.save();
    const wg=ctx.createLinearGradient(w.x,w.y,w.x,w.y+w.h);
    wg.addColorStop(0,"#8B3A1A"); wg.addColorStop(0.5,"#C8603A"); wg.addColorStop(1,"#6B2A10");
    ctx.fillStyle=wg; ctx.shadowColor="rgba(200,80,50,0.6)"; ctx.shadowBlur=8;
    ctx.fillRect(w.x,w.y,w.w,w.h);
    ctx.fillStyle="rgba(255,150,100,0.3)"; ctx.fillRect(w.x,w.y,w.w,3);
    ctx.restore();
  });

  // 渦巻き
  s9Vortexes.forEach(v=>{
    const alpha=Math.min(1,Math.min(v.life/30,(v.maxLife-v.life)/30))*0.6;
    ctx.save(); ctx.globalAlpha=alpha; ctx.translate(v.x,v.y);
    for(let ri=0;ri<4;ri++){
      const r=v.r*(0.25+ri*0.25);
      ctx.strokeStyle=`rgba(255,100,100,${0.4-ri*0.08})`; ctx.lineWidth=2;
      ctx.beginPath(); ctx.arc(0,0,r,v.angle+ri*0.5,v.angle+ri*0.5+Math.PI*1.5); ctx.stroke();
    }
    ctx.restore();
  });

  // ロッド
  s9Rods.forEach(r=>{
    ctx.save(); ctx.translate(r.x,r.y); ctx.rotate(r.angle);
    ctx.fillStyle="#FF6644"; ctx.shadowColor="#FF6644"; ctx.shadowBlur=8;
    ctx.fillRect(-r.w/2,-r.h/2,r.w,r.h);
    ctx.restore();
  });

  // 範囲攻撃エフェクト（第1形態）
  if(s9AoeActive&&!s9Phase2){
    ctx.save();
    const progress=s9AoeLife/180;
    const r2=Math.floor(150+progress*105);
    const warnColor=`rgba(${r2},50,50,0.8)`;
    ctx.strokeStyle=warnColor; ctx.lineWidth=4;
    ctx.shadowColor=warnColor; ctx.shadowBlur=20;
    ctx.beginPath(); ctx.arc(s9AoeX,s9AoeY,s9AoeRadius,0,Math.PI*2); ctx.stroke();
    ctx.fillStyle=`rgba(${r2},50,50,${0.05+progress*0.1})`;
    ctx.beginPath(); ctx.arc(s9AoeX,s9AoeY,s9AoeRadius,0,Math.PI*2); ctx.fill();
    const countdown=Math.ceil((180-s9AoeLife)/60);
    ctx.fillStyle=warnColor; ctx.font=`bold ${Math.floor(W*0.06)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle"; ctx.shadowBlur=16;
    ctx.fillText(countdown>0?countdown:"💥",s9AoeX,s9AoeY);
    ctx.restore();
  }

  // 第2形態吸い寄せエフェクト
  if(s9Phase2SuckActive&&s9Phase2SuckLife<150){
    ctx.save();
    ctx.strokeStyle="rgba(255,50,50,0.5)"; ctx.lineWidth=2;
    for(let i=0;i<8;i++){
      const angle=(i/8)*Math.PI*2+s9Phase2SuckLife*0.05;
      const r3=60+Math.random()*100;
      ctx.beginPath();
      ctx.moveTo(W/2+Math.cos(angle)*r3,H/2+Math.sin(angle)*r3);
      ctx.lineTo(W/2+Math.cos(angle)*(r3-30),H/2+Math.sin(angle)*(r3-30));
      ctx.stroke();
    }
    ctx.restore();
  }

  // 彗星描画　←隕石の直前
  s9Comets.forEach(c=>{
    const alpha=Math.min(1,Math.min(c.life/20,(c.maxLife-c.life)/20));
    ctx.save(); ctx.globalAlpha=alpha;
    const tailDir=c.vx>0?-1:1;
    const grad=ctx.createLinearGradient(c.x,c.y,c.x+tailDir*60,c.y);
    grad.addColorStop(0,"rgba(107,203,119,0.8)");
    grad.addColorStop(1,"rgba(107,203,119,0)");
    ctx.fillStyle=grad;
    ctx.beginPath();
    ctx.moveTo(c.x,c.y-5);
    ctx.lineTo(c.x+tailDir*60,c.y);
    ctx.lineTo(c.x,c.y+5);
    ctx.closePath(); ctx.fill();
    ctx.fillStyle="#6BCB77"; ctx.shadowColor="#6BCB77"; ctx.shadowBlur=16;
    ctx.beginPath(); ctx.arc(c.x,c.y,10,0,Math.PI*2); ctx.fill();
    ctx.restore();
  });

  // 隕石
  meteors.forEach(m=>{
    ctx.save();
    ctx.fillStyle=m.isBig?"#2A1A4A":"#888";
    ctx.shadowColor=m.isBig?"rgba(100,50,200,0.4)":"rgba(180,180,180,0.4)"; ctx.shadowBlur=6;
    ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    if(!m.isBig){
      ctx.fillStyle="#666"; ctx.shadowBlur=0;
      ctx.beginPath(); ctx.ellipse(m.x+m.w*0.35,m.y+m.h*0.35,m.w*0.15,m.h*0.12,0.5,0,Math.PI*2); ctx.fill();
    } else {
      const hpR=m.hp/4;
      ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(m.x,m.y-10,m.w,6,3); ctx.fill();
      ctx.fillStyle="#FF4444"; ctx.beginPath(); ctx.roundRect(m.x,m.y-10,m.w*hpR,6,3); ctx.fill();
    }
    ctx.restore();
  });

  // 爆弾隕石
  s9BombMeteors.forEach(m=>{
    ctx.save();
    ctx.fillStyle="#FF4400"; ctx.shadowColor="#FF4400"; ctx.shadowBlur=12;
    ctx.beginPath(); ctx.ellipse(m.x+m.w/2,m.y+m.h/2,m.w/2,m.h/2,0,0,Math.PI*2); ctx.fill();
    // 爆弾マーク
    ctx.fillStyle="#FFD93D"; ctx.font=`bold ${Math.floor(m.w*0.6)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText("💣",m.x+m.w/2,m.y+m.h/2);
    ctx.restore();
  });

  // クイズゾーン
  if(s9QuizActive&&s9QuizZones.length>0){
    ctx.save();
    ctx.fillStyle="rgba(0,0,0,0.82)";
    ctx.beginPath(); ctx.roundRect(W*0.03,H*0.47,W*0.94,46,8); ctx.fill();
    ctx.fillStyle="#FF4444"; ctx.font=`bold ${Math.floor(W*0.034)}px sans-serif`;
    ctx.textAlign="center"; ctx.textBaseline="middle";
    ctx.fillText(`「${s9QuizWord}」の意味は？`,W/2,H*0.47+16);
    ctx.fillStyle="rgba(255,255,255,0.6)"; ctx.font=`${Math.floor(W*0.028)}px sans-serif`;
    ctx.fillText(`⏱ ${s9QuizTimer}秒 いるゾーンが回答！`,W/2,H*0.47+34);
    ctx.restore();
    const zoneColors=["rgba(255,68,68,0.3)","rgba(255,149,0,0.3)","rgba(107,203,119,0.3)","rgba(255,217,61,0.3)"];
    const zoneBorders=["#FF4444","#FF9500","#6BCB77","#FFD93D"];
    s9QuizZones.forEach((z,i)=>{
      ctx.save();
      ctx.fillStyle=zoneColors[i%4]; ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=2;
      ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.fill(); ctx.stroke();
      ctx.fillStyle="#fff"; ctx.textAlign="center"; ctx.textBaseline="middle";
      const fs=Math.floor(W*0.026); ctx.font=`bold ${fs}px sans-serif`;
      const lines=wrapText(ctx,z.label,z.w-14,fs);
      const lh=fs+3, sy=z.y+z.h/2-(lines.length-1)*lh/2;
      lines.forEach((l,li)=>ctx.fillText(l,z.x+z.w/2,sy+li*lh));
      const cx2=ship.x+ship.w/2, cy2=ship.y+ship.h/2;
      if(cx2>=z.x&&cx2<=z.x+z.w&&cy2>=z.y&&cy2<=z.y+z.h){
        ctx.strokeStyle=zoneBorders[i%4]; ctx.lineWidth=4;
        ctx.shadowColor=zoneBorders[i%4]; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.roundRect(z.x,z.y,z.w,z.h,8); ctx.stroke();
      }
      ctx.restore();
    });
  }

  // 自弾
  shipBullets.forEach(b=>{
    if(!b.active)return;
    ctx.save();
    const g=ctx.createLinearGradient(b.x,b.y,b.x,b.y+(b.h||14));
    g.addColorStop(0,"#fff"); g.addColorStop(1,"#FF4444");
    ctx.fillStyle=g; ctx.shadowColor="#FF4444"; ctx.shadowBlur=10;
    ctx.beginPath(); ctx.roundRect(b.x,b.y,b.w,b.h||14,4); ctx.fill();
    ctx.restore();
  });

  // ボスフェーズ
  if(shootingPhase==="boss"){
    // ボス弾描画
    boss.bullets.forEach(b=>{
      if(!b.active)return;
      ctx.save();
      if(b.invisible){
        ctx.restore();
        return;
      } else if(b.isPhase2Giant){
        const bg=ctx.createRadialGradient(b.x+b.w/2,b.y+b.h/2,4,b.x+b.w/2,b.y+b.h/2,b.w/2);
        bg.addColorStop(0,"#fff"); bg.addColorStop(0.3,"#FF4444"); bg.addColorStop(1,"rgba(150,0,0,0.4)");
        ctx.fillStyle=bg; ctx.shadowColor="#FF4444"; ctx.shadowBlur=35;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
        ctx.strokeStyle="rgba(255,100,100,0.6)"; ctx.lineWidth=5;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2+8,0,Math.PI*2); ctx.stroke();
      } else if(b.fast){
        ctx.fillStyle="#FF6B6B"; ctx.shadowColor="#FF6B6B"; ctx.shadowBlur=18;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
      } else if(b.isBounce){
        ctx.fillStyle="#FF9500"; ctx.shadowColor="#FF9500"; ctx.shadowBlur=14;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
      } else {
        ctx.fillStyle="#FF4444"; ctx.shadowColor="#FF4444"; ctx.shadowBlur=14;
        ctx.beginPath(); ctx.arc(b.x+b.w/2,b.y+b.h/2,b.w/2,0,Math.PI*2); ctx.fill();
      }
      ctx.restore();
    });

    // 冥王星ボス描画
    const bossHPRatio=Math.max(0,boss.hp/(s9Phase2?s9Boss2MaxHP:s9Boss1MaxHP));
    ctx.save();

    if(s9Phase2){
      // 第2形態：より暗く禍々しい
      ctx.shadowColor="rgba(255,0,0,1)"; ctx.shadowBlur=30+(1-bossHPRatio)*40;
      const pg=ctx.createRadialGradient(boss.x+boss.w*0.35,boss.y+boss.h*0.3,boss.w*0.05,boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2);
      pg.addColorStop(0,"#FF8080"); pg.addColorStop(0.3,"#CC0000"); pg.addColorStop(0.7,"#600000"); pg.addColorStop(1,"#200000");
      ctx.fillStyle=pg;
      ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.fill();
      // 禍々しい模様
      ctx.save();
      ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.clip();
      ctx.strokeStyle="rgba(255,50,0,0.5)"; ctx.lineWidth=3;
      for(let i=0;i<5;i++){
        ctx.beginPath();
        ctx.moveTo(boss.x+boss.w/2,boss.y+boss.h/2);
        const angle=(i/5)*Math.PI*2;
        ctx.lineTo(boss.x+boss.w/2+Math.cos(angle)*boss.w*0.5,boss.y+boss.h/2+Math.sin(angle)*boss.h*0.5);
        ctx.stroke();
      }
      ctx.restore();
      // 目
      ctx.fillStyle="#FF0000"; ctx.shadowColor="#FF0000"; ctx.shadowBlur=20;
      ctx.beginPath(); ctx.arc(boss.x+boss.w*0.38,boss.y+boss.h*0.38,boss.w*0.07,0,Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(boss.x+boss.w*0.62,boss.y+boss.h*0.38,boss.w*0.07,0,Math.PI*2); ctx.fill();
      ctx.fillStyle="#000";
      ctx.beginPath(); ctx.arc(boss.x+boss.w*0.38,boss.y+boss.h*0.38,boss.w*0.04,0,Math.PI*2); ctx.fill();
      ctx.beginPath(); ctx.arc(boss.x+boss.w*0.62,boss.y+boss.h*0.38,boss.w*0.04,0,Math.PI*2); ctx.fill();
    } else {
      // 第1形態
      const glowPulse=s9BossGlowing?0.5+Math.sin(Date.now()*0.1)*0.5:0;
      ctx.shadowColor=`rgba(255,${50+glowPulse*200},0,0.9)`;
      ctx.shadowBlur=(20+(1-bossHPRatio)*25)+(glowPulse*30);
      const pg=ctx.createRadialGradient(boss.x+boss.w*0.35,boss.y+boss.h*0.3,boss.w*0.05,boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2);
      if(s9BossGlowing){
        pg.addColorStop(0,"#FFFFFF"); pg.addColorStop(0.3,"#FF8080"); pg.addColorStop(0.8,"#8B1A05"); pg.addColorStop(1,"#5A0A00");
      } else {
        pg.addColorStop(0,"#FF6050"); pg.addColorStop(0.3,"#CC2010"); pg.addColorStop(0.8,"#8B1A05"); pg.addColorStop(1,"#5A0A00");
      }
      ctx.fillStyle=pg;
      ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.fill();
      // 表面模様
      ctx.save();
      ctx.beginPath(); ctx.arc(boss.x+boss.w/2,boss.y+boss.h/2,boss.w/2,0,Math.PI*2); ctx.clip();
      ctx.fillStyle="rgba(200,60,30,0.3)";
      for(let i=0;i<4;i++){
        const wy=boss.y+boss.h*0.2+i*boss.h*0.2;
        ctx.beginPath(); ctx.ellipse(boss.x+boss.w/2,wy,boss.w*0.4,boss.h*0.04,0,0,Math.PI*2); ctx.fill();
      }
      ctx.restore();
    }

    if(bossHPRatio<0.5){
      ctx.strokeStyle=`rgba(255,100,50,${0.5+(1-bossHPRatio)*0.5})`; ctx.lineWidth=2.5; ctx.shadowBlur=0;
      ctx.beginPath(); ctx.moveTo(boss.x+boss.w*0.3,boss.y+boss.h*0.1); ctx.lineTo(boss.x+boss.w*0.5,boss.y+boss.h*0.5); ctx.lineTo(boss.x+boss.w*0.72,boss.y+boss.h*0.85); ctx.stroke();
    }
    ctx.restore();
  }

  // エフェクト
  hitEffects.forEach(e=>{
    if(e.alpha<=0)return;
    ctx.save(); ctx.globalAlpha=e.alpha;
    if(e.type==="debris"){ ctx.fillStyle=e.color; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill(); }
    else if(e.type==="heal"){ ctx.strokeStyle=e.color; ctx.lineWidth=3; ctx.shadowColor=e.color; ctx.shadowBlur=12; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); }
    else if(e.type==="explosion"){  // ← ここに追加
      ctx.strokeStyle=e.color; ctx.lineWidth=4;
      ctx.shadowColor="#FF4400"; ctx.shadowBlur=20;
      ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke();
      ctx.fillStyle=`rgba(255,100,0,${e.alpha*0.2})`;
      ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.fill();
    }
    else { ctx.strokeStyle=e.color; ctx.lineWidth=2.5; ctx.shadowColor=e.color; ctx.shadowBlur=14; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r),0,Math.PI*2); ctx.stroke(); ctx.fillStyle=e.color; ctx.globalAlpha=e.alpha*0.3; ctx.beginPath(); ctx.arc(e.x,e.y,Math.max(0,e.r*0.5),0,Math.PI*2); ctx.fill(); }
    ctx.restore();
  });

  // 宇宙船
  drawSpaceShip(ctx,ship.x,ship.y,ship.w,ship.h);
  if(dodgeActive){
    ctx.save();
    const pulse=Math.sin(Date.now()*0.02)*0.3+0.7;
    ctx.strokeStyle=`rgba(255,255,255,${pulse})`;
    ctx.lineWidth=3;
    ctx.shadowColor="#fff";
    ctx.shadowBlur=20;
    ctx.beginPath();
    ctx.arc(ship.x+ship.w/2,ship.y+ship.h/2,ship.w*0.8,0,Math.PI*2);
    ctx.stroke();
    ctx.restore();
  }
  if(ship.subShips&&ship.subShips.length>0){
    ship.subShips.forEach(ss=>{
      drawRVSubShip(ctx,ship.x+ship.w/2+ss.offset-12,ship.y+8,"#FF4444");
    });
  }

  // HPバー
  const hpRatio=Math.max(0,shootingPlayerHP/shootingPlayerMaxHP);
  const barW=W*0.5,barX=(W-barW)/2,barY=H-14;
  ctx.save();
  ctx.fillStyle="rgba(0,0,0,0.4)"; ctx.beginPath(); ctx.roundRect(barX,barY,barW,8,4); ctx.fill();
  const hpColor=hpRatio>0.5?"#6BCB77":hpRatio>0.25?"#FFD93D":"#FF6B6B";
  ctx.fillStyle=hpColor; ctx.shadowColor=hpColor; ctx.shadowBlur=6;
  ctx.beginPath(); ctx.roundRect(barX,barY,barW*hpRatio,8,4); ctx.fill();
  ctx.restore();

  drawElementBadge(ctx,W,s9PlayerElement);
}

